-- Poems batch 202
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('423b590d-b488-4c9f-ac5d-680ac1564d26','八月十四日夜約客月下有賦','魏了翁','宋','宋诗','song-poetry','','[]','秋空和月卷玻瓈，清入肝脾觸撥詩。',64,'全唐诗/poet.song.191000.json','["秋空和月卷玻瓈，清入肝脾觸撥詩。", "元自生來全體具，只緣見處一分虧。", "俗情數日須圓候，識者先幾畏滿時。", "千古詞人誰解道，擬將今夕當佳期。"]'),
('bb6b4be7-77ea-4866-9ef8-887c95086792','即席自和','魏了翁','宋','宋诗','song-poetry','','[]','薌林逗月剪玻瓈，要索人閒飲與詩。',64,'全唐诗/poet.song.191000.json','["薌林逗月剪玻瓈，要索人閒飲與詩。", "不飲清風嗤我俗，無詩明月怨人虧。", "少陵正念西營日，越石方驅北狄時。", "滿目憂端無處說，且將醉口謾期期。"]'),
('2bc229f5-751d-4667-9066-35f36cb25cd8','八月十五日夜月意偃蹇夜久微明須臾復晦瞻叔兄有詩因次其韻','魏了翁','宋','宋诗','song-poetry','','[]','長風送月九霄寬，無頼浮雲告亦頑。',64,'全唐诗/poet.song.191000.json','["長風送月九霄寬，無頼浮雲告亦頑。", "本自無私長委照，不應有礙似偏慳。", "蒼生望治東山隠，四海傾風釣瀨閒。", "潛復雖深終是昭，停觴且待夜深還。"]'),
('162a90b6-49c0-43c9-a5f4-e5336cb47473','翌日對客雨中再和','魏了翁','宋','宋诗','song-poetry','','[]','風雨盲程不少寬，告焉藐藐似殷頑。',64,'全唐诗/poet.song.191000.json','["風雨盲程不少寬，告焉藐藐似殷頑。", "苦於風月佳時競，甘向雲霓望處慳。", "天象自從盈裏缺，人心正要用時閒。", "浩然此樂無時極，應笑徽之興盡還。"]'),
('8d9e70e2-5a3b-4f69-9bd1-2be0d1105408','贈相士郭灝','魏了翁','宋','宋诗','song-poetry','','[]','載小奚奴長自隨，兩牛腰大贈行詩。',64,'全唐诗/poet.song.191000.json','["載小奚奴長自隨，兩牛腰大贈行詩。", "逢人有問輒如見，及我相遭不肯奇。", "每會面時長好好，合開口處或期期。", "道人莫是朱僊術，當與余言未及之。"]'),
('9049cf1b-c631-423c-b167-17b93887cdec','李微之聞其弟貫之西歸以詩迓之劉左史和韻屬余同賦  其一','魏了翁','宋','宋诗','song-poetry','','[]','室中萬象鎮寬閒，舒卷風煙入鳳山。',32,'全唐诗/poet.song.191000.json','["室中萬象鎮寬閒，舒卷風煙入鳳山。", "俯聽候蟲坏戶去，仰看倦鴈絕雲還。"]'),
('bec7718a-5e90-4da0-87a5-9405366693f7','李微之聞其弟貫之西歸以詩迓之劉左史和韻屬余同賦  其二','魏了翁','宋','宋诗','song-poetry','','[]','只期玉女是用諫，肯爲金夫不有躬。',32,'全唐诗/poet.song.191000.json','["只期玉女是用諫，肯爲金夫不有躬。", "想見江南兩膚使，天涯顦顇鬢成翁。"]'),
('a579e4af-26fb-4a1d-b394-5aacd5d2dfaf','李微之聞其弟貫之西歸以詩迓之劉左史和韻屬余同賦  其三','魏了翁','宋','宋诗','song-poetry','','[]','行李營營遍八荒，麴車炙騎趁春忙。',32,'全唐诗/poet.song.191000.json','["行李營營遍八荒，麴車炙騎趁春忙。", "莞然獨笑無人管，寒蕙牆東蜀海棠。"]'),
('5c4f4041-86c8-4f38-960b-d3faadcc278a','李微之聞其弟貫之西歸以詩迓之劉左史和韻屬余同賦  其四','魏了翁','宋','宋诗','song-poetry','','[]','公卿奏疏謾琅琅，誰刃樓蘭檻鬼章。',32,'全唐诗/poet.song.191000.json','["公卿奏疏謾琅琅，誰刃樓蘭檻鬼章。", "巢燕豫憂江上北，幕烏未到峴之陽。"]'),
('1c2fcdc2-4c29-452f-b445-a518220918b6','李微之聞其弟貫之西歸以詩迓之劉左史和韻屬余同賦  其五','魏了翁','宋','宋诗','song-poetry','','[]','滔滔斯世我誰歸，置散投閒分亦宜。',32,'全唐诗/poet.song.191000.json','["滔滔斯世我誰歸，置散投閒分亦宜。", "乾鵲頗驚仁鳥害，堅冰已向履霜知。"]'),
('6093c387-6e5a-407d-bb35-64d15d5fd49c','李微之聞其弟貫之西歸以詩迓之劉左史和韻屬余同賦  其六','魏了翁','宋','宋诗','song-poetry','','[]','曩與劉公同一邦，如今背我去堂堂。',32,'全唐诗/poet.song.191000.json','["曩與劉公同一邦，如今背我去堂堂。", "京師尊貴在朝者，爲問誰能踰阿章。"]'),
('fd1a4bbe-9367-4238-aea4-93083c567f65','元夕卜油溪故事  其一','魏了翁','宋','宋诗','song-poetry','','[]','不隨洛俗占燈影，不學荆人問紫姑。',32,'全唐诗/poet.song.191000.json','["不隨洛俗占燈影，不學荆人問紫姑。", "賣得薪來卜油去，豐年還似去年無。"]'),
('e403d42d-1794-413e-aad3-4da3f338adb0','元夕卜油溪故事  其二','魏了翁','宋','宋诗','song-poetry','','[]','滿目憂端膏火煎，聊將膏卜驗新年。',32,'全唐诗/poet.song.191000.json','["滿目憂端膏火煎，聊將膏卜驗新年。", "只祈五色雲瑞世，不願蚩尤旗亙天。"]'),
('3007ad20-c5d7-418c-b376-467716aa27c8','和李參政正旦聞邊報','魏了翁','宋','宋诗','song-poetry','','[]','羽檄連旬月，邊塵換歲陰。',48,'全唐诗/poet.song.191000.json','["羽檄連旬月，邊塵換歲陰。", "捉衿憂見肘，補肉忍剜心。", "天遠鴻飛急，林踈燕恨深。", "直將歸往地，都作殺胡林。"]'),
('82ed094a-17b2-436d-bac0-16980aff26a2','茂叔兄還鄉北郊酌別','魏了翁','宋','宋诗','song-poetry','','[]','動是三年別，纔堪十日留。',48,'全唐诗/poet.song.191000.json','["動是三年別，纔堪十日留。", "蒼頭相與並，軟語未能休。", "祇攪逍遥夢，真成浪泊遊。", "相期各努力，歲月鬢邊遒。"]'),
('b0e03339-8716-412f-a944-4ea1a6555a20','次王萬里愁霖','魏了翁','宋','宋诗','song-poetry','','[]','江聲砧杵入層樓，預作人閒八月秋。',64,'全唐诗/poet.song.191000.json','["江聲砧杵入層樓，預作人閒八月秋。", "虹外挂無窮遠思，鴈聲鳴不斷新愁。", "漢淮赤地不知里，巴蜀青天更上頭。", "蹇我康時分無策，只祈一飽暫銷憂。"]'),
('26371d9b-b951-428d-a590-ead84d281fef','贈術士龔恢乙','魏了翁','宋','宋诗','song-poetry','','[]','龔生來過我，極意論先天。',24,'全唐诗/poet.song.191000.json','["龔生來過我，極意論先天。", "自得環中趣，無言已十年。"]'),
('a017d6ec-eaae-4446-b4e9-7630cba1e00a','題桃源圖','魏了翁','宋','宋诗','song-poetry','','[]','伏勝高堂書已出，竇公制氏樂猶傳。',64,'全唐诗/poet.song.191000.json','["伏勝高堂書已出，竇公制氏樂猶傳。", "魯生力破秦儀陋，商皓終扶漢鼎顛。", "隠者寧無人禮義，武陵獨匪我山川。", "若將此地爲真有，亂我彝倫六百年。"]'),
('584ce4e7-f869-4e79-a282-43e72e75cf3e','題賈伯用大龍阡','魏了翁','宋','宋诗','song-poetry','','[]','積薪寢火漢公卿，爛額焦頭城郭臣。',64,'全唐诗/poet.song.191000.json','["積薪寢火漢公卿，爛額焦頭城郭臣。", "新沔精神開白日，三泉血泪濕初春。", "舊聞撇難須男子，誰識先機有婦人。", "添入開禧忠義傳，擬將笄珥易冠巾。"]'),
('3c766b82-fce7-40de-a9a8-a91394eb009d','次韻李參政龍鶴山廬  其一','魏了翁','宋','宋诗','song-poetry','','[]','山色醉痕邊，溪聲客枕前。',24,'全唐诗/poet.song.191000.json','["山色醉痕邊，溪聲客枕前。", "山溪元自舊，人已別經年。"]'),
('b4f652f0-99c4-49d7-8f66-94cd014fdcfa','次韻李參政龍鶴山廬  其二','魏了翁','宋','宋诗','song-poetry','','[]','天公富萬有，秋事不曾貧。',24,'全唐诗/poet.song.191000.json','["天公富萬有，秋事不曾貧。", "靜閲歲時信，動觀天地仁。"]'),
('f4d72d17-ac8a-4fc2-a0d4-b29c4b91afd9','次韻李參政龍鶴山廬  其三','魏了翁','宋','宋诗','song-poetry','','[]','莫使兒輩覺，從渠青紫紛。',24,'全唐诗/poet.song.191000.json','["莫使兒輩覺，從渠青紫紛。", "馬前金罷亞，鳥外玉奫淪。"]'),
('3efa3f4a-4973-4083-9bfa-c78fe85da6aa','次韻李參政龍鶴山廬  其四','魏了翁','宋','宋诗','song-poetry','','[]','世事從頭數，時機觸眼奇。',24,'全唐诗/poet.song.191000.json','["世事從頭數，時機觸眼奇。", "山靈莫留客，大厦要人枝。"]'),
('e63c0a53-38cb-4e51-8c02-374ffe1190e8','李參政約至井監偶得三絕  其一','魏了翁','宋','宋诗','song-poetry','','[]','忽聞車馬下天來，擁術闐衢撥不開。',32,'全唐诗/poet.song.191000.json','["忽聞車馬下天來，擁術闐衢撥不開。", "六十七年無此客，竈前老隸亦驚猜。"]'),
('2ba5e8d0-d318-42e0-abbc-760fea20682a','李參政約至井監偶得三絕  其二','魏了翁','宋','宋诗','song-poetry','','[]','不乘轞轞上公車，軋軋肩輿兩僕夫。',32,'全唐诗/poet.song.191000.json','["不乘轞轞上公車，軋軋肩輿兩僕夫。", "世道險夷隨所遇，車中只是舊時吾。"]'),
('93d42f7c-4687-4c33-9949-d397df9e0bac','李參政約至井監偶得三絕  其三','魏了翁','宋','宋诗','song-poetry','','[]','溪邊鵠白蘆花瘦，山下鵝黄稻實肥。',32,'全唐诗/poet.song.191000.json','["溪邊鵠白蘆花瘦，山下鵝黄稻實肥。", "更得天公晴十日，今年穡事庶乎幾。"]'),
('ff4b410b-a49b-450e-ad4d-9d8eb8c8050f','題成都憲江公廉勤謹忠信和緩八箴','魏了翁','宋','宋诗','song-poetry','','[]','勤似忉忉廉揭揭，謹疑𪘏𪘏信悾悾。',64,'全唐诗/poet.song.191000.json','["勤似忉忉廉揭揭，謹疑𪘏𪘏信悾悾。", "佩韋董子柔成緩，專瑟梁丘和近同。", "義利只差絲杪忽，功夫端驗始衷終。", "六箴須把公忠貫，公處還歸一字忠。"]'),
('dee5abf2-68aa-441a-8b24-3bae5fa8e2b5','自長寧阡過靈泉兄墓爇黄經從隈支以歸','魏了翁','宋','宋诗','song-poetry','','[]','晨策犯層巔，危如峭壁緣。',48,'全唐诗/poet.song.191000.json','["晨策犯層巔，危如峭壁緣。", "溪明人在地，路絕馬行天。", "松倚露雲立，稻依霜雨眠。", "不知歲年晚，撫事亦悠然。"]'),
('ad42d807-7a90-42db-818f-5686cd6a20cc','李參政生日  其一','魏了翁','宋','宋诗','song-poetry','','[]','文章心印老傳家，閒弄湖霜拭劍花。',32,'全唐诗/poet.song.191000.json','["文章心印老傳家，閒弄湖霜拭劍花。", "時事令人添白髮，只憑書味養靈芽。"]'),
('77a1a279-4bbf-47cf-98ce-39d7cc3c37c4','李參政生日  其二','魏了翁','宋','宋诗','song-poetry','','[]','天馬流行不見痕，黄鐘吹籥煦乾坤。',32,'全唐诗/poet.song.191000.json','["天馬流行不見痕，黄鐘吹籥煦乾坤。", "坎離互處靈根峙，剝復機中碩果存。"]'),
('1f6f0b2d-e640-4c30-860b-fbad081bc10d','李參政生日  其三','魏了翁','宋','宋诗','song-poetry','','[]','才記官來早去官，行人驚說路艱難。',32,'全唐诗/poet.song.191000.json','["才記官來早去官，行人驚說路艱難。", "行藏用舍何關我，時把尼淵出處看。"]'),
('67048c49-8055-4e67-88ca-a8a524af38a5','李參政生日  其四','魏了翁','宋','宋诗','song-poetry','','[]','歷盡玄枵十二辰，飽看三十六宮春。',32,'全唐诗/poet.song.191000.json','["歷盡玄枵十二辰，飽看三十六宮春。", "纔噴一霎挂龍雨，又卷雲霓還翠旻。"]'),
('91bce017-a6e2-4273-8db9-7ef1aef43fd4','李參政生日  其五','魏了翁','宋','宋诗','song-poetry','','[]','梅豔凌霜带雪餘，鉛華洗盡玉生膚。',32,'全唐诗/poet.song.191000.json','["梅豔凌霜带雪餘，鉛華洗盡玉生膚。", "東方千騎推人去，聊折春風寄鴈湖。"]'),
('33cd4074-a3e8-4908-a758-f5f56c91a6df','李參政生日  其六','魏了翁','宋','宋诗','song-poetry','','[]','絕嗤梁夢誤金甌，又嘆祁征困木牛。',32,'全唐诗/poet.song.191000.json','["絕嗤梁夢誤金甌，又嘆祁征困木牛。", "只藉人才作元氣，聞公安健百無憂。"]'),
('231ea9aa-3a38-45d8-8f77-efc9e4101eb0','安宣撫生日  其一','魏了翁','宋','宋诗','song-poetry','','[]','知是皇家幾世仁，天開人物作長城。',64,'全唐诗/poet.song.191000.json','["知是皇家幾世仁，天開人物作長城。", "元崇雅號濟時相，景略真成間代英。", "天路旂常鋪績用，中原草木識威名。", "北征西略公餘事，應念同胞百萬生。"]'),
('b0d86d71-8744-414a-be34-9d56d282b3ce','安宣撫生日  其二','魏了翁','宋','宋诗','song-poetry','','[]','踈戇煩公刮目看，肯持諛語祝加餐。',64,'全唐诗/poet.song.191000.json','["踈戇煩公刮目看，肯持諛語祝加餐。", "千鈞弩上機寧易，百尺竿頭步轉難。", "事遇快時聊復忍，民當急處略須寬。", "掃除荆棘栽梨棗，累璧重圭耐歲寒。"]'),
('d4ab3ad6-2c24-467b-8c27-0301e3a2f829','和楊仲禹送史子修特奏赴吏部注闕','魏了翁','宋','宋诗','song-poetry','','[]','科名寧較後先題，嘆老嗟卑世所迷。',64,'全唐诗/poet.song.191000.json','["科名寧較後先題，嘆老嗟卑世所迷。", "須識是閒天地似，要知立處聖賢齊。", "人情一理塗塗附，古道千年印印泥。", "屬子隨時崇令德，窗前紅日未全西。"]'),
('01b93958-bf81-4893-91c9-adbe578dc67e','和除夕前一日南叔兄會楊仲博楊季穆詩','魏了翁','宋','宋诗','song-poetry','','[]','玄裏探幽識罔冥，易中觀象見文明。',64,'全唐诗/poet.song.191000.json','["玄裏探幽識罔冥，易中觀象見文明。", "心虛有友皆三益，宇靜無時不四并。", "物理玩來成獨笑，年華見慣漸忘驚。", "只餘親友關天分，離合鍾情不肯平。"]'),
('6d1c8e9b-a3aa-458d-8c20-bc65ee7c5bbe','人日南山寺約汪憲','魏了翁','宋','宋诗','song-poetry','','[]','天開三十六宮春，又見階蓂七葉新。',64,'全唐诗/poet.song.191000.json','["天開三十六宮春，又見階蓂七葉新。", "雨足翦來齊麥壠，時和看不斷遊輪。", "記曾英簜爲使客，却擁朱轓作主人。", "客主何常均寄耳，繫邊認取本來身。"]'),
('b0d03376-30ce-4f03-9904-2aa408822cde','正月九日北山雍熙寺約同官','魏了翁','宋','宋诗','song-poetry','','[]','自從寒陸爽乾坤，律呂還宮歲換辰。',64,'全唐诗/poet.song.191000.json','["自從寒陸爽乾坤，律呂還宮歲換辰。", "曆紀人正纔九日，斗移天位已三春。", "銷磨壯士姑隨俗，牽引閒心苦爲人。", "終愧時艱才力短，只將民命倚洪鈞。"]'),
('eabdc87d-3e2e-450a-abd1-9dc2a73023dc','春社日祀事既畢轎中得三絕  其一','魏了翁','宋','宋诗','song-poetry','','[]','風雨聲中聽李陵，起來被服對神明。',32,'全唐诗/poet.song.191000.json','["風雨聲中聽李陵，起來被服對神明。", "歌鐘才徹車轓動，歸到譙樓恰六更。"]'),
('f877461c-9429-4195-a911-20cdd7039b4b','春社日祀事既畢轎中得三絕  其二','魏了翁','宋','宋诗','song-poetry','','[]','輾然馮軾受風吹，吏皂前驚雨濕衣。',32,'全唐诗/poet.song.191000.json','["輾然馮軾受風吹，吏皂前驚雨濕衣。", "豈識主人非崛强，一川生意索褰幃。"]'),
('1a5e5a81-3561-48e8-bf29-845bb312bb56','春社日祀事既畢轎中得三絕  其三','魏了翁','宋','宋诗','song-poetry','','[]','陰霧冥濛慢鼓鼙，田坡勃窣誤輪蹄。',32,'全唐诗/poet.song.191000.json','["陰霧冥濛慢鼓鼙，田坡勃窣誤輪蹄。", "居人閉戶未忺起，太守車前一尺泥。"]'),
('556da459-4e57-4247-bdff-4d45228d10ce','觀南隄','魏了翁','宋','宋诗','song-poetry','','[]','吏報南郊役事休，好風吹袂到江頭。',64,'全唐诗/poet.song.191000.json','["吏報南郊役事休，好風吹袂到江頭。", "長隄飲水馬非馬，疊石護田牛戴牛。", "處處女筐蠶望歲，村村社鼓麥祈秋。", "守臣不辦康時策，只把農夫作己憂。"]'),
('9ffd3953-d765-4030-82e3-090f2139e9d2','正月九日川上之遊楊季穆以酬唱見寄走筆次韻','魏了翁','宋','宋诗','song-poetry','','[]','雨中未放笑眉開，獨守空齋著玉杯。',32,'全唐诗/poet.song.191000.json','["雨中未放笑眉開，獨守空齋著玉杯。", "觀水功夫隨處見，逝川意思即心來。"]'),
('94c664c2-60e4-4419-9d57-22b2bf0be3af','次韻李參政見寄  其一','魏了翁','宋','宋诗','song-poetry','','[]','自失鷗邊約，應羞鶴上人。',48,'全唐诗/poet.song.191000.json','["自失鷗邊約，應羞鶴上人。", "竹荒青翼短，書遠墨題親。", "世事方嘗膽，時賢謾飲醇。", "國疑誰爲嗣，公子急振振。"]'),
('f6fa2e2a-38a0-4c10-9617-a514810ed631','次韻李參政見寄  其二','魏了翁','宋','宋诗','song-poetry','','[]','怕放紅樓目，浮雲斷復連。',48,'全唐诗/poet.song.191000.json','["怕放紅樓目，浮雲斷復連。", "遠看壺聚拓，近眎室如縣。", "耿耿自許國，悠悠誰訊天。", "天心那可識，拄頰看晴川。"]'),
('5e850a24-8de7-47bf-8cb1-1a9fa4320fff','次韻李參政見寄  其三','魏了翁','宋','宋诗','song-poetry','','[]','湖畔三頃秫，釀成聊獨斟。',48,'全唐诗/poet.song.191000.json','["湖畔三頃秫，釀成聊獨斟。", "積薪傷汲直，求舊感遲任。", "夢裏牛山峻，吟邊鴈泊深。", "兩鄉明月夜，應照舊登臨。"]'),
('61b3ce88-0b9c-4802-8ae7-86042c215016','次韻李參政見遺生日  其一','魏了翁','宋','宋诗','song-poetry','','[]','六月不知暑，湖風漲晚林。',48,'全唐诗/poet.song.191000.json','["六月不知暑，湖風漲晚林。", "憑闌追舊夢，馳驛寄新吟。", "出入三朝意，卷舒千古心。", "感余不暇懶，窗影午蟾侵。"]'),
('97c1b4c0-a944-4a0d-aa9f-eb4bcec0e864','次韻李參政見遺生日  其二','魏了翁','宋','宋诗','song-poetry','','[]','月暗書中色，霜彫鏡裏年。',48,'全唐诗/poet.song.191000.json','["月暗書中色，霜彫鏡裏年。", "滔滔時易失，落落意難傳。", "信己終違俗，隨人謾辱先。", "輸他南閣老，欹玉弄寒泉。"]'),
('725b82d9-8caf-4352-bc63-b1a21510ca15','次韻李參政見遺生日  其三','魏了翁','宋','宋诗','song-poetry','','[]','幸有鶴山房，圖書繞夢香。',48,'全唐诗/poet.song.191000.json','["幸有鶴山房，圖書繞夢香。", "况慙聞道淺，何苦爲人忙。", "五斗米非分，三間茅可長。", "何當重操几，同踏古松岡。"]'),
('07f7d6b4-66f6-4fe7-b8cd-ee02027e9ff8','送王教授之官臨邛','魏了翁','宋','宋诗','song-poetry','','[]','賸喜人從義理趨，却憂末習墮浮虛。',64,'全唐诗/poet.song.191000.json','["賸喜人從義理趨，却憂末習墮浮虛。", "未通經術先談傳，祇送人言不識渠。", "偶向檐頭覓桃李，徑從紙上索鳶魚。", "君今去主師儒席，後倦先傳謹在初。"]'),
('e5885577-9387-4111-af45-e37036fe81e5','余既賦詩坐客請以唐人家花車斜韻同賦醉中作五十六言','魏了翁','宋','宋诗','song-poetry','','[]','人生偶被浮名誤，往往貪程不識家。',64,'全唐诗/poet.song.191000.json','["人生偶被浮名誤，往往貪程不識家。", "醉眼亂穿青草屐，狂心長戀碧桃花。", "舉頭大道平如掌，入鬢韶光轉似車。", "是乃吾憂今贈子，情親語直字欺斜。"]'),
('997868fe-ed12-4f39-8ae3-35c87400ab8b','八月十四夜月用舊作韻呈諸友','魏了翁','宋','宋诗','song-poetry','','[]','鬢髮成宣面欲黎，逢人恥誦故年詩。',64,'全唐诗/poet.song.191000.json','["鬢髮成宣面欲黎，逢人恥誦故年詩。", "才看震象應知滿，未睹乾爻已識虧。", "止處光明渾在裏，偶然顯晦謾隨時。", "風光流轉渾閒事，要與知心結久期。"]'),
('650bca09-09cc-476e-8499-a7a45f091506','應提刑以十五日和韻見示再次韻','魏了翁','宋','宋诗','song-poetry','','[]','大圓垂象曉羣黎，猶送昨宵畏滿詩。',64,'全唐诗/poet.song.191000.json','["大圓垂象曉羣黎，猶送昨宵畏滿詩。", "要看天行嫌位亢，若言人事惡功虧。", "升於正處元爲利，坎到盈中乃識時。", "疑我冰輪公賜厚，敢申餘義副襟期。"]'),
('c940031b-e4a0-4938-81e3-756e4d9770d0','九月丁亥秋祀畢勞農北郊蘇提幹以疾不往以詩見寄因次其韻','魏了翁','宋','宋诗','song-poetry','','[]','秋嘗事畢與賓遊，神惠如臨不敢留。',64,'全唐诗/poet.song.191000.json','["秋嘗事畢與賓遊，神惠如臨不敢留。", "騎吹一川松露曉，踏歌千里稻雲秋。", "豳公堂上兕觥薦，鄆使溪前經律諏。", "盡日臨民看不足，歸從蘇子靜中求。"]'),
('6f916473-8591-4f00-a7aa-ec5cd0ca2d81','李參政生日  其一','魏了翁','宋','宋诗','song-poetry','','[]','已露明年造化機，便將六十四年推。',32,'全唐诗/poet.song.191000.json','["已露明年造化機，便將六十四年推。", "後天八八無窮數，一畫初陽自此基。"]'),
('4c69a861-b707-4cce-a78e-6a652f6a8814','李參政生日  其二','魏了翁','宋','宋诗','song-poetry','','[]','歲月陶鎔兩鬢毛，坐看時事爾滔滔。',32,'全唐诗/poet.song.191000.json','["歲月陶鎔兩鬢毛，坐看時事爾滔滔。", "可能只袖區中手，鎮在湖亭讀楚騷。"]'),
('0c607e07-bac2-47de-9d10-8527dbe850bc','李參政生日  其三','魏了翁','宋','宋诗','song-poetry','','[]','八十蹁躚老阿兄，一窗風雨伴雙清。',32,'全唐诗/poet.song.191000.json','["八十蹁躚老阿兄，一窗風雨伴雙清。", "武昌近日音書少，時聽湖邊過鴈聲。"]'),
('fdd16312-35aa-4557-ad1a-da7b63b7f0da','李參政生日  其四','魏了翁','宋','宋诗','song-poetry','','[]','瀉出清明醉眼醒，都人彈指祝前星。',32,'全唐诗/poet.song.191000.json','["瀉出清明醉眼醒，都人彈指祝前星。", "憑誰提起源頭話，治國齊家要六經。"]'),
('0a1df732-1369-418e-8cbc-9d7536d3cf51','李參政生日  其五','魏了翁','宋','宋诗','song-poetry','','[]','剺面花門未果馴，夏人兵馬薄熙秦。',32,'全唐诗/poet.song.191000.json','["剺面花門未果馴，夏人兵馬薄熙秦。", "誰將鞭策驅時運，十數年間日日新。"]'),
('89a987f5-0a8d-40cc-afb0-19661ad5ecac','李參政生日  其六','魏了翁','宋','宋诗','song-poetry','','[]','分付諸兒自致身，朝陽閣上看長春。',32,'全唐诗/poet.song.191000.json','["分付諸兒自致身，朝陽閣上看長春。", "梅邊認得真消息，往古來今一屈伸。"]'),
('8e912c22-21b9-42d4-91b7-5cee5207f169','次韻蘇和甫雨後觀梅','魏了翁','宋','宋诗','song-poetry','','[]','歲寒賓友伴蕭蕭，客氣無根已盡凋。',64,'全唐诗/poet.song.191000.json','["歲寒賓友伴蕭蕭，客氣無根已盡凋。", "踈影照人騷夢冷，清香徹骨醉痕銷。", "話逢理到春生坐，飲爲心知月滿瓢。", "更祝天公多雨麥，時携樂酒酹芳條。"]'),
('08574d8f-b5ec-4008-8738-1bff79598b4f','海潮院領客觀梅','魏了翁','宋','宋诗','song-poetry','','[]','竹外蒲牢挂晚晴，霜威洗出月精神。',64,'全唐诗/poet.song.191000.json','["竹外蒲牢挂晚晴，霜威洗出月精神。", "山無此客林泉活，詩到茲遊景氣新。", "元是當年郪縣北，不知幾度梓州春。", "梅邊認得真消息，往古來今一屈伸。"]'),
('90943ff6-f57d-4198-bd41-10df26618b6f','嘉甫弟生日','魏了翁','宋','宋诗','song-poetry','','[]','山居面面接青天，更把青天觸處看。',64,'全唐诗/poet.song.191000.json','["山居面面接青天，更把青天觸處看。", "心事和平官職耐，家人順正室廬寬。", "栽培桃李扶春意，長養松篁伴歲寒。", "門戶千鈞今付汝，書來時寄我平安。"]'),
('3505fc48-0d33-46bd-a632-ff88f7ce868a','瀘帥曹太博生日四首  其一','魏了翁','宋','宋诗','song-poetry','','[]','荔香摇艇下瀘川，自別君侯十八年。',32,'全唐诗/poet.song.191000.json','["荔香摇艇下瀘川，自別君侯十八年。", "尉我調饑刻爲歲，爭如兩日往南田。"]'),
('eb4f696d-71c0-43c4-96d6-3b703d315eb0','瀘帥曹太博生日四首  其二','魏了翁','宋','宋诗','song-poetry','','[]','天馬無蹤運四時，試將六十四年推。',32,'全唐诗/poet.song.191000.json','["天馬無蹤運四時，試將六十四年推。", "後天八八方來數，加倍無窮自此基。"]'),
('e50731e6-b46a-4356-80cf-0cb19de36e09','瀘帥曹太博生日四首  其三','魏了翁','宋','宋诗','song-poetry','','[]','十年更瑟不曾調，百載張弓未肯弨。',32,'全唐诗/poet.song.191000.json','["十年更瑟不曾調，百載張弓未肯弨。", "隨事提撕民受賜，寧論外服與王朝。"]'),
('5ddf61d1-7517-4786-8948-8cc3cb0043d5','瀘帥曹太博生日四首  其四','魏了翁','宋','宋诗','song-poetry','','[]','犖犖聖門心事長，悠悠客路鬢毛蒼。',32,'全唐诗/poet.song.191000.json','["犖犖聖門心事長，悠悠客路鬢毛蒼。", "東南人物寥寥甚，扶植斯文我所望。"]'),
('0602505f-bbed-4424-aba0-155f7e1f7e13','舟至合江度周卿以詩相迓次韻','魏了翁','宋','宋诗','song-poetry','','[]','雨滿長空水拍疇，荔香松色倚江流。',64,'全唐诗/poet.song.191000.json','["雨滿長空水拍疇，荔香松色倚江流。", "半窗燈火千年夢，萬里風波一葉舟。", "謾道班卿若僊去，誰知謝傅正同憂。", "西歸待我期相告，橫被風師三日留。"]'),
('805d2ce4-77df-4a9b-8b61-d7fe8775e397','將至古渝虞憲以三絕同端午節見寄用韻爲謝  其一','魏了翁','宋','宋诗','song-poetry','','[]','故山朱果恰離離，翠竹青蒲護衆菲。',32,'全唐诗/poet.song.191000.json','["故山朱果恰離離，翠竹青蒲護衆菲。", "夢裏不知身造闕，閒隨白鶴照江衣。"]'),
('ca52e1c0-962b-4e2b-8864-deb2b0d3ce88','將至古渝虞憲以三絕同端午節見寄用韻爲謝  其二','魏了翁','宋','宋诗','song-poetry','','[]','鬢邊憂緒已千端，誰喚扁舟下濮干。',32,'全唐诗/poet.song.191000.json','["鬢邊憂緒已千端，誰喚扁舟下濮干。", "落日明舡劍如電，勇心觸撥到樓蘭。"]'),
('1ec3f126-fc8e-44c3-9b55-3115a62a5ac6','將至古渝虞憲以三絕同端午節見寄用韻爲謝  其三','魏了翁','宋','宋诗','song-poetry','','[]','蓬窗暑雨氣低垂，不記龍舟競渡期。',32,'全唐诗/poet.song.191000.json','["蓬窗暑雨氣低垂，不記龍舟競渡期。", "詩卷打門驚節序，滿盤角黍正累累。"]'),
('1fb8af5a-23cf-486d-8109-9354e09b5c21','萬州守潘拉登魯池觀荷花荔枝  其一','魏了翁','宋','宋诗','song-poetry','','[]','密林和雨翦離支，曲徑留陰切藕絲。',32,'全唐诗/poet.song.191000.json','["密林和雨翦離支，曲徑留陰切藕絲。", "自入渝涪山色惡，眼明見此魯家池。"]'),
('53a34b43-8c96-4799-839f-82727bd72208','萬州守潘拉登魯池觀荷花荔枝  其二','魏了翁','宋','宋诗','song-poetry','','[]','分隨猿鶴老隈支，趨詔重來兩鬢絲。',32,'全唐诗/poet.song.191000.json','["分隨猿鶴老隈支，趨詔重來兩鬢絲。", "解后一觴莫辭凸，能禁二十載差池。"]'),
('22c00ebe-578f-4506-a2c1-c1309f9ec83c','和崔侍郎送行詩韻  其一','魏了翁','宋','宋诗','song-poetry','','[]','昔歲阽危日，煩公疋馬來。',48,'全唐诗/poet.song.191000.json','["昔歲阽危日，煩公疋馬來。", "人心成勝勢，天理是良媒。", "抖擻精神集，扶持氣脈回。", "黄宮才一點，有許到葭灰。"]'),
('dffc7b70-ef74-4a0d-b853-08a6858cc942','和崔侍郎送行詩韻  其二','魏了翁','宋','宋诗','song-poetry','','[]','軋軋度空明，懷人夢不成。',48,'全唐诗/poet.song.191000.json','["軋軋度空明，懷人夢不成。", "蜀天隨處見，巵酒與誰傾。", "多事鬢毛改，長途髀肉生。", "隨流渾未定，鼻息滿舡鳴。"]'),
('47495049-39dd-4113-8a8b-a0518dd90b7c','即席和丁夔帥送行詩韻  其一','魏了翁','宋','宋诗','song-poetry','','[]','人生行止莫非天，去國重來十七年。',64,'全唐诗/poet.song.191000.json','["人生行止莫非天，去國重來十七年。", "學自孔顔期有是，道非堯舜敢陳前。", "憂時正念梁甌缺，視己當如趙璧全。", "若得時清身不辱，儘教人道是登僊。"]'),
('b3a99372-2903-4df9-bcae-8ad4232b80ca','即席和丁夔帥送行詩韻  其二','魏了翁','宋','宋诗','song-poetry','','[]','眼明織翠剪新詩，勉我當今尚可爲。',64,'全唐诗/poet.song.191000.json','["眼明織翠剪新詩，勉我當今尚可爲。", "知覺斯民知覺我，溺饑天下溺饑誰。", "志亨不管身窮達，誼正寧論效疾遲。", "倒盡玉瓶談未了，沙頭忍淚與君辭。"]'),
('7854c229-4170-4a98-a8b7-deecdea8b110','和夔漕王韻  其一','魏了翁','宋','宋诗','song-poetry','','[]','開濟堂前送櫂歌，淵淵舡鼓伐靈鼉。',64,'全唐诗/poet.song.191000.json','["開濟堂前送櫂歌，淵淵舡鼓伐靈鼉。", "雲埋白帝千山小，浪拍青天一葉過。", "解后天涯驚易別，顧瞻水劑得如何。", "惟餘報國忠肝在，鐵石云堅尚可磨。"]'),
('6668df97-cac3-45b3-a30f-9843626786fc','和夔漕王韻  其二','魏了翁','宋','宋诗','song-poetry','','[]','成都別酒幾何年，再見江滣豈偶然。',64,'全唐诗/poet.song.191000.json','["成都別酒幾何年，再見江滣豈偶然。", "胡不握蘭居紫界，却來轉粟上青天。", "鵬圖海澨騫新味，鴈斷衡陽感舊聯。", "國子先生書在笥，願從熟路力加鞭。"]'),
('33314257-bde2-4fdb-b9d0-18d7080a6635','生日和辛江陵即席韻  其一','魏了翁','宋','宋诗','song-poetry','','[]','有生同得本來公，凜凜淵冰保降衷。',64,'全唐诗/poet.song.191000.json','["有生同得本來公，凜凜淵冰保降衷。", "多愧行年稱有子，長懷當日謝無功。", "羈蹤不稱歌三拜，淺量難堪酒一中。", "飲盡玉瓶天地闊，不知身客楚臺風。"]'),
('8b691efb-2849-446e-8ce4-cad249ac2c24','生日和辛江陵即席韻  其二','魏了翁','宋','宋诗','song-poetry','','[]','笑語聲中別有天，巫雲楚岫玉明舡。',64,'全唐诗/poet.song.191000.json','["笑語聲中別有天，巫雲楚岫玉明舡。", "冷風入坐酒無力，斜日媚空花欲然。", "獵獵旗風猶夏五，摇摇帆影立秋千。", "他時輦路追今夢，儻許陪公髮未宣。"]'),
('31ead8e0-66f4-4c6e-82e5-bee7072cb62e','李季允作吞雲樓索詩和總漕韻答之  其一','魏了翁','宋','宋诗','song-poetry','','[]','柵新飛觀走狐嘷，樓鶴洲鸚賀此遭。',64,'全唐诗/poet.song.191000.json','["柵新飛觀走狐嘷，樓鶴洲鸚賀此遭。", "整暇旌旗登𡽱嶪，奔波舟楫笑嗷嘈。", "宅中平後規摹拓，燭理明時運量高。", "須信是間天地似，詞人雲夢特秋毫。"]'),
('69d999c9-88a4-4466-b194-9484682e053e','李季允作吞雲樓索詩和總漕韻答之  其二','魏了翁','宋','宋诗','song-poetry','','[]','舉頭無語望天高，有許功夫歲月慆。',64,'全唐诗/poet.song.191000.json','["舉頭無語望天高，有許功夫歲月慆。", "萬竈貔貅仰膏雨，百年事業倚江濤。", "雲橫紫邏憂千緒，露立蒼生命一毛。", "昨夜西風弦月魄，可能無夢到神臯。"]'),
('bc9fd19e-171b-4a46-bbb7-c34076835c40','艤舟琵琶亭次福士張元龍以詩代柬韻  其一','魏了翁','宋','宋诗','song-poetry','','[]','人生行止莫非天，萬里風波一葉舡。',32,'全唐诗/poet.song.191000.json','["人生行止莫非天，萬里風波一葉舡。", "時有賓朋慰牢落，寧論遠道困行躔。"]'),
('4c147a28-7b4e-428d-9667-1172aef69b8e','艤舟琵琶亭次福士張元龍以詩代柬韻  其二','魏了翁','宋','宋诗','song-poetry','','[]','樂天未信果知天，枉爲琵琶絃繫舡。',32,'全唐诗/poet.song.191000.json','["樂天未信果知天，枉爲琵琶絃繫舡。", "須識屈信常事耳，暑寒代序月移躔。"]'),
('a3242c49-d9a5-49ed-9528-b50ef60a0043','楊仲博生日  其一','魏了翁','宋','宋诗','song-poetry','','[]','平塍雨足蟹魚肥，遠水涵空鸛鶴飛。',32,'全唐诗/poet.song.191000.json','["平塍雨足蟹魚肥，遠水涵空鸛鶴飛。", "相對不知身是客，兩家兒女綵成圍。"]'),
('3f432c0e-0173-4179-934a-70e062fcb327','楊仲博生日  其二','魏了翁','宋','宋诗','song-poetry','','[]','玉粹金渾好弟兄，向來馳譽鬢雙青。',32,'全唐诗/poet.song.191000.json','["玉粹金渾好弟兄，向來馳譽鬢雙青。", "世間賢美寧常有，百歲三亭過一亭。"]'),
('7bd1f0cb-6739-4dd6-80b7-e2de8ce214fa','楊仲博生日  其三','魏了翁','宋','宋诗','song-poetry','','[]','任教寒畯着先鞭，儘使權豪紊選班。',32,'全唐诗/poet.song.191000.json','["任教寒畯着先鞭，儘使權豪紊選班。", "縱誚我迂嗤我矯，箇中所負重於山。"]'),
('abd827ca-7573-4bb3-a834-a2c2cc76a513','史倉使約登齊山自弄水亭過清溪橋至壺天洞洞乃史新作或曰此即左史洞又至華蓋洞翠微亭史倉索賦','魏了翁','宋','宋诗','song-poetry','','[]','自分宇宙有江山，獨覺新年勝故年。',64,'全唐诗/poet.song.191000.json','["自分宇宙有江山，獨覺新年勝故年。", "水拍大堤人射地，路盤絕嶮馬行天。", "松蘿苒苒開還密，洞谷谽谽斷復穿。", "理道元來無隠爾，人從紙上看天淵。"]'),
('e4a5720f-701e-4bbc-b2e6-19a7456c607b','李池州和韻見寄再賦以答之','魏了翁','宋','宋诗','song-poetry','','[]','晨策隨烏瞰屋山，面前咫尺隔同年。',64,'全唐诗/poet.song.191000.json','["晨策隨烏瞰屋山，面前咫尺隔同年。", "邛人自愛橘中樂，晉客驚逢洞裏天。", "行傍輶軒心半醉，坐看戟衛眼雙穿。", "西風一夕驚龍睡，撼取明珠出九淵。"]'),
('0a178f0e-025f-4e2c-a617-c87b17602e66','高不疑與客登梁昭明釣臺李肩吾和前詩見遺用韻謝之','魏了翁','宋','宋诗','song-poetry','','[]','籃輿軋軋度齊山，文獻風流數百年。',64,'全唐诗/poet.song.191000.json','["籃輿軋軋度齊山，文獻風流數百年。", "遥想牧之歌晚月，閒尋白也詠平天。", "只餘釣水梁臺在，未辦登山謝屐穿。", "多謝秋風吹好語，如陪杖屨俯魚淵。"]'),
('f768a744-9872-4f53-96d9-a9b292ba7202','十八日上壽退賜坐十九日貢院錫宴二十一日紫宸殿御筵即事  其一','魏了翁','宋','宋诗','song-poetry','','[]','珂繖摇心夢不成，忽聽吏皂放衙聲。',32,'全唐诗/poet.song.191000.json','["珂繖摇心夢不成，忽聽吏皂放衙聲。", "吹燈撥火供晨粥，趁到皇城恰六更。"]'),
('98c5f5fd-a957-492d-a675-3f2bcf3e2b88','十八日上壽退賜坐十九日貢院錫宴二十一日紫宸殿御筵即事  其二','魏了翁','宋','宋诗','song-poetry','','[]','嚴妝列衛啟宸居，百辟滔滔若貫魚。',32,'全唐诗/poet.song.191000.json','["嚴妝列衛啟宸居，百辟滔滔若貫魚。", "後幄宰臣先奏事，猶隨郎從立前除。"]'),
('70e9cbc5-b646-404a-86a4-d81662354bb3','十八日上壽退賜坐十九日貢院錫宴二十一日紫宸殿御筵即事  其三','魏了翁','宋','宋诗','song-poetry','','[]','有次鞭鞘陸續鳴，赭袍當殿萬簪纓。',32,'全唐诗/poet.song.191000.json','["有次鞭鞘陸續鳴，赭袍當殿萬簪纓。", "羣臣拜舞分行坐，十味肴羞酒五行。"]'),
('97c0f8ac-3c6b-4cef-9205-9af28b72a416','十八日上壽退賜坐十九日貢院錫宴二十一日紫宸殿御筵即事  其四','魏了翁','宋','宋诗','song-poetry','','[]','蹴鞠尋橦列廣庭，吹絲按竹布前榮。',32,'全唐诗/poet.song.191000.json','["蹴鞠尋橦列廣庭，吹絲按竹布前榮。", "卿郎朶殿渾無見，只聽時時萬歲聲。"]'),
('bd8de61b-ffc6-48c9-93bd-8845c1f6d58d','十八日上壽退賜坐十九日貢院錫宴二十一日紫宸殿御筵即事  其五','魏了翁','宋','宋诗','song-poetry','','[]','再坐猶餘四屈巵，筋駑肉痹股生胝。',32,'全唐诗/poet.song.191000.json','["再坐猶餘四屈巵，筋駑肉痹股生胝。", "侍臣醉飽皇歡洽，更看終場角牴嬉。"]'),
('46787c65-1ac8-4075-906c-ffc23e7b14e7','十八日上壽退賜坐十九日貢院錫宴二十一日紫宸殿御筵即事  其六','魏了翁','宋','宋诗','song-poetry','','[]','蛾眉班捲戴花回，遥望君王玉色開。',32,'全唐诗/poet.song.191000.json','["蛾眉班捲戴花回，遥望君王玉色開。", "畫楯諸班謝茶酒，尻高首下一聲雷。"]'),
('45e757ae-11da-4233-930e-dfa099d8929a','十八日上壽退賜坐十九日貢院錫宴二十一日紫宸殿御筵即事  其七','魏了翁','宋','宋诗','song-poetry','','[]','十七年間作外臣，重來三日齒嘉賓。',32,'全唐诗/poet.song.191000.json','["十七年間作外臣，重來三日齒嘉賓。", "天顔不減當年澤，點檢同朝共五人。"]'),
('d107c288-b9fb-4784-aadd-ac8738d65327','和楊尚書韻送藺恭甫歸永康','魏了翁','宋','宋诗','song-poetry','','[]','夢遶秦祠月半稜，歸尋岷嶺雪千層。',64,'全唐诗/poet.song.191000.json','["夢遶秦祠月半稜，歸尋岷嶺雪千層。", "儻來富貴垤藏蟻，儘大科名筆誤蠅。", "須驗家庭真事業，更追簡冊淡交朋。", "他年再出爲時用，莫遣功夫似不曾。"]'),
('de6928f4-339c-4e56-ab24-7b03b87d0872','十二月九日雪融夜起達旦','魏了翁','宋','宋诗','song-poetry','','[]','遠鐘入枕雪初晴，衾鐵稜稜夢不成。',32,'全唐诗/poet.song.191000.json','["遠鐘入枕雪初晴，衾鐵稜稜夢不成。", "起傍梅花讀周易，一窗明月四簷聲。"]'),
('ea90129c-4fa1-4ef9-9ee5-5407e39df005','十日夜聞風聲','魏了翁','宋','宋诗','song-poetry','','[]','雪盡冰澌涕亦晴，布衾紙帳復求成。',32,'全唐诗/poet.song.191000.json','["雪盡冰澌涕亦晴，布衾紙帳復求成。", "卷書擬續前宵夢，一夜狂風撼戶聲。"]'),
('70031ed0-41c7-4326-b132-90e8ebb9b1cd','臘日同舍郎即湖上送諸葛吏部赴湖北常平次汪吏部韻','魏了翁','宋','宋诗','song-poetry','','[]','繡衣銜命去，祖帳爲王留。',48,'全唐诗/poet.song.191000.json','["繡衣銜命去，祖帳爲王留。", "大舶滿青鏡，寒雲明玉舟。", "歲餘官事省，蜡畢吏功休。", "千古行藏意，梅邊細講求。"]'),
('0fcfc028-3a10-485f-8faa-2875c2ab3d9d','楊尚書和晴字韻詩適趨部宿再韻謝之  其一','魏了翁','宋','宋诗','song-poetry','','[]','靜將軀榦驗陰晴，風雪中閒玉汝成。',32,'全唐诗/poet.song.191000.json','["靜將軀榦驗陰晴，風雪中閒玉汝成。", "襆被直趨郎省直，更無剌剌耳邊聲。"]'),
('88915b89-2ad8-4ab3-b663-84e672ca1b95','楊尚書和晴字韻詩適趨部宿再韻謝之  其二','魏了翁','宋','宋诗','song-poetry','','[]','冬令陰陰我獨晴，世間寒暑本思成。',32,'全唐诗/poet.song.191000.json','["冬令陰陰我獨晴，世間寒暑本思成。", "玉珂金鑰聲中睡，無限山林入耳聲。"]'),
('46b785db-d025-4657-9190-ffca1906f9ee','袁都官同前韻賦二詩一章問易邊賦唐律二章索奏劄錄本  其一','魏了翁','宋','宋诗','song-poetry','','[]','那得閒功詠雪晴，風光自解湊詩成。',32,'全唐诗/poet.song.191000.json','["那得閒功詠雪晴，風光自解湊詩成。", "須知精粗無非易，千古人心只一聲。"]'),
('9462e1d0-2507-402a-8bf7-f9293df5bc17','袁都官同前韻賦二詩一章問易邊賦唐律二章索奏劄錄本  其二','魏了翁','宋','宋诗','song-poetry','','[]','一天西雨又東晴，喚作陰晴雨不成。',32,'全唐诗/poet.song.191000.json','["一天西雨又東晴，喚作陰晴雨不成。", "朝睡着人渾未覺，鳴嚶枝上一聲聲。"]'),
('bf0caa6c-3b04-49b2-90f1-5563ea3775db','次韻楊尚書立春  其一','魏了翁','宋','宋诗','song-poetry','','[]','帽屋釵梁剪綵新，誰知井底及池瀕。',32,'全唐诗/poet.song.191000.json','["帽屋釵梁剪綵新，誰知井底及池瀕。", "只從陽月方中日，已作明年第一春。"]'),
('f7341977-5483-4f24-aa18-702f580d40fa','次韻楊尚書立春  其二','魏了翁','宋','宋诗','song-poetry','','[]','行玉盤中驚杜老，扣窗聲裏喚祈賓。',32,'全唐诗/poet.song.191000.json','["行玉盤中驚杜老，扣窗聲裏喚祈賓。", "扶持大道須公等，正恐鄉車未可巾。"]'),
('303068ec-b3c0-465a-a8b5-af4516116523','曾少卿約飲即席賦','魏了翁','宋','宋诗','song-poetry','','[]','深院簾旌晝掩門，海牛挂出好乾坤。',64,'全唐诗/poet.song.191000.json','["深院簾旌晝掩門，海牛挂出好乾坤。", "日烘花影漲春膩，風撼柳絲明醉痕。", "極目翦來齊翠嶂，關心看不斷青原。", "明朝又逐文書去，且盡今宵極意論。"]'),
('26270b31-1d71-4511-8ebb-833ceab487b1','八月七日被命上會稽沿途所歷拙於省記爲韻語以記之舟中馬上隨得隨書不復敘次  其一','魏了翁','宋','宋诗','song-poetry','','[]','篾帆松艇趁潮生，隔岸平疇喚得譍。',32,'全唐诗/poet.song.191000.json','["篾帆松艇趁潮生，隔岸平疇喚得譍。", "上到渡頭失歡喜，泥行十里是西興。"]'),
