('2505154a-09a9-4051-b5c1-e1a7cfd3683e','送從子令憲西歸  其四','魏了翁','宋','宋诗','song-poetry','','[]','自爾南來歲再周，新功培養氣揚休。',32,'全唐诗/poet.song.191000.json','["自爾南來歲再周，新功培養氣揚休。", "且留數月須多益，歸妹愆期母所憂。"]'),
('7d06c696-c8cc-4720-a8a5-09aa954c5375','送從子令憲西歸  其五','魏了翁','宋','宋诗','song-poetry','','[]','古人爲學戒悠悠，說命惟從務敏求。',32,'全唐诗/poet.song.191000.json','["古人爲學戒悠悠，說命惟從務敏求。", "識此味時那可已，更從來處驗吾脩。"]'),
('e817ab58-1ce4-4d0b-b456-f8b25719e106','送從子令憲西歸  其六','魏了翁','宋','宋诗','song-poetry','','[]','弘毅規摹本末周，既難分付又難酬。',32,'全唐诗/poet.song.191000.json','["弘毅規摹本末周，既難分付又難酬。", "須知陋巷憂中樂，又識耕莘樂處憂。"]'),
('319e5b5e-a414-4bf8-bc47-02475d87eb5e','題南叔兄藏脩閣息遊觀','魏了翁','宋','宋诗','song-poetry','','[]','中存外習即藏脩，夙寤晨興此息遊。',64,'全唐诗/poet.song.191000.json','["中存外習即藏脩，夙寤晨興此息遊。", "要把孟軻三勿看，更將夫子四於求。", "顔淵陋巷樂何事，曾晳風雩詠不休。", "此意斯須不容離，敢申鄭義儆悠悠。"]'),
('3f6dff5a-086f-4141-9f45-0fc32462c7a3','次韻黄判官喜雪','魏了翁','宋','宋诗','song-poetry','','[]','天馬流行澤上坤，玉龍飛灑水邊村。',64,'全唐诗/poet.song.191000.json','["天馬流行澤上坤，玉龍飛灑水邊村。", "扶持農扈培邦本，排盪陰機立歲元。", "遍地詩材供墨客，通宵酒令屬侯門。", "却憐赤子無衣褐，仰面蒼蒼嘆少恩。"]'),
('3b6b4d49-3b87-49b8-830c-1bc78ced27ef','肩吾生日三絕句  其一','魏了翁','宋','宋诗','song-poetry','','[]','尚記聯車入界頭，廉安門外麥三秋。',32,'全唐诗/poet.song.191000.json','["尚記聯車入界頭，廉安門外麥三秋。", "江山氣度依前偉，簡冊功夫匪昔侔。"]'),
('6bc4d93a-d3ee-472e-845b-43faf709c570','肩吾生日三絕句  其二','魏了翁','宋','宋诗','song-poetry','','[]','世歷嬴劉周典盡，經由孫沈古音休。',32,'全唐诗/poet.song.191000.json','["世歷嬴劉周典盡，經由孫沈古音休。", "更嗟書法開元壞，不易肩吾字字求。"]'),
('1b1a7ce9-db0b-482b-a7f2-b1767e9948fd','肩吾生日三絕句  其三','魏了翁','宋','宋诗','song-poetry','','[]','昔人年德位俱優，淇奧賓筵苦自脩。',32,'全唐诗/poet.song.191000.json','["昔人年德位俱優，淇奧賓筵苦自脩。", "學至百年寧有厭，勉哉三十六春秋。"]'),
('efc18f6c-dba9-42ee-861f-4cd4c8af663f','次肩吾慶生日韻  其一','魏了翁','宋','宋诗','song-poetry','','[]','謾閲人間五十年，年來道遠思悠然。',64,'全唐诗/poet.song.191000.json','["謾閲人間五十年，年來道遠思悠然。", "一心可使乾坤位，五性元鍾父母全。", "爲己工夫渾間斷，滿頭歲月浪推遷。", "更無益友相扶植，平地羊腸仆白顛。"]'),
('9e285829-d2ef-48ab-ac5a-6476f002da91','次肩吾慶生日韻  其二','魏了翁','宋','宋诗','song-poetry','','[]','山中兀兀不知年，但數前山䓞火然。',64,'全唐诗/poet.song.191000.json','["山中兀兀不知年，但數前山䓞火然。", "人笑腰無金可佩，我忻脛與玉俱全。", "聖賢面目晝三接，簡冊期程日九遷。", "此事知心君有幾，不妨相伴各童顛。"]'),
('17f00b24-2e01-4d67-bcb9-9318db39bb9f','題陳膚仲真希元詩卷贈蕭道士蕭善爲詩亦解鼓琴  其一','魏了翁','宋','宋诗','song-poetry','','[]','手撇飛鳶上五溪，兩牛腰大送行詩。',32,'全唐诗/poet.song.191000.json','["手撇飛鳶上五溪，兩牛腰大送行詩。", "猶嫌言語無多子，古錦奚囊長自隨。"]'),
('a37bb67f-9e56-4097-bf9b-9af136772e4e','題陳膚仲真希元詩卷贈蕭道士蕭善爲詩亦解鼓琴  其二','魏了翁','宋','宋诗','song-poetry','','[]','吾廬几研半生塵，朋友相邀問保鄰。',32,'全唐诗/poet.song.191000.json','["吾廬几研半生塵，朋友相邀問保鄰。", "旅進羣咻渾易事，鄰家老子是何人。"]'),
('2487468d-24b5-4686-a7f8-ba5369d6a90c','題陳膚仲真希元詩卷贈蕭道士蕭善爲詩亦解鼓琴  其三','魏了翁','宋','宋诗','song-poetry','','[]','是間正位至虛靈，都把精神逐外明。',32,'全唐诗/poet.song.191000.json','["是間正位至虛靈，都把精神逐外明。", "勸子抱琴歸舊隠，亂雲深處認真情。"]'),
('1bfb8af9-3354-4e67-b78e-b3f9e7e92f16','肩吾生日  其一','魏了翁','宋','宋诗','song-poetry','','[]','誰遣青龍日夜流，記經星紀已降婁。',32,'全唐诗/poet.song.191000.json','["誰遣青龍日夜流，記經星紀已降婁。", "邊城恰匝三寒暑，初度聯翩四倡酬。"]'),
('039bdf33-3591-4711-b0a9-5dc7ac8698f4','肩吾生日  其二','魏了翁','宋','宋诗','song-poetry','','[]','力探上下三千載，行半東西二百州。',32,'全唐诗/poet.song.191000.json','["力探上下三千載，行半東西二百州。", "有許豪雄都忘却，松窗棐几靜中求。"]'),
('152fbce0-79ed-4175-9768-1bfd9a2b7d0e','肩吾生日  其三','魏了翁','宋','宋诗','song-poetry','','[]','餘晦越鄉別臨賀，郭君出竟送荆州。',32,'全唐诗/poet.song.191000.json','["餘晦越鄉別臨賀，郭君出竟送荆州。", "放麑心事人誇說，得似如今累歲留。"]'),
('e3dad00d-fcb4-4152-8a86-449226c53db5','次肩吾慶生日韻  其一','魏了翁','宋','宋诗','song-poetry','','[]','男兒生世果何事，卜士詩之閭史書。',64,'全唐诗/poet.song.191000.json','["男兒生世果何事，卜士詩之閭史書。", "內美元非私正則，天彝豈但付胥餘。", "滔滔大化亙千古，職職羣生同一初。", "此事年來才信得，從前浪走只成疏。"]'),
('df2eaca9-e460-4a63-9724-934c162d55b5','次肩吾慶生日韻  其二','魏了翁','宋','宋诗','song-poetry','','[]','我友憂時髮滿梳，殷勤勉我用詩書。',64,'全唐诗/poet.song.191000.json','["我友憂時髮滿梳，殷勤勉我用詩書。", "情知分義如何廢，可使才能自有餘。", "氣血漸衰多病後，創夷轉甚數年初。", "夢魂慣識歸來趣，長傍山椒擷稻疏。"]'),
('009a072a-16d8-4cdc-842d-d66bfbb217f0','次韻丁大監見懷  其一','魏了翁','宋','宋诗','song-poetry','','[]','行藏去就各隨時，敬怒嫌疏忍奮飛。',64,'全唐诗/poet.song.191000.json','["行藏去就各隨時，敬怒嫌疏忍奮飛。", "正怕霜嚴天宇凈，敢誇舟載月明歸。", "生松有夢還公固，化鶴何心駐令威。", "獨抱遺編看千古，昔人歷歷未應非。"]'),
('66cfed01-4a7d-49ea-bab0-6d0ff729e7b3','次韻丁大監見懷  其二','魏了翁','宋','宋诗','song-poetry','','[]','見慣不驚如四時，流光任逐鬢蓬飛。',64,'全唐诗/poet.song.191000.json','["見慣不驚如四時，流光任逐鬢蓬飛。", "日從南去老龍蟄，火向西流玄鳥歸。", "荷子感時堂蟋蟀，移書勞我室伊威。", "益嗟往日無良友，四十八年成一非。"]'),
('667d8f31-6e30-4350-a7a9-9f08cc16de2f','次韻九華葉見思鶴山書院詩','魏了翁','宋','宋诗','song-poetry','','[]','天空地迥託吾廬，何處山川不裕如。',64,'全唐诗/poet.song.191000.json','["天空地迥託吾廬，何處山川不裕如。", "太極光陰寧有閒，環中事業本無書。", "道亨誰謂大人否，夷陋不妨君子居。", "昨夢九芙蓉裏去，起聞跫足到空虛。"]'),
('a397ba83-0aa3-41b8-a985-ba1b56f00a99','和虞退夫韻  其一','魏了翁','宋','宋诗','song-poetry','','[]','醵酒成懽似旅酬，偶然解后得英游。',32,'全唐诗/poet.song.191000.json','["醵酒成懽似旅酬，偶然解后得英游。", "却因樂極生良感，今夜蟾光照幾州。"]'),
('22732f7a-10e6-474b-b5a0-b99cdbd9fc90','和虞退夫韻  其二','魏了翁','宋','宋诗','song-poetry','','[]','牛女河邊兩夾持，前瞻箕斗後虛危。',32,'全唐诗/poet.song.191000.json','["牛女河邊兩夾持，前瞻箕斗後虛危。", "經星不動元如此，自是人閒空好奇。"]'),
('6781efd4-7b79-4f87-a0ba-941a3e8aa2e7','和虞退夫韻  其三','魏了翁','宋','宋诗','song-poetry','','[]','假拙濟姦真是拙，認姦作巧巧何曾。',32,'全唐诗/poet.song.191000.json','["假拙濟姦真是拙，認姦作巧巧何曾。", "須知我自靈於物，一點光明萬古鐙。"]'),
('384b8239-c6fc-49ba-9438-46ca514140b2','子益教授再用韻賦弈有審機從諫之誨某復和呈  其一','魏了翁','宋','宋诗','song-poetry','','[]','從衡腷膊競相酬，伺擊羸行緯復游。',32,'全唐诗/poet.song.191000.json','["從衡腷膊競相酬，伺擊羸行緯復游。", "或把疑兵勝淝水，或乘猛勢失荆州。"]'),
('8c731b9e-d39e-4d89-a6b9-0af4a0374635','子益教授再用韻賦弈有審機從諫之誨某復和呈  其二','魏了翁','宋','宋诗','song-poetry','','[]','古人用衆水如持，不爲常安不慮危。',32,'全唐诗/poet.song.191000.json','["古人用衆水如持，不爲常安不慮危。", "違諫伏波終自困，捍羌充國本無奇。"]'),
('68775125-ae27-4f17-8e5b-5abd434bcfe3','子益教授再用韻賦弈有審機從諫之誨某復和呈  其三','魏了翁','宋','宋诗','song-poetry','','[]','才分雖殊學可能，譬如泰華立曾曾。',32,'全唐诗/poet.song.191000.json','["才分雖殊學可能，譬如泰華立曾曾。", "居高視廣心逾遠，下眎羣峰如豆鐙。"]'),
('ed3b34ca-a272-49de-bd04-e065a0fd9d9c','某曩在遂寧嘗賦木犀云茂樹幽花兀老蒼不隨衆卉入詞場虎頭點點開金粟犀首纍纍佩印章明月上時疑白傅清風度處看黄香人才生世元如此不爲無人不肯芳今十數年矣偶憶前作未免兒戲用韻再賦呈諸友','魏了翁','宋','宋诗','song-poetry','','[]','洞煙谿月楚山蒼，萬木辭林稼滌場。',64,'全唐诗/poet.song.191000.json','["洞煙谿月楚山蒼，萬木辭林稼滌場。", "老桂挾秋清入骨，明河倚樹爛成章。", "城隅靜女閒逾美，澤畔纍臣晚更香。", "若數秋花饒此品，未容陶菊逞孤芳。"]'),
('e46e12d5-310a-4312-91c2-6a58517ec24e','某偶爲木犀有賦遂蒙別駕諸丈光和盈軸因惟晉以後名科第曰折桂兩無相關至近世則又以木犀之別種有巖桂之名其實非桂也遂併爲一物輒爲二木訟冤呈諸丈一笑','魏了翁','宋','宋诗','song-poetry','','[]','澹雲明露立蒼蒼，不識從來聲利場。',64,'全唐诗/poet.song.191000.json','["澹雲明露立蒼蒼，不識從來聲利場。", "晉士習浮輕興喻，唐人承誤轉周章。", "高談天上兔蟾影，卑擬人閒龍麝香。", "犀桂自殊苦相累，都將榮進溷真芳。"]'),
('0239b6e0-7d2b-47bc-83eb-2526936991ad','次韻中秋風雨中約客葉元老有詩','魏了翁','宋','宋诗','song-poetry','','[]','長雨頑雲處處山，浹旬渾不露天慳。',64,'全唐诗/poet.song.191000.json','["長雨頑雲處處山，浹旬渾不露天慳。", "魚旟未兆心如醉，鴻鴈關情鬢欲斑。", "月體晦明猶偶爾，酒腸舒慘亦渾閒。", "只將愚慮酬佳贈，未必騷情不破顔。"]'),
('57615c03-d011-48ec-8964-1e15307b1880','虞退夫生日  其一','魏了翁','宋','宋诗','song-poetry','','[]','尚記扁舟下古渝，蘭芽秀茁媚庭除。',32,'全唐诗/poet.song.191000.json','["尚記扁舟下古渝，蘭芽秀茁媚庭除。", "跕鳶聲裏驚重見，玉粹揚休偉丈夫。"]'),
('914eeb33-5118-4c7d-9a2c-473727b4afdd','虞退夫生日  其二','魏了翁','宋','宋诗','song-poetry','','[]','雍公匹馬立乾坤，善念熏蒸到子孫。',32,'全唐诗/poet.song.191000.json','["雍公匹馬立乾坤，善念熏蒸到子孫。", "富貴君家餘事耳，更將此念植仍昆。"]'),
('e2e32906-e4e5-4506-8210-678387570d87','用真景元韻題豫章朱正父湖山清隠詩卷','魏了翁','宋','宋诗','song-poetry','','[]','乾坤爾闊着吾廬，水繞山環仁知居。',64,'全唐诗/poet.song.191000.json','["乾坤爾闊着吾廬，水繞山環仁知居。", "君友東湖徐孺子，我聞西洛邵堯夫。", "欲爲天下屠龍手，肯讀人閒非聖書。", "聊借斯言相贈勉，樂顔之樂即顔徒。"]'),
('4eb5a7f2-6823-4bb1-ba52-91b0f99ba99e','次韻虞退夫除夕七絕句  其一','魏了翁','宋','宋诗','song-poetry','','[]','太極光陰不計年，聖賢千古此周旋。',32,'全唐诗/poet.song.191000.json','["太極光陰不計年，聖賢千古此周旋。", "九夷自陋吾何與，長在回瓢點瑟邊。"]'),
('f84a9b59-c132-46c6-8a35-3aec8d59904c','次韻虞退夫除夕七絕句  其二','魏了翁','宋','宋诗','song-poetry','','[]','從渠滿腹貯千年，遮莫揮毫動百篇。',32,'全唐诗/poet.song.191000.json','["從渠滿腹貯千年，遮莫揮毫動百篇。", "入到聖門無一事，東西日月自行天。"]'),
('5ae6057e-9adc-40b1-8e63-d86975659390','次韻虞退夫除夕七絕句  其三','魏了翁','宋','宋诗','song-poetry','','[]','將軍元自敬延年，明主何曾棄浩然。',32,'全唐诗/poet.song.191000.json','["將軍元自敬延年，明主何曾棄浩然。", "自分康時了無策，故山多少未芸田。"]'),
('b513e6e2-f112-49d0-92d9-1b90d5119e95','次韻虞退夫除夕七絕句  其四','魏了翁','宋','宋诗','song-poetry','','[]','已是秋陰誤有年，泰交倏變震乘乾。',32,'全唐诗/poet.song.191000.json','["已是秋陰誤有年，泰交倏變震乘乾。", "阿香夜夜驚春夢，推出新悲上鬢邊。"]'),
('c91a0958-ee2c-449c-a6c6-4efecf58251b','次韻虞退夫除夕七絕句  其五','魏了翁','宋','宋诗','song-poetry','','[]','長嘆熙豐祐聖年，偏輕偏重幾番舡。',32,'全唐诗/poet.song.191000.json','["長嘆熙豐祐聖年，偏輕偏重幾番舡。", "誰能裝載亭勻了，多著男兒盡力牽。"]'),
('2f1f0dab-ab42-459a-84d7-4dccb714bcaf','次韻虞退夫除夕七絕句  其六','魏了翁','宋','宋诗','song-poetry','','[]','又嘆崇寧宣政年，無端亡虜誤開邊。',32,'全唐诗/poet.song.191000.json','["又嘆崇寧宣政年，無端亡虜誤開邊。", "誰能爲我懲前轍，早挈江山入舜甄。"]'),
('7ecb5b34-2814-4fa9-8bbb-c5af1cfaa870','次韻虞退夫除夕七絕句  其七','魏了翁','宋','宋诗','song-poetry','','[]','虞倩思親感歲年，歸心巫峽暮雲前。',32,'全唐诗/poet.song.191000.json','["虞倩思親感歲年，歸心巫峽暮雲前。", "乖逢逝止那能料，靜倚閒雲看大川。"]'),
('d9909d56-b887-49be-ab51-1366b53bc2de','用張子益教授韻送虞退夫西歸','魏了翁','宋','宋诗','song-poetry','','[]','子已江頭戒櫂郎，卬須何事未乘方。',64,'全唐诗/poet.song.191000.json','["子已江頭戒櫂郎，卬須何事未乘方。", "須看此意關時數，不爲斯人自肺腸。", "白傅徒然泣商婦，毛生豈解出王檣。", "卬雖不敏真知得，爲子臨岐釂一觴。"]'),
('13bde5ce-ac1e-438d-93d6-8d4c21795e25','嘗爲趙太社作章泉二字及匹紙寫詩二十二首趙一再有詩因次韻  其一','魏了翁','宋','宋诗','song-poetry','','[]','易象於坤必有章，泉翁此義發天光。',64,'全唐诗/poet.song.191000.json','["易象於坤必有章，泉翁此義發天光。", "離趨外卦文加質，乾伏中爻絅覆裳。", "欲驗吾心觀習坎，誠知是理識歸藏。", "公詩謝我祗成辱，敢復從公質寸長。"]'),
('bace9653-42a7-4450-b55a-9ca256e39157','嘗爲趙太社作章泉二字及匹紙寫詩二十二首趙一再有詩因次韻  其二','魏了翁','宋','宋诗','song-poetry','','[]','幾度詩來儆謬悠，懷人應念水三州。',64,'全唐诗/poet.song.191000.json','["幾度詩來儆謬悠，懷人應念水三州。", "寧睎太白懷金馬，忍效靈均駟玉虯。", "上帝汝臨毋敢貳，中心如噎本何求。", "狂言又被公挑撥，知我惟公不我郵。"]'),
('5e80b049-7dc1-4c88-954a-c0291ba58115','題趙昌父太社寄桃源何道士','魏了翁','宋','宋诗','song-poetry','','[]','八十六年彊健客，求余判斷二蘇詩。',32,'全唐诗/poet.song.191000.json','["八十六年彊健客，求余判斷二蘇詩。", "年來點檢室中事，問着鄰家總不知。"]'),
('273b95e8-dc4a-46b2-addc-8d0d02f6ca1c','題羅年能六友堂','魏了翁','宋','宋诗','song-poetry','','[]','羅氏堂中六友圖，要求紙尾數行書。',32,'全唐诗/poet.song.191000.json','["羅氏堂中六友圖，要求紙尾數行書。", "若於此味真知得，着甚言詞乞與渠。"]'),
('9df292ae-b156-443e-bdcd-240af9290a98','次韻靖州貢士鹿鳴宴二首  其一','魏了翁','宋','宋诗','song-poetry','','[]','何處何時不産賢，黔中故地夜郎天。',64,'全唐诗/poet.song.191000.json','["何處何時不産賢，黔中故地夜郎天。", "雖云地脈元無閒，欲破天荒未有先。", "萬蟻場中春鎖棘，九賓庭下曉鳴鞭。", "便將正學昭羣聵，留取魁名萬口傳。"]'),
('4c186559-84b9-4336-bd11-a539b6ccc12a','次韻靖州貢士鹿鳴宴二首  其二','魏了翁','宋','宋诗','song-poetry','','[]','豈但詩書對聖賢，須知屋漏與神天。',23,'全唐诗/poet.song.191000.json','["豈但詩書對聖賢，須知屋漏與神天。", "設科雖較詞章。"]'),
('6433e808-7105-4cb4-ba64-d63e9da14215','次韻靖州貢士鹿鳴宴二首  其三','魏了翁','宋','宋诗','song-poetry','','[]','鳴春。',19,'全唐诗/poet.song.191000.json','["鳴春。", "敢將愚見酬佳贈，願子深思勿語人。"]'),
('38cd1ae1-4343-406d-9e10-d72b6dcc4ba7','次韻王常博題贈江陵樂德佐  其一','魏了翁','宋','宋诗','song-poetry','','[]','僇餘甘遠屏，分表得生還。',48,'全唐诗/poet.song.191000.json','["僇餘甘遠屏，分表得生還。", "夜雨滴歸夢，曉霜彫醉顔。", "角巾吾故里，璞玉子荆山。", "又作無期別，扁舟上峽關。"]'),
('75f1007b-96dd-4e98-9993-b8fa212a3a74','次韻王常博題贈江陵樂德佐  其二','魏了翁','宋','宋诗','song-poetry','','[]','三十有三載，好風吹又來。',48,'全唐诗/poet.song.191000.json','["三十有三載，好風吹又來。", "清堅霜後竹，冷澹雪邊梅。", "世事憂千緒，家山腸九回。", "江頭一樽酒，煙雨暗章臺。"]'),
('783ed2e5-9909-4e23-b841-2fd82bd379f8','題峽州三遊洞  其一','魏了翁','宋','宋诗','song-poetry','','[]','洞前日日客維舟，短詠長吟汗馬牛。',32,'全唐诗/poet.song.191000.json','["洞前日日客維舟，短詠長吟汗馬牛。", "名迹都隨形氣盡，惟餘元白幾人留。"]'),
('e1c8dac0-dc22-4909-a767-749104e74f3d','題峽州三遊洞  其二','魏了翁','宋','宋诗','song-poetry','','[]','可怪忠州與虢州，偶因起廢得茲遊。',32,'全唐诗/poet.song.191000.json','["可怪忠州與虢州，偶因起廢得茲遊。", "蘇歐諸老亦何德，千古聯芳未肯休。"]'),
('75975e1e-6c59-4e29-8b84-ca7111edddcb','和虞退夫見貽生日詩韻  其一','魏了翁','宋','宋诗','song-poetry','','[]','夫容布葉亂田田，尚憶前年對二賢。',32,'全唐诗/poet.song.191000.json','["夫容布葉亂田田，尚憶前年對二賢。", "今度觀亭人獨立，一江風月意誰傳。"]'),
('2b70e6de-9f61-4856-bdc2-07ec5b5b9ac7','和虞退夫見貽生日詩韻  其二','魏了翁','宋','宋诗','song-poetry','','[]','路人笑我此何觀，風颭渠江萬頃寒。',32,'全唐诗/poet.song.191000.json','["路人笑我此何觀，風颭渠江萬頃寒。", "歷歷聖賢心事在，從渠把作畫圖看。"]'),
('bb7f4346-825d-4f28-b7d4-4d2230d10ced','和虞退夫見貽生日詩韻  其三','魏了翁','宋','宋诗','song-poetry','','[]','九十九峰江上山，乾坤爾闊我中間。',32,'全唐诗/poet.song.191000.json','["九十九峰江上山，乾坤爾闊我中間。", "此心頓著秋豪愧，久矣顔衰鬢髮斑。"]'),
('1b0ff8a7-9897-49f8-87c0-46f9e0b69848','和虞退夫見貽生日詩韻  其四','魏了翁','宋','宋诗','song-poetry','','[]','虎豹當關路險艱，家人占鵲望予還。',32,'全唐诗/poet.song.191000.json','["虎豹當關路險艱，家人占鵲望予還。", "四方蹙蹙還何許，家在西南山外山。"]'),
('fee4170c-510c-4382-a428-170435b8d841','和虞退夫見貽生日詩韻  其五','魏了翁','宋','宋诗','song-poetry','','[]','范蔣諸賢友義申，肩吾見說倍精神。',32,'全唐诗/poet.song.191000.json','["范蔣諸賢友義申，肩吾見說倍精神。", "年來人物寥寥甚，更憶浦城人姓真。"]'),
('28ce0d99-ddea-4edf-ac4f-37597a44a43d','和蔣成甫見貽生日韻  其一','魏了翁','宋','宋诗','song-poetry','','[]','窗外浮雲捲帝青，腰閒流水卧青萍。',64,'全唐诗/poet.song.191000.json','["窗外浮雲捲帝青，腰閒流水卧青萍。", "發揮孔孟真三代，補葺嬴劉破六經。", "理義本心如皦日，詞章末伎謾流螢。", "獨嗟弱步躋長阪，百歲期程過五亭。"]'),
('1324fdf3-e2d8-4e08-a645-ca07f03b2e23','和蔣成甫見貽生日韻  其二','魏了翁','宋','宋诗','song-poetry','','[]','尚記春風酒滿衣，數旬客館掩空扉。',64,'全唐诗/poet.song.191000.json','["尚記春風酒滿衣，數旬客館掩空扉。", "雙烏念哺歸難忍，斷雁辭行凝不飛。", "正念縣弧成底事，有來連錦爛生輝。", "亟哦七字酬佳贈，歸櫂瀟湘水正肥。"]'),
('0c8adb31-b55e-4dfe-a11b-dc8df6fc8d71','次韻知常德袁尊固監丞送別四詩  其一','魏了翁','宋','宋诗','song-poetry','','[]','試把行藏爲子評，只知盡分敢徼名。',64,'全唐诗/poet.song.191000.json','["試把行藏爲子評，只知盡分敢徼名。", "出如有益殷三聘，用不能行魯兩生。", "此道古人如飲食，後來竈婢或猜驚。", "子雲亦號知書者，猶把商山作采榮。"]'),
('1a43c70e-fa4e-4f8e-8b24-4b0ab050acaa','次韻知常德袁尊固監丞送別四詩  其二','魏了翁','宋','宋诗','song-poetry','','[]','孔訓元無實對名，只言爲己與求人。',64,'全唐诗/poet.song.191000.json','["孔訓元無實對名，只言爲己與求人。", "能知管仲不爲諒，便識殷賢都是仁。", "義利兩塗消處長，古今一理屈中伸。", "自從聖學寥寥後，千百年誰信得真。"]'),
('a11e6b8c-0994-4cc0-b830-e0f97d59be43','次韻知常德袁尊固監丞送別四詩  其三','魏了翁','宋','宋诗','song-poetry','','[]','別來歲月爾滔滔，流落天涯忽此遭。',64,'全唐诗/poet.song.191000.json','["別來歲月爾滔滔，流落天涯忽此遭。", "萬木辭榮秋意澹，百川歸壑岸容高。", "笑看海上兩蝸角，閒禿山中千兔毫。", "若向顔曾得消息，直須奴僕命離騷。"]'),
('ecc5e854-33ac-4ca2-9dde-5d9f1b5a1b6a','次韻知常德袁尊固監丞送別四詩  其四','魏了翁','宋','宋诗','song-poetry','','[]','夕陽舂處是吾家，水繞山環路轉賒。',64,'全唐诗/poet.song.191000.json','["夕陽舂處是吾家，水繞山環路轉賒。", "蹙蹙四方渾未定，茫茫大化渺無涯。", "歸來已恨十年晚，老去空嗟兩鬢華。", "各願及時崇令德，萬鍾於我本何加。"]'),
('02857442-83f7-4b65-92cc-299d59c197ef','用蔣成甫韻賀虞退夫生子且以相名之','魏了翁','宋','宋诗','song-poetry','','[]','秦雍孫曾尚典刑，只將一念答天明。',64,'全唐诗/poet.song.191000.json','["秦雍孫曾尚典刑，只將一念答天明。", "震雷殷地勾萌達，解雨鳴春澗谷聲。", "階玉正看聯羯末，籝金安足擬賢成。", "相門爲我成宅相，我欲將兒以相名。"]'),
('7e9e3ce8-1142-459e-a37c-e413486ceea6','虞退夫生日  其一','魏了翁','宋','宋诗','song-poetry','','[]','人情處約久斯渝，子把膏腴氣習除。',32,'全唐诗/poet.song.191000.json','["人情處約久斯渝，子把膏腴氣習除。", "肯向縑緗迂事業，要尋屋漏實工夫。"]'),
('b7d69e0d-502b-4b38-93c3-aa8fa556f5e4','虞退夫生日  其二','魏了翁','宋','宋诗','song-poetry','','[]','初度重逢巽上坤，庭闈應念子生孫。',32,'全唐诗/poet.song.191000.json','["初度重逢巽上坤，庭闈應念子生孫。", "好將吉語傳金母，更把歸音報玉昆。"]'),
('8f2da2d4-e63e-46e2-87a1-d1f4b8589775','十一月九日新灘李示余開禧三年四月九日所跋外舅楊憲使灘字韻詩爲次韻','魏了翁','宋','宋诗','song-poetry','','[]','憶從筮仕歲涒灘，三十餘年閲暑寒。',64,'全唐诗/poet.song.191000.json','["憶從筮仕歲涒灘，三十餘年閲暑寒。", "撫事無成人潦倒，懷人有夢涕汍瀾。", "家山擾擾膠膠裏，廟社譆譆出出間。", "欲上青天愁險絕，誰能爲我斬樓蘭。"]'),
('6d26efc4-1f4e-4b4d-bf9d-1a457cfa95a1','建士施霆亨自夔以詩相迓','魏了翁','宋','宋诗','song-poetry','','[]','三峽雲連白帝城，風波九死得餘生。',64,'全唐诗/poet.song.191000.json','["三峽雲連白帝城，風波九死得餘生。", "虎頭狼尾亂流濟，貓面馬肝緣壁行。", "中衍何妨需在險，心亨但見坎常平。", "况逢詩友慇懃問，寧復窮途哭步兵。"]'),
('e1f6b6dc-59e0-48f0-977f-29323d38ab59','過虎頭狼尾灘避險出陸至譚晉仲故居有謝公昌國劉公德脩薛公仲章詩用謝韻有賦  其一','魏了翁','宋','宋诗','song-poetry','','[]','尚記翩然下帝傍，七年纔入屈公鄉。',64,'全唐诗/poet.song.191000.json','["尚記翩然下帝傍，七年纔入屈公鄉。", "山銜西日去家近，風遞北氛吹袂凉。", "新事感傷心力短，舊交零落話頭長。", "况堪劉薛吾師友，黄壤堂堂閟夜光。"]'),
('5ed17eda-b604-48af-b8c7-285754f67894','過虎頭狼尾灘避險出陸至譚晉仲故居有謝公昌國劉公德脩薛公仲章詩用謝韻有賦  其二','魏了翁','宋','宋诗','song-poetry','','[]','紛紛操罟入山林，我自終朝不獲禽。',64,'全唐诗/poet.song.191000.json','["紛紛操罟入山林，我自終朝不獲禽。", "遠物只知肥遯利，窮幽不問浚恒深。", "畢逋啼日滿荒戍，款段行雲供醉吟。", "宇宙窮空歲遲暮，平沙獨立數寒金。"]'),
('5510194d-8c08-4ded-8cfc-d2e517783935','書所見聞示諸友  其一','魏了翁','宋','宋诗','song-poetry','','[]','行到青天最上頭，蜀人爭看錦衣遊。',32,'全唐诗/poet.song.191000.json','["行到青天最上頭，蜀人爭看錦衣遊。", "誰知一夜北風惡，吹起家山萬斛愁。"]'),
('e70f4c35-8fae-43ac-af6a-7ee4476f5825','書所見聞示諸友  其二','魏了翁','宋','宋诗','song-poetry','','[]','聞說奔軍闖閬州，餘州民潰去如流。',32,'全唐诗/poet.song.191000.json','["聞說奔軍闖閬州，餘州民潰去如流。", "親曾見虎誠堪怖，只爲狐驚亦可羞。"]'),
('a71bddef-ef03-40ba-bdef-acd88166f800','書所見聞示諸友  其三','魏了翁','宋','宋诗','song-poetry','','[]','一從輕棄五邊州，所恃藩籬僅武休。',32,'全唐诗/poet.song.191000.json','["一從輕棄五邊州，所恃藩籬僅武休。", "又謂武休無足恃，併捐洋漢守金牛。"]'),
('576d5737-eea8-421d-92aa-e82f366c197e','書所見聞示諸友  其四','魏了翁','宋','宋诗','song-poetry','','[]','金繒啗虜已無謀，况恃空言廢內修。',32,'全唐诗/poet.song.191000.json','["金繒啗虜已無謀，况恃空言廢內修。", "師卦在中惟九二，曾聞帷幄授成籌。"]'),
('e726da89-1c52-4480-829f-3fa2582a2d47','書所見聞示諸友  其五','魏了翁','宋','宋诗','song-poetry','','[]','死城陷陣已長休，捍虜鳩民亦漫憂。',32,'全唐诗/poet.song.191000.json','["死城陷陣已長休，捍虜鳩民亦漫憂。", "局外閒人倚江立，全軀保室信良謀。"]'),
('68c9f345-f4a0-4bd4-a858-1431bdbbaab7','次韻虞退夫除夕七絕句  其一','魏了翁','宋','宋诗','song-poetry','','[]','蜀人誰不望西還，何事天公獨我慳。',32,'全唐诗/poet.song.191000.json','["蜀人誰不望西還，何事天公獨我慳。", "兩度來逢單閼歲，腥風血雨滿人間。"]'),
('f5ffea57-1e39-43f5-8e78-1d7dfac4137c','次韻虞退夫除夕七絕句  其二','魏了翁','宋','宋诗','song-poetry','','[]','誰驅斗柄向東遷，漸喜新年勝故年。',32,'全唐诗/poet.song.191000.json','["誰驅斗柄向東遷，漸喜新年勝故年。", "歲緯移躔東井外，狼星歛角左參邊。"]'),
('0d1276d7-88f6-42b8-95f0-3bc7df9cf221','次韻虞退夫除夕七絕句  其三','魏了翁','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','是滔滔者竟誰歸，有酒盈巵不暇揮。',32,'全唐诗/poet.song.191000.json','["是滔滔者竟誰歸，有酒盈巵不暇揮。", "待挽長江洗兵馬，盡還草木舊晶暉。"]'),
('9c89f394-0969-4803-8cdb-39a3e4c9fcaa','次韻虞退夫除夕七絕句  其四','魏了翁','宋','宋诗','song-poetry','','[]','雲外銜山日半環，傳盃共惜片雲懽。',32,'全唐诗/poet.song.191000.json','["雲外銜山日半環，傳盃共惜片雲懽。", "莫疑來日是來歲，萬古光陰只麽看。"]'),
('126d7284-656b-4efd-879a-89b69391f71f','次韻虞退夫除夕七絕句  其五','魏了翁','宋','宋诗','song-poetry','','[]','幾度將心安處安，有時中夜起長嘆。',32,'全唐诗/poet.song.191000.json','["幾度將心安處安，有時中夜起長嘆。", "年來識得安心法，否泰元從隨蠱看。"]'),
('6152cc51-69d9-410a-bb18-461dda9e7eee','次韻虞退夫除夕七絕句  其六','魏了翁','宋','宋诗','song-poetry','','[]','人道渠陽爾嶮囏，嶮囏在彼我何關。',32,'全唐诗/poet.song.191000.json','["人道渠陽爾嶮囏，嶮囏在彼我何關。", "却從楚澤寬平後，彫盡從前鏡裏顔。"]'),
('bc2d6cc4-9a71-4f32-928e-69df9328dda3','次韻虞退夫除夕七絕句  其七','魏了翁','宋','宋诗','song-poetry','','[]','明朝同上四賢山，要與羣英盡日還。',32,'全唐诗/poet.song.191000.json','["明朝同上四賢山，要與羣英盡日還。", "認取鈎深堂上意，春風曳曳鳥關關。"]'),
('475e2d70-4bcc-4ffd-9e6f-92e927bb2784','用樊武仲致政韻餞黄戶部','魏了翁','宋','宋诗','song-poetry','','[]','七載賫身入楚鄉，誰將平坂換羊腸。',64,'全唐诗/poet.song.191000.json','["七載賫身入楚鄉，誰將平坂換羊腸。", "覺來親友渾依舊，觸處江山不改香。", "正引德星成勝集，更忻郎宿下垂光。", "人生行止時爲大，膜外浮榮蟻穴王。"]'),
('ef5747a6-b0ac-4e66-a4dc-08f83918326c','次韻荆門張守寺簿見寄詩韻張守以制司調民築城申朝廷制司繳納告敕不願仕  其一','魏了翁','宋','宋诗','song-poetry','','[]','不把離憂寄楚辭，絕嗤致邑請臧爲。',64,'全唐诗/poet.song.191000.json','["不把離憂寄楚辭，絕嗤致邑請臧爲。", "日纔北向夏長至，火未西流秋變衰。", "消息一機川水逝，詘信二氣蟄蟲知。", "夫君識慮超餘子，我亦年來管豹窺。"]'),
('fc172093-cc89-4eb6-bdf5-676b78d1c155','次韻荆門張守寺簿見寄詩韻張守以制司調民築城申朝廷制司繳納告敕不願仕  其二','魏了翁','宋','宋诗','song-poetry','','[]','書來寄我賦歸辭，諒子知其不可爲。',64,'全唐诗/poet.song.191000.json','["書來寄我賦歸辭，諒子知其不可爲。", "𧥄𧥄牛羊芻牧隘，嗸嗸鴻鴈稻粱衰。", "有饑有溺己饑溺，後覺後知誰覺知。", "細翫海州三奏藁，前賢風味儼重窺。"]'),
('45843dca-38a0-454f-8744-ca480641e2b8','六月十四次韻樊武仲喜雨','魏了翁','宋','宋诗','song-poetry','','[]','誰信夔夔解感神，嚶嚶赤子母心熏。',64,'全唐诗/poet.song.191000.json','["誰信夔夔解感神，嚶嚶赤子母心熏。", "爲將一滴翻瓢水，散作千家舉臿雲。", "大化無端長寂寂，衆形有欲自芸芸。", "更須盡挽天河水，亟與三邊洗惡氛。"]'),
('31e5324f-b2e8-472e-a3fa-c88da437a953','送楊子有赴敘倅用高榮州韻','魏了翁','宋','宋诗','song-poetry','','[]','俗事縈人阻四并，東郊又送屏星行。',64,'全唐诗/poet.song.191000.json','["俗事縈人阻四并，東郊又送屏星行。", "欲安邊圉元無策，善服人心只有清。", "使馬如羊非我愛，带牛佩犢豈其情。", "非惟此意行夷狄，讒舌雖工亦絕聲。"]'),
('4b93c992-63ef-4646-8b38-6b06479d8f51','長女生日  其一','魏了翁','宋','宋诗','song-poetry','','[]','相逢猶記度瀟湘，旋理衿纓旋理裝。',32,'全唐诗/poet.song.191000.json','["相逢猶記度瀟湘，旋理衿纓旋理裝。", "壻見舅姑纔識面，明朝馬首上渠陽。"]'),
('d30800f6-a6f7-48a9-8696-4301ed9a4858','長女生日  其二','魏了翁','宋','宋诗','song-poetry','','[]','蜑煙蠻雨鎖窮荒，寇焰兵氛返故鄉。',32,'全唐诗/poet.song.191000.json','["蜑煙蠻雨鎖窮荒，寇焰兵氛返故鄉。", "誰信夢回人似舊，青衣綵服儼成行。"]'),
('481eab63-1922-437c-a11a-e04fd4b01794','長女生日  其三','魏了翁','宋','宋诗','song-poetry','','[]','兩地耶娘正健强，門楣况是得安郎。',32,'全唐诗/poet.song.191000.json','["兩地耶娘正健强，門楣况是得安郎。", "七年重會非容易，且爲新陽釂一觴。"]'),
('f755edcb-8467-4e7c-afef-ea001755d9ef','送李蒲江歸簡池用高榮州韻','魏了翁','宋','宋诗','song-poetry','','[]','尚記春風黄栗留，明年春又到鈎輈。',64,'全唐诗/poet.song.191000.json','["尚記春風黄栗留，明年春又到鈎輈。", "會疏長作去時恨，年大能禁生別愁。", "言偃得人行不徑，繆公受責俾如流。", "願將二語爲君贈，更願開誠學武侯。"]'),
('88595bdb-bd79-4310-9330-9e7a0c329b84','北郊勞農歸路五十六言','魏了翁','宋','宋诗','song-poetry','','[]','方春不及與劭農，十月郊行勞歲功。',64,'全唐诗/poet.song.191000.json','["方春不及與劭農，十月郊行勞歲功。", "因記旱雲占晻濭，更愁霖雨望曈矓。", "田苗粒粒祈禳裏，民命絲絲嘆恨中。", "憂國願豐雖我志，更須人事與天通。"]'),
('b1f324af-461e-460c-bbe4-e6ff8f750077','安總領生日  其一','魏了翁','宋','宋诗','song-poetry','','[]','猶記僊翁護玉關，版圖半壁手提還。',64,'全唐诗/poet.song.191000.json','["猶記僊翁護玉關，版圖半壁手提還。", "每驚蕩潏風波後，多謝經綸父子間。", "元是爛柯觀已熟，故應當局祇如閒。", "幾人錢穀鞭中老，雙鬢何曾點一斑。"]'),
('3aba6065-8f49-40bc-a02f-62ac3829e032','安總領生日  其二','魏了翁','宋','宋诗','song-poetry','','[]','祝公不作語啾啾，陛下憑公釋顧憂。',64,'全唐诗/poet.song.191000.json','["祝公不作語啾啾，陛下憑公釋顧憂。", "往誤叵堪成鐵錯，後圖猶可保金甌。", "飲江共喜無胡馬，屯渭懸知有木牛。", "虎也膚公康是似，願歌江漢美宗周。"]'),
('c49d06df-7593-4f53-8f48-20aba48068cf','楊尚書生日  其一','魏了翁','宋','宋诗','song-poetry','','[]','幾許中和釀此身，秋風江上玉精神。',64,'全唐诗/poet.song.191000.json','["幾許中和釀此身，秋風江上玉精神。", "性姿無忤水行地，富貴有緣花得春。", "閒處消摇欣佚老，會朝魁艾正須人。", "絕知雲滃龍淵濕，莫倚晴江把釣緡。"]'),
('6fb0338b-ffcc-4c66-9f88-056f50090e68','楊尚書生日  其二','魏了翁','宋','宋诗','song-poetry','','[]','三邊頭緒正相尋，雲氣模糊尚積陰。',64,'全唐诗/poet.song.191000.json','["三邊頭緒正相尋，雲氣模糊尚積陰。", "已喜龍荒通漢使，更須帝夢起商霖。", "功名本自於人薄，家國相關此念深。", "共指岷峨祝公壽，鬢華未聽曉霜侵。"]'),
('0ef4aac9-5675-46eb-a620-3e217724f16f','李制置生日  其一','魏了翁','宋','宋诗','song-poetry','','[]','玉堂人住玉堂山，公論推排授將壇。',64,'全唐诗/poet.song.191000.json','["玉堂人住玉堂山，公論推排授將壇。", "朔壘令嚴精采異，甘泉烽息顧憂寬。", "北邊舊嘆無頗牧，西賊今聞有范韓。", "夏屋不知幾崇廣，喚回春燕下林端。"]'),
('a359ac4b-9725-41e8-a799-bb1b7769057b','李制置生日  其二','魏了翁','宋','宋诗','song-poetry','','[]','披荆重立小朝廷，風遞南薰入扇巾。',64,'全唐诗/poet.song.191000.json','["披荆重立小朝廷，風遞南薰入扇巾。", "大勢已馮天祚宋，中興更頼嶽生申。", "扶持命脈還吾蜀，消息精神運此身。", "人願武公歸入相，我祈河內且留恂。"]'),
('9f19a586-3caa-4ef4-a6d0-93eb37d8fa64','魏茶馬生日  其一','魏了翁','宋','宋诗','song-poetry','','[]','南渡波流蕩潏中，紹興御史最清忠。',64,'全唐诗/poet.song.191000.json','["南渡波流蕩潏中，紹興御史最清忠。", "和戎二字排時論，用世諸孫尚祖風。", "彈壓峽江羣嘯靜，指麾邊市虜資空。", "盛心未必榮三錫，且喜朝廷答有功。"]'),
('c41616c7-ff3d-4023-b76b-cdd3597d9a9d','魏茶馬生日  其二','魏了翁','宋','宋诗','song-poetry','','[]','浪誇京洛漸塵清，局面今翻第幾枰。',64,'全唐诗/poet.song.191000.json','["浪誇京洛漸塵清，局面今翻第幾枰。", "須倚玉龍擎重任，暫依金馬作長城。", "時人共記維寅度，陽畫元從建亥生。", "試向後天推八八，吾宗卜數萬爲盈。"]'),
('dfd24d7f-e74b-4df2-9c51-396b26f203d4','遂寧家知府生日  其一','魏了翁','宋','宋诗','song-poetry','','[]','玉堂元不閟英靈，地主還從此地生。',64,'全唐诗/poet.song.191000.json','["玉堂元不閟英靈，地主還從此地生。", "千里樓高人獨立，九宗山峙月雙清。", "洋洋水薤臨民意，獵獵霜林戰葉聲。", "如許高情誰與擬，玉梅枝外看參橫。"]'),
('10bf2e68-81c3-411b-8bd6-7d5f2a076cc4','遂寧家知府生日  其二','魏了翁','宋','宋诗','song-poetry','','[]','相去無多五日間，兩家牛酒賀生賢。',64,'全唐诗/poet.song.191000.json','["相去無多五日間，兩家牛酒賀生賢。", "二陽引類臨爻長，三壽爲朋泰茹連。", "析木旁瞻星兩兩，大椿遥祝歲千千。", "相期協力亨屯難，未聽絲絲鬢髮宣。"]'),
('05e6f412-5928-4604-a89b-9a42616da2e9','潼川路施運判生日  其一','魏了翁','宋','宋诗','song-poetry','','[]','家聲燁燁自乾淳，王謝門中着此身。',64,'全唐诗/poet.song.191000.json','["家聲燁燁自乾淳，王謝門中着此身。", "金碧池邊金碧使，玉山臺上玉山人。", "都將奕葉芝蘭味，散作羣州桃李春。", "應記西陵分首後，枯棋一局幾回新。"]'),
('cf9f573d-0d31-4f6b-b58a-592fe9aa0828','潼川路施運判生日  其二','魏了翁','宋','宋诗','song-poetry','','[]','朔吹饕寒凝不禁，地雷應合戰羣陰。',64,'全唐诗/poet.song.191000.json','["朔吹饕寒凝不禁，地雷應合戰羣陰。", "悠悠未快功名手，渺渺誰覘造物心。", "三壽作朋剛已復，二陽初動卦爲臨。", "經綸及此身强健，插頷青絲雪未侵。"]'),
('0a4943c8-8e43-403e-9a09-ba0cf6f12ed6','瀘貢士二十人端平元年手書增郡國貢士員瀘增二人是歲貢于東西路轉運司者各二人以五月庚戌合寮吏宴于郡之正牙歌鹿鳴以遣之  其一','魏了翁','宋','宋诗','song-poetry','','[]','皎日中天萬國明，恢恢賢路慶端平。',64,'全唐诗/poet.song.191000.json','["皎日中天萬國明，恢恢賢路慶端平。", "月正元日下書詔，二十六人登姓名。", "西澤射陳狸首節，東廉歌奏鹿鳴聲。", "謬侯何幸身爲駕，要示周行玉女成。"]'),
('fa78b944-540e-4181-84c1-7890fcfa4ed9','瀘貢士二十人端平元年手書增郡國貢士員瀘增二人是歲貢于東西路轉運司者各二人以五月庚戌合寮吏宴于郡之正牙歌鹿鳴以遣之  其二','魏了翁','宋','宋诗','song-poetry','','[]','天地中間着此身，合將位育入經綸。',64,'全唐诗/poet.song.191000.json','["天地中間着此身，合將位育入經綸。", "陰陽固自生成我，爵祿安能富貴人。", "利欲當權心退舍，詖淫得路俗迷津。", "諸君自此騰驤去，願以先知覺此民。"]'),
('101b667f-a207-44b9-be6f-d2e1946e06ab','送李季允赴召  其一','魏了翁','宋','宋诗','song-poetry','','[]','擁馬懽呼夾道迎，詔書洛社起耆英。',64,'全唐诗/poet.song.191000.json','["擁馬懽呼夾道迎，詔書洛社起耆英。", "史筵載筆聯翁季，政路題名接弟兄。", "新政期公皆一律，故交惟我得忘情。", "正邦須自明倫始，要仗公開萬世程。"]'),
('3a0f13d5-0823-4956-8fbd-ac88f8015844','送李季允赴召  其二','魏了翁','宋','宋诗','song-poetry','','[]','一傾鼎否一番新，但見新人笑故人。',64,'全唐诗/poet.song.191000.json','["一傾鼎否一番新，但見新人笑故人。", "元祐至今迭更化，崇寧以後幾權臣。", "曾趨嘉定改元詔，又賀端平第一春。", "長把人才留一半，今年新是去年陳。"]'),
('8bc7d41c-131f-4e4c-87bc-2159e95560a4','送李季允赴召  其三','魏了翁','宋','宋诗','song-poetry','','[]','是是非非各有心，以同爲愛異爲憎。',64,'全唐诗/poet.song.191000.json','["是是非非各有心，以同爲愛異爲憎。", "誓殽秦穆旋修怨，在莒齊威卒震矜。", "事急求言常易入，位高從諫最難能。", "願公一破從前陋，萬里無雲皎日升。"]'),
('8a5ee088-6a0d-4d28-859d-0bc5c3ad35c0','李尚書被召過瀘臨發之日官吏以行香日分追送不及明日尚書自合江詰後期次韻以謝','魏了翁','宋','宋诗','song-poetry','','[]','黄雞喔喔丑前催，擬效張侯夜半來。',64,'全唐诗/poet.song.191000.json','["黄雞喔喔丑前催，擬效張侯夜半來。", "殘夢方隨僧梵去，挐音已聽客帆開。", "江臯望極空留恨，陛下憂深正急才。", "已賦明倫相贈勉，更思桃李及時栽。"]'),
('b0d0a3bf-e3c3-46b1-9fff-44adb82253b6','題外舅提刑楊大夫墓','魏了翁','宋','宋诗','song-poetry','','[]','追思初攝大夫車，得助堂前見舅姑。',64,'全唐诗/poet.song.191000.json','["追思初攝大夫車，得助堂前見舅姑。", "三十三年歸夢枕，一生一死隔黄壚。", "時危剩着人間我，境換遥憐向者吾。", "伯也叔兮今已矣，誓偕仲季勉終圖。"]'),
('5855d306-ed90-4fe4-9562-a65389b8fc98','嘉泰二年題資州醮壇山星斗閣至是同王資州賈大安楊季持諸公登山用前韻  其一','魏了翁','宋','宋诗','song-poetry','','[]','三十三年去復還，筍將重踏舊江山。',64,'全唐诗/poet.song.191000.json','["三十三年去復還，筍將重踏舊江山。", "青衿朋友子當戶，綠幘奚臧霜半鬟。", "贏得光陰歸鬢裏，悔將聲譽落人間。", "聖門事業無窮已，只問君王覓退閒。"]'),
('78d97a67-b1d8-4105-aa92-dfc9cd870a69','嘉泰二年題資州醮壇山星斗閣至是同王資州賈大安楊季持諸公登山用前韻  其二','魏了翁','宋','宋诗','song-poetry','','[]','天磨團團任往還，莫將止處認兼山。',64,'全唐诗/poet.song.191000.json','["天磨團團任往還，莫將止處認兼山。", "水歸寒谷歛秋練，木落前峰明曉鬟。", "天度已歸參井後，日行又值斗箕間。", "若知此處真消息，血氣浮名總是閒。"]'),
('a2119aba-1b74-4147-bc64-edb910a960a2','制置丁少卿生日  其一','魏了翁','宋','宋诗','song-poetry','','[]','皜皜陵霄獨鶴飛，九芙蓉裏爛生輝。',64,'全唐诗/poet.song.191000.json','["皜皜陵霄獨鶴飛，九芙蓉裏爛生輝。", "青陽少府舊弓冶，白石先生新杼機。", "閲盡世紛磨不磷，聽渠公論是邪非。", "恭惟陛下方親政，小却猶應伴紫薇。"]'),
('2086d0af-dd80-4c61-9884-1b1891f30c61','制置丁少卿生日  其二','魏了翁','宋','宋诗','song-poetry','','[]','蜀道今行第幾回，天西玉帳又宏開。',64,'全唐诗/poet.song.191000.json','["蜀道今行第幾回，天西玉帳又宏開。", "鶴歸華表人如舊，龜放長河獨再來。", "屈處觀伸霜後菊，消中見息雪前梅。", "瀘江不解西流去，引領長空酌斗魁。"]'),
('ba5af47b-09be-4386-9f85-35442e1c844b','次韻丁制置遠迎三絕  其一','魏了翁','宋','宋诗','song-poetry','','[]','錦里論交三十年，浮筠大玉透中邊。',32,'全唐诗/poet.song.191000.json','["錦里論交三十年，浮筠大玉透中邊。", "投荒已作無期別，夢覺依然墮我前。"]'),
('2916f40c-2bcd-4e8d-b9a4-c9456cbadd88','次韻丁制置遠迎三絕  其二','魏了翁','宋','宋诗','song-poetry','','[]','喬松挺挺百年期，霜雪無端頓繫之。',32,'全唐诗/poet.song.191000.json','["喬松挺挺百年期，霜雪無端頓繫之。", "一點陽和消不斷，春風又長歲寒枝。"]'),
('23a811b6-c131-467b-8930-9993645d8d34','次韻丁制置遠迎三絕  其三','魏了翁','宋','宋诗','song-poetry','','[]','谿瘴蠻煙隔市朝，十年山徑長蒿茅。',32,'全唐诗/poet.song.191000.json','["谿瘴蠻煙隔市朝，十年山徑長蒿茅。", "好風吹送知時雨，生意洋洋大國郊。"]'),
('761c2bd0-db98-4f9f-993a-c6fdfaead458','寄題李季衡東樓','魏了翁','宋','宋诗','song-poetry','','[]','前年呼舫下玻瓈，突兀新樓闖目圍。',64,'全唐诗/poet.song.191000.json','["前年呼舫下玻瓈，突兀新樓闖目圍。", "鴈影已隨流水去，鶴歸空感昔人非。", "曩遊歷歷夢中似，往事茫茫知者稀。", "幸有季衡風味肖，何當倚檻語朝暉。"]'),
('04661c41-c816-4995-831f-fa60602b811c','題王巴州傳經樓','魏了翁','宋','宋诗','song-poetry','','[]','牣庋充厨書滿家，到無言處柰書何。',64,'全唐诗/poet.song.191000.json','["牣庋充厨書滿家，到無言處柰書何。", "六經文字未曾有，三代聖賢如許多。", "直自語言空布滿，却嗟人物轉消磨。", "有來訂古談經者，試把斯言爲切磋。"]'),
('21889372-1595-4704-8b90-c83807aba90a','恭和聞喜宴御製','魏了翁','宋','宋诗','song-poetry','','[]','祖宗德澤被生民，列服山川各效神。',64,'全唐诗/poet.song.191000.json','["祖宗德澤被生民，列服山川各效神。", "幾見高岡鳴鳳集，又看層浪化魚新。", "升歌幸聽三章雅，佩印行紆五兩綸。", "聖世賓賢如此厚，致君忍負不貲身。"]'),
('39e02072-231c-4c91-b9f4-8116f18d5763','題余氏聚遠樓','魏了翁','宋','宋诗','song-poetry','','[]','若向天機識得親，是間看不盡青春。',32,'全唐诗/poet.song.191000.json','["若向天機識得親，是間看不盡青春。", "須知聚遠惟方寸，說與樓前望眼人。"]'),
('73c935e4-cce3-4886-8905-e49cfdaa2e1a','將作監栽竹徐直翁清叟俾予書植賢亭三大字以詩見貽  其一','魏了翁','宋','宋诗','song-poetry','','[]','烈日嚴霜恣挾持，孤標犖犖肯隨時。',32,'全唐诗/poet.song.191000.json','["烈日嚴霜恣挾持，孤標犖犖肯隨時。", "笑看世上閒桃李，一夕狂風失令姿。"]'),
('8065adf5-1a70-4eb5-a695-c3c0284d440f','將作監栽竹徐直翁清叟俾予書植賢亭三大字以詩見貽  其二','魏了翁','宋','宋诗','song-poetry','','[]','氣端解使四時青，萬物彫零獨典刑。',32,'全唐诗/poet.song.191000.json','["氣端解使四時青，萬物彫零獨典刑。", "嚴子高風扶漢鼎，包胥勁節撼秦庭。"]'),
('1ce1e252-b9b2-466c-9c5c-17f449488f85','將作監栽竹徐直翁清叟俾予書植賢亭三大字以詩見貽  其三','魏了翁','宋','宋诗','song-poetry','','[]','客夢時時遶故山，夢餘砉見玉孱顔。',32,'全唐诗/poet.song.191000.json','["客夢時時遶故山，夢餘砉見玉孱顔。", "徐公本自無通介，自是時人醉眼斑。"]'),
('685b69f8-6e4b-4b04-9ddf-7d00bc38b504','夜直玉堂  其一','魏了翁','宋','宋诗','song-poetry','','[]','金鑾坡上疏開邊，夢也非與三十年。',32,'全唐诗/poet.song.191000.json','["金鑾坡上疏開邊，夢也非與三十年。", "世事煙埃緣手盡，正邪二字在遺編。"]'),
('3ccfddf1-8a40-4c73-8124-140a0869a61f','夜直玉堂  其二','魏了翁','宋','宋诗','song-poetry','','[]','金羈玉勒錦籠韉，重上鑾坡鬢欲宣。',32,'全唐诗/poet.song.191000.json','["金羈玉勒錦籠韉，重上鑾坡鬢欲宣。", "自喜晨趨無媿色，更忻夜直得安眠。"]'),
('5f7381ef-978b-401b-958c-3802b70e511e','四月癸巳發潯陽館過濂谿飯于杏谿愒清虛庵宿太平宮  其一','魏了翁','宋','宋诗','song-poetry','','[]','旌旗陰裏盛傳呼，春夢纔醒一事無。',32,'全唐诗/poet.song.191000.json','["旌旗陰裏盛傳呼，春夢纔醒一事無。", "草草山肴話朋友，依然白鶴故時吾。"]'),
('59155ff6-ba5b-4132-9481-1553df14ce56','四月癸巳發潯陽館過濂谿飯于杏谿愒清虛庵宿太平宮  其二','魏了翁','宋','宋诗','song-poetry','','[]','多少濂谿生並時，兩程夫子詠而歸。',32,'全唐诗/poet.song.191000.json','["多少濂谿生並時，兩程夫子詠而歸。", "須知宇宙何曾隠，魚自川游鳥自飛。"]'),
('d53f5043-21ba-4b0a-9060-60e5a3c8a3e4','四月癸巳發潯陽館過濂谿飯于杏谿愒清虛庵宿太平宮  其三','魏了翁','宋','宋诗','song-poetry','','[]','欲識真人千古心，療饑獨有杏成林。',32,'全唐诗/poet.song.191000.json','["欲識真人千古心，療饑獨有杏成林。", "豈無世上閒桃李，要使人從實行尋。"]'),
('2ffa310b-0ec6-4edf-bf0a-6f9b0a917bd1','四月癸巳發潯陽館過濂谿飯于杏谿愒清虛庵宿太平宮  其四','魏了翁','宋','宋诗','song-poetry','','[]','步自清虛過上宮，千言萬論總談空。',32,'全唐诗/poet.song.191000.json','["步自清虛過上宮，千言萬論總談空。", "擬將一語隨人後，嘗與心謀不肯同。"]'),
('ac0a04e9-9e9a-4b03-80f1-c37832625d2c','四月癸巳發潯陽館過濂谿飯于杏谿愒清虛庵宿太平宮  其五','魏了翁','宋','宋诗','song-poetry','','[]','又過前谿訪梵宮，人言此與老莊同。',32,'全唐诗/poet.song.191000.json','["又過前谿訪梵宮，人言此與老莊同。", "是同是異誰知得，擬問山前無極翁。"]'),
('2c9dd58f-fcce-41b0-b40a-e7f908573ad6','丙申携客自康王觀東北行十里觀谷簾泉  其一','魏了翁','宋','宋诗','song-poetry','','[]','正喜昔聞今見之，泉稱第一更何疑。',32,'全唐诗/poet.song.191000.json','["正喜昔聞今見之，泉稱第一更何疑。", "此心好樂先爲主，但見忠謀皆我欺。"]'),
('0fdbe7dd-41fb-43e2-a01d-f15f3b1498f8','丙申携客自康王觀東北行十里觀谷簾泉  其二','魏了翁','宋','宋诗','song-poetry','','[]','筍將軋軋度巖隈，亂澗穿空去復回。',32,'全唐诗/poet.song.191000.json','["筍將軋軋度巖隈，亂澗穿空去復回。", "方識人間真毀譽，只緣親到地頭來。"]'),
('9f6d4ca0-9098-4ecf-bb93-88825b238e44','題歸宗寺','魏了翁','宋','宋诗','song-poetry','','[]','憒憒深源與會稽，識時惟有一羲之。',32,'全唐诗/poet.song.191000.json','["憒憒深源與會稽，識時惟有一羲之。", "千年誤作能書看，謾說鵝池與墨池。"]'),
('72f76869-fca7-4be9-b24e-ba57a844f281','青玉峽','魏了翁','宋','宋诗','song-poetry','','[]','一派泉聲萬古懸，觀瀾歎逝意悠然。',32,'全唐诗/poet.song.191000.json','["一派泉聲萬古懸，觀瀾歎逝意悠然。", "須知大化無窮已，莫賦銀河落九天。"]'),
('5ed09528-0f94-4593-a9d4-86f6d0308811','萬杉寺','魏了翁','宋','宋诗','song-poetry','','[]','萬杉深處着僧廬，中有昭陵飛帛書。',32,'全唐诗/poet.song.191000.json','["萬杉深處着僧廬，中有昭陵飛帛書。", "想象承平心似醉，小亭竚立看跳珠。"]'),
('f211c1e7-e838-42f3-bda0-bfec9ac2535a','三峽橋','魏了翁','宋','宋诗','song-poetry','','[]','英雲皓雨瀉明蠲，題作人間第六泉。',32,'全唐诗/poet.song.191000.json','["英雲皓雨瀉明蠲，題作人間第六泉。", "擬把谷簾從黜降，却將此水爲超遷。"]'),
('ff8f08b8-c272-46b3-97d3-73de5406f89d','任宜人挽詩','魏了翁','宋','宋诗','song-poetry','','[]','家聲門九戟，庭秀樹三株。',48,'全唐诗/poet.song.191000.json','["家聲門九戟，庭秀樹三株。", "閫範閑金燧，林風瑩玉壺。", "未經親絳幔，何遽作黄壚。", "凝睇兩竿竹，醇情一束芻。"]'),
('74449019-bc32-40d4-a6ea-90a7f1acf21a','支大監挽詩','魏了翁','宋','宋诗','song-poetry','','[]','四海李南紀，蚤從山斗韓。',48,'全唐诗/poet.song.191000.json','["四海李南紀，蚤從山斗韓。", "恥擔兵部米，寧着大夫冠。", "人舐黄金筆，天頒白玉棺。", "平生一厚字，千古薄夫寬。"]'),
('ed73193b-a3f7-4a63-ae5c-be362557befd','嘉興張寺丞挽詩','魏了翁','宋','宋诗','song-poetry','','[]','壯氣凜橫秋，如何老作州。',48,'全唐诗/poet.song.191000.json','["壯氣凜橫秋，如何老作州。", "有兒官左墄，無地辦菟裘。", "木落湖陰暝，書沈塞外秋。", "佳城千古恨，樹靜晚風遒。"]'),
('56b6d26d-edf6-420e-afed-8f52ee7e27e9','韓主簿挽詩','魏了翁','宋','宋诗','song-poetry','','[]','當年門列三株樹，馬足駸駸桐木韓。',64,'全唐诗/poet.song.191000.json','["當年門列三株樹，馬足駸駸桐木韓。", "誰謂平生螢雪事，姳名盤古榜中看。", "不趨益守杜國輔，醉伴鄰翁王慶源。", "一代風流蓋棺了，空餘翁仲慘青原。"]'),
('9f6f971d-e8ec-4a3d-930c-0fa08f3756d3','馮校書挽詩','魏了翁','宋','宋诗','song-poetry','','[]','高志崢嶸局九州，直從人表着先籌。',64,'全唐诗/poet.song.191000.json','["高志崢嶸局九州，直從人表着先籌。", "青囊書在鬼神泣，黄絹辭高冰雪羞。", "槐里但知矜折角，蘭臺無復問長頭。", "玉棺夜入青雲去，山是人非白鶴愁。"]'),
('4828ac92-597c-4f57-89b2-6d14c5610b80','丹稜楊子金挽詩','魏了翁','宋','宋诗','song-poetry','','[]','氣象古君子，淵源朝大夫。',48,'全唐诗/poet.song.191000.json','["氣象古君子，淵源朝大夫。", "里門車下澤，客舍馬青芻。", "霜柏寒逾勁，庭荆老不枯。", "只愁兒返哺，不及見飛烏。"]'),
('a3f7c678-ab01-4517-be34-4e200fe880ca','楊經母范氏挽詩','魏了翁','宋','宋诗','song-poetry','','[]','大父生逢世，嚴君死守城。',48,'全唐诗/poet.song.191000.json','["大父生逢世，嚴君死守城。", "尊章全急義，娣姒得賢名。", "夫子行無玷，男兒學有成。", "典刑今已矣，風雨送紅旌。"]'),
('88650aa4-ff07-4fe6-b16b-dc2128c5fed9','于眉州挽詩  其一','魏了翁','宋','宋诗','song-poetry','','[]','士爲謀身蛇有足，人於囂訟鼠無牙。',32,'全唐诗/poet.song.191000.json','["士爲謀身蛇有足，人於囂訟鼠無牙。", "獄書一落于公手，不識從來豪大家。"]'),
('8cb1b765-1b1f-4c79-99ee-a01d6fedf451','于眉州挽詩  其二','魏了翁','宋','宋诗','song-poetry','','[]','南浦冬陰翻手雨，湓江春漲打頭風。',32,'全唐诗/poet.song.191000.json','["南浦冬陰翻手雨，湓江春漲打頭風。", "乖逢命耳吾何戚，贏得三州桃李叢。"]'),
('5102d080-08f0-4e36-bea0-f2299d30cb44','于眉州挽詩  其三','魏了翁','宋','宋诗','song-poetry','','[]','老鴈長雲橫蜀道，歸鴉落日倚江城。',32,'全唐诗/poet.song.191000.json','["老鴈長雲橫蜀道，歸鴉落日倚江城。", "摩挲少日生祠記，忍聽虞歌薤露聲。"]'),
('f4b913d5-6a26-47fd-8cd0-b560fd147cee','賜冠帔楊氏挽詩  其一','魏了翁','宋','宋诗','song-poetry','','[]','賓筵籩秩秩，宗室被祁祁。',48,'全唐诗/poet.song.191000.json','["賓筵籩秩秩，宗室被祁祁。", "琴瑟鷄鳴御，山河象服宜。", "六珈不偕老，兩髧誓維儀。", "一代賢公子，堂堂鎖繐帷。"]'),
('97c451f6-e7f0-4bba-ba6b-eb21d23c380f','賜冠帔楊氏挽詩  其二','魏了翁','宋','宋诗','song-poetry','','[]','嚴霜六月降，老幹四時春。',48,'全唐诗/poet.song.191000.json','["嚴霜六月降，老幹四時春。", "事閲三朝舊，年開九秩新。", "母孫相與命，輩行獨斯人。", "蹇我幽憂久，傷心倍等倫。"]'),
('9b26f212-42c7-43f0-a743-be3d49f95729','李參政夫人張氏挽詩  其一','魏了翁','宋','宋诗','song-poetry','','[]','澗谿蘋采采，夙夜被祁祁。',48,'全唐诗/poet.song.191000.json','["澗谿蘋采采，夙夜被祁祁。", "琴瑟鷄鳴御，山河象服宜。", "西悲零雨日，南望殷雷時。", "彤管今猶美，歸荑不及貽。"]'),
('7e662211-ef63-4035-b938-1a9d1e6ea37f','李參政夫人張氏挽詩  其二','魏了翁','宋','宋诗','song-poetry','','[]','銜命龍荒日，危機呼吸閒。',48,'全唐诗/poet.song.191000.json','["銜命龍荒日，危機呼吸閒。", "內言知勉正，時事迄多難。", "誤國頭顱去，和戎使節還。", "至今爲厲梗，撫事不勝潸。"]'),
('71530e8c-5bf6-40ed-9810-757de7a314d3','王寶謨挽詩  其一','魏了翁','宋','宋诗','song-poetry','','[]','寧懷會稽綬，不遺帝城書。',48,'全唐诗/poet.song.191000.json','["寧懷會稽綬，不遺帝城書。", "仕止四千石，年開八秩初。", "傾囷除旱魃，防岸免民魚。", "欲識恩田廣，銜哀到小胥。"]'),
('b5abf917-a134-4aab-a302-c94315324ffb','王寶謨挽詩  其二','魏了翁','宋','宋诗','song-poetry','','[]','瀘江鮫夜泣，柳廟鶴秋飛。',48,'全唐诗/poet.song.191000.json','["瀘江鮫夜泣，柳廟鶴秋飛。", "零露傷蘭穎，凄風撼王徽。", "焄蒿恍兮惚，精爽是邪非。", "豈必存亡問，吾知全以歸。"]'),
('946ef316-996d-4aea-9eb0-079528d0ff2d','王寶謨挽詩  其三','魏了翁','宋','宋诗','song-poetry','','[]','昔我仕龜城，猶能友寧馨。',48,'全唐诗/poet.song.191000.json','["昔我仕龜城，猶能友寧馨。", "記曾𣂏別酒，俄遽隔泉扃。", "頃刻成三世，凄凉隔九齡。", "魂兮誰與作，吾友許公銘。"]'),
('650276ff-2a35-482a-806d-56ade79dbc0e','郭宣教挽詩','魏了翁','宋','宋诗','song-poetry','','[]','趨義古君子，辭榮真丈夫。',48,'全唐诗/poet.song.191000.json','["趨義古君子，辭榮真丈夫。", "里門車下澤，子舍騎傳呼。", "霜柏寒逾勁，庭荆老不枯。", "典刑今已矣，宰木嘆羣烏。"]'),
('5ae39bc8-bd35-4eed-abd1-a553da448604','蟠鼇孫通直挽詩','魏了翁','宋','宋诗','song-poetry','','[]','趨義古君子，辭榮真丈夫。',48,'全唐诗/poet.song.191000.json','["趨義古君子，辭榮真丈夫。", "澤車款段馬，古錦小奚奴。", "老樹檠蒼幹，脩庭擁碧梧。", "發潛無巨筆，斜月照龜趺。"]'),
('f64a4c14-1b3a-45b5-a783-8f375e055f4d','何府君挽詩  其一','魏了翁','宋','宋诗','song-poetry','','[]','林泉間富貴，縑素老功夫。',48,'全唐诗/poet.song.191000.json','["林泉間富貴，縑素老功夫。", "古樹檠蒼幹，脩庭擁碧梧。", "只安車下澤，不侈騎傳呼。", "軋軋成都道，還家日未晡。"]'),
('6d01a757-37df-40d0-998d-afb6bf50db61','何府君挽詩  其二','魏了翁','宋','宋诗','song-poetry','','[]','橐裝隨寶劍，將水過荆州。',48,'全唐诗/poet.song.191000.json','["橐裝隨寶劍，將水過荆州。", "世事雲翻手，客程風打頭。", "空回剡溪棹，莫挽海山舟。", "欲報何嗟及，堂堂閟一丘。"]'),
('6507f3dc-5956-4f11-a694-ce22a471dccc','袁參政挽詩  其一','魏了翁','宋','宋诗','song-poetry','','[]','奕奕萬夫望，才名四十霜。',48,'全唐诗/poet.song.191000.json','["奕奕萬夫望，才名四十霜。", "重來陪講幄，三入位文昌。", "地闢南廳峻，磚重首折行。", "脩途日未旰，弭節復相羊。"]'),
('4d013146-3fc5-4966-ad2b-cd2d238e3e0d','袁參政挽詩  其二','魏了翁','宋','宋诗','song-poetry','','[]','耆舊晨星似，公胡不憗留。',48,'全唐诗/poet.song.191000.json','["耆舊晨星似，公胡不憗留。", "竟成青塢去，莫返赤松遊。", "時事方欹枕，天年不到頭。", "獨餘經在笥，衮衮付公侯。"]'),
('d8a90df7-025c-4f71-b3a9-54179d2e35cb','袁參政挽詩  其三','魏了翁','宋','宋诗','song-poetry','','[]','生世恨不蚤，庚申始識公。',48,'全唐诗/poet.song.191000.json','["生世恨不蚤，庚申始識公。", "象衣垂綷䌨，長珮奏璁瓏。", "幸甚蠅依驥，居然燕背鴻。", "靈輀送無路，淚灑霅溪風。"]'),
('3141922b-7b4a-451f-80e0-e0ede6c044e3','樂府君挽詩  其一','魏了翁','宋','宋诗','song-poetry','','[]','縑緗迂活計，屋壁老功夫。',48,'全唐诗/poet.song.191000.json','["縑緗迂活計，屋壁老功夫。", "月暗烏聲迥，霜寒鴈影孤。", "江靈知孝子，天賦厚耆儒。", "賸馥多沾丐，于今道未臞。"]'),
('a62d1e48-ebba-4a0e-b300-a3eaef2cba15','樂府君挽詩  其二','魏了翁','宋','宋诗','song-poetry','','[]','大雅云亡久，流風尚典刑。',48,'全唐诗/poet.song.191000.json','["大雅云亡久，流風尚典刑。", "賦登司馬室，詩授伯魚庭。", "不及瞻郎罷，猶能識寧馨。", "蕪辭書琬琰，敢齒蔡邕銘。"]'),
('31f320c6-0837-4fa3-993a-70cc38d7b3cf','趙廣安挽詩  其一','魏了翁','宋','宋诗','song-poetry','','[]','蚤志周程學，期闚孔孟心。',48,'全唐诗/poet.song.191000.json','["蚤志周程學，期闚孔孟心。", "人知行馬貴，我愛隙駒陰。", "秋樹檠蒼榦，霜空聳翠岑。", "一生迂事業，造物作知音。"]'),
('46e75b26-9acc-48cc-8c78-281c7f2aa607','趙廣安挽詩  其二','魏了翁','宋','宋诗','song-poetry','','[]','星隕南昌日，梟鳴蜀道時。',48,'全唐诗/poet.song.191000.json','["星隕南昌日，梟鳴蜀道時。", "孝誠移地軸，忠淚灑天涯。", "盡己皇它恤，求仁不復疑。", "衛公精爽在，足尉九原思。"]'),
('79177f6c-251b-4bea-b462-46a7c5e75cbc','趙廣安挽詩  其三','魏了翁','宋','宋诗','song-poetry','','[]','珪組曾分寄，經綸未究才。',48,'全唐诗/poet.song.191000.json','["珪組曾分寄，經綸未究才。", "冥心求己事，真氣養玄胎。", "月遽中河落，蘭先白露摧。", "若人嗟不淑，天意謂何哉。"]'),
('403534b8-2027-4ffa-ac80-1ac9d50e5d7f','譙修職挽詩','魏了翁','宋','宋诗','song-poetry','','[]','風高鴻影隻，秋迥鶚飛雙。',48,'全唐诗/poet.song.191000.json','["風高鴻影隻，秋迥鶚飛雙。", "桐帽人耆耈，綸封澤駿厖。", "歐書曾肆力，古調罕同腔。", "且幸碑銘識，無從親扣撞。"]'),
('989ea2fb-c7a9-4bbf-b764-ec3f01518912','韓少謨挽詩  其一','魏了翁','宋','宋诗','song-poetry','','[]','早年豪氣蓋區中，晚歲頹然一病翁。',32,'全唐诗/poet.song.191000.json','["早年豪氣蓋區中，晚歲頹然一病翁。", "負許才華竟何事，有皇上帝豈夢夢。"]'),
('44e5f5d5-57bc-4d79-a9ff-1c95eec139c8','韓少謨挽詩  其二','魏了翁','宋','宋诗','song-poetry','','[]','據鞍新息困壺頭，款段何如弟少游。',32,'全唐诗/poet.song.191000.json','["據鞍新息困壺頭，款段何如弟少游。", "馬革裹屍吾願足，不然肯向死前休。"]'),
('41c104be-aadc-4f55-8fbd-413fe8b0fa76','韓少謨挽詩  其三','魏了翁','宋','宋诗','song-poetry','','[]','鏡裏孤鸞背影飛，庭前玉樹向人稀。',32,'全唐诗/poet.song.191000.json','["鏡裏孤鸞背影飛，庭前玉樹向人稀。", "尚思別我成都去，忍聽虞歌薤露歸。"]'),
('7a61cd08-0940-4a04-aeaf-3fba077f1428','郭孺人挽詩','魏了翁','宋','宋诗','song-poetry','','[]','一性根原匪自今，厥生異甚理難尋。',64,'全唐诗/poet.song.191000.json','["一性根原匪自今，厥生異甚理難尋。", "因思出腹恩難稱，不恤傷膚念極深。", "雷殷饑腸旋歛蟄，春溫好語解移陰。", "華堂命服蕃孫子，天報還渠一片心。"]'),
('79f57669-9404-4f1b-bec5-d7191a5ee0be','陳隠君挽詩','魏了翁','宋','宋诗','song-poetry','','[]','新息亡人過，關西畏己知。',48,'全唐诗/poet.song.191000.json','["新息亡人過，關西畏己知。", "袖無漫滅刺，門鮮在亡辭。", "庭下荆三樹，墳前桂一枝。", "堂堂風木恨，掩淚讀邕碑。"]'),
('362b9e42-5721-4fda-8286-cd96db7bd07f','宇文瀘州挽詩  其一','魏了翁','宋','宋诗','song-poetry','','[]','篤信寧違俗，質行非近名。',48,'全唐诗/poet.song.191000.json','["篤信寧違俗，質行非近名。", "室無官燭淚，庖有甑塵生。", "吏不知廝卒，家毋役叟兵。", "茲猶餘事耳，徹底是真清。"]'),
('3fab3466-2880-4122-8903-fa816d739690','宇文瀘州挽詩  其二','魏了翁','宋','宋诗','song-poetry','','[]','風壑昂脩榦，霜空突翠峰。',48,'全唐诗/poet.song.191000.json','["風壑昂脩榦，霜空突翠峰。", "介然疑苦硬，行處獨從容。", "不忝南軒嗣，奚慚北學宗。", "巫陽招不復，曖曖日高舂。"]'),
('da036ebb-5f3a-4285-b2b3-f23f909c228b','陳總領挽詩  其一','魏了翁','宋','宋诗','song-poetry','','[]','士處宴安日，咸歆節誼名。',48,'全唐诗/poet.song.191000.json','["士處宴安日，咸歆節誼名。", "范陽徒爾怵，河朔莽然平。", "僅識淺利害，惡知真重輕。", "開禧忠義傳，吾得扈農卿。"]'),
('74f19f8d-0ba7-4f67-a8b7-6d36887088a6','陳總領挽詩  其二','魏了翁','宋','宋诗','song-poetry','','[]','舉頭西日遠，滿扇北塵汙。',48,'全唐诗/poet.song.191000.json','["舉頭西日遠，滿扇北塵汙。", "病已關心腹，吾何愛髮膚。", "變名逃越難，微服過商都。", "忽復天開霽，依然只故吾。"]'),
('f5e5a223-5ac4-480d-af13-fb80a2976c60','陳總領挽詩  其三','魏了翁','宋','宋诗','song-poetry','','[]','聞詔彈冠日，頹然禿鬢翁。',48,'全唐诗/poet.song.191000.json','["聞詔彈冠日，頹然禿鬢翁。", "當肩百鈞重，卷袂兩拳空。", "既上供軍最，方修給饟功。", "大鈞那可問，曾不憗留公。"]'),
('1247d743-4f43-44ab-a845-5f7141e24a67','潼川孫監稅挽詩','魏了翁','宋','宋诗','song-poetry','','[]','平地九折坂，通天一片心。',48,'全唐诗/poet.song.191000.json','["平地九折坂，通天一片心。", "寧甘門骯髒，不與俗浮沉。", "方授縱橫對，忍聞虞殯音。", "平都秋月白，精爽伴王陰。"]'),
('bb2d69c8-a717-40cf-b956-0a8fd4f78695','廖巴州挽詩','魏了翁','宋','宋诗','song-poetry','','[]','區區白屋一生酸，落落朱轓兩鬢班。',64,'全唐诗/poet.song.191000.json','["區區白屋一生酸，落落朱轓兩鬢班。", "篆水秋成蒼氏富，字江春暖玉人閒。", "二千石祿人常有，九秩年華天所慳。", "手種芝蘭香滿室，堂堂歸去住青山。"]'),
('5182ba32-cf55-4f8c-b31c-88f9b0a301a8','王處士挽詩','魏了翁','宋','宋诗','song-poetry','','[]','槿籬山下屋，桐帽水邊村。',48,'全唐诗/poet.song.191000.json','["槿籬山下屋，桐帽水邊村。", "遺子方寸地，傳家廿四言。", "芳蓀生夕秀，衰柳带秋昏。", "千古堂堂恨，青雲落淚痕。"]'),
('b2cc75c9-e847-425b-8d28-83346b581604','史制幹晦甫挽詩','魏了翁','宋','宋诗','song-poetry','','[]','菑川元自屬公孫，竟策詞場第一勛。',64,'全唐诗/poet.song.191000.json','["菑川元自屬公孫，竟策詞場第一勛。", "理有是非寧撓奪，官無大小只憂勤。", "紛紛白地皆灘瀨，豁豁青天亡片雲。", "滿腹詩書竟何用，泉臺曖曖日西曛。"]'),
('0edd3640-d505-4fca-872e-b4f7d69026a4','崇慶通判楊君挽詩','魏了翁','宋','宋诗','song-poetry','','[]','長珮高冠集翠裾，華途落落僅題輿。',64,'全唐诗/poet.song.191000.json','["長珮高冠集翠裾，華途落落僅題輿。", "官無小大皆行己，理有是非寧問渠。", "賦似長楊猶悔作，材如雄劍獨藏餘。", "方相掩淚催歸去，遺稿空存子政書。"]'),
('c2e78bbb-1c69-42a3-98e4-84a22549a43f','羅承事挽詩','魏了翁','宋','宋诗','song-poetry','','[]','人爲浮名若挂鈎，夫君知命獨休休。',64,'全唐诗/poet.song.191000.json','["人爲浮名若挂鈎，夫君知命獨休休。", "寒烏落日風林晚，老鴈長雲夜壑秋。", "寶劍裝留松影裏，黄金籝在架籤頭。", "便隨丹旐堂堂去，宰木號寒起伏牛。"]'),
('4b8aab46-8db5-4a4a-828b-7c5b10695e42','張隆州挽詩','魏了翁','宋','宋诗','song-poetry','','[]','行馬門闌宰胄巍，高冠長珮獨委蛇。',64,'全唐诗/poet.song.191000.json','["行馬門闌宰胄巍，高冠長珮獨委蛇。", "紫微自有申公學，太史還從從祖知。", "靜嘿無非蒙力處，功夫全在不欺時。", "故家遺俗寥寥甚，忍聽虞歌薤露悲。"]'),
('194714ea-ce61-4031-b283-99b37dd21797','計處士挽詩','魏了翁','宋','宋诗','song-poetry','','[]','我之外王父，早歲識殷州。',45,'全唐诗/poet.song.191000.json','["我之外王父，早歲識殷州。", "落落雙蓬鬢，蕭蕭一天時四不出。", "人事百無憂，事業雖亡試，全歸閟一丘。"]'),
('bed20def-1b85-4630-add5-ea0df367395b','致政宋君挽詩','魏了翁','宋','宋诗','song-poetry','','[]','窗寒研冷一生酸，坎止流行百念寬。',64,'全唐诗/poet.song.191000.json','["窗寒研冷一生酸，坎止流行百念寬。", "劍騎已荒江北草，簡編歸伴室中蘭。", "孰癡孰覺從渠看，真是真非只我觀。", "掩淚方相人已矣，廣平遺錄僅留殘。"]'),
('adac67dc-8ea3-42b2-8ad4-bc0ec44e12b8','楊隆慶挽詩','魏了翁','宋','宋诗','song-poetry','','[]','夜雨撼雝渠，春風載畢逋。',48,'全唐诗/poet.song.191000.json','["夜雨撼雝渠，春風載畢逋。", "畏途摇短夢，壯志束長湖。", "如此奇男子，終於朝大夫。", "鮮原千字誄，頼有少公蘇。"]'),
('b9ec61c5-deb1-4109-89eb-51d98994eea7','孫夫人挽詩','魏了翁','宋','宋诗','song-poetry','','[]','莊重知爲女，寬和解相夫。',48,'全唐诗/poet.song.191000.json','["莊重知爲女，寬和解相夫。", "母慈均衆子，婦道盡皇姑。", "春日鳴摶黍，秋風撼畢逋。", "尚遲彤管筆，宿草卧龜跗。"]'),
('f3732a74-6829-4b9b-9f96-46bf6b7256e2','程節推挽詩','魏了翁','宋','宋诗','song-poetry','','[]','入官當是學優時，政學尤知念昨非。',64,'全唐诗/poet.song.191000.json','["入官當是學優時，政學尤知念昨非。", "鬴實剖爭真識變，寶刀佩信解知幾。", "人謀是處雖同好，天理當然識者希。", "易簀遺言無一愧，死能如此庶全歸。"]'),
('09d20e5f-26d2-43f2-9768-77d4f4cfb6ff','從事郎致仕史挽詩','魏了翁','宋','宋诗','song-poetry','','[]','人爲浮名若掛鉤，夫君知命獨休休。',64,'全唐诗/poet.song.191000.json','["人爲浮名若掛鉤，夫君知命獨休休。", "東都門外蚤辭祿，西峴山前不入州。", "告第書歸泉壤底，滿籝金在架籤頭。", "當年勇退稱三老，此老胡寧不憗留。"]'),
('edfd5219-949d-485b-ba6e-2e40731f644b','雅州教授杜君挽詩','魏了翁','宋','宋诗','song-poetry','','[]','衣冠不但數城南，百世詩書味孔甘。',64,'全唐诗/poet.song.191000.json','["衣冠不但數城南，百世詩書味孔甘。", "夜半辭金知畏四，璞中有玉刖寧三。", "宦情本與秋俱薄，旅夢每驚春未酣。", "已矣參軍誰喜慍，一陂綠水鎮涵涵。"]'),
('bd0f84e5-bd9c-428f-a8b7-b056ae2f9844','成都教授史君挽詩','魏了翁','宋','宋诗','song-poetry','','[]','槁乾迂事業，講授老功夫。',48,'全唐诗/poet.song.191000.json','["槁乾迂事業，講授老功夫。", "日暮烏聲急，山空鶴影孤。", "高譚霜皎潔，及物雨昭蘇。", "已矣公何憾，于今道未臞。"]'),
('8319e4b8-449e-4c8c-945a-00574ad33bdd','楊夫人挽詩','魏了翁','宋','宋诗','song-poetry','','[]','行應珩璜女子師，薦修蘋藻大夫妻。',64,'全唐诗/poet.song.191000.json','["行應珩璜女子師，薦修蘋藻大夫妻。", "禮門總是行持地，宦海元非愛欲泥。", "翬翟相傳猶白鳳，鵷雛可伏勝黄雞。", "柳州念妹嗟何及，令德章章銀筆題。"]'),
('114e0adf-2bad-4ab7-80de-9c5382285afe','楊修撰挽詩  其一','魏了翁','宋','宋诗','song-poetry','','[]','早辭天子詔，晚挂大夫車。',48,'全唐诗/poet.song.191000.json','["早辭天子詔，晚挂大夫車。", "文雅三朝舊，風流二祖餘。", "眼前甲乙石，胸次丙丁書。", "自古誰無死，前休得似渠。"]'),
('0a128830-b611-4b7d-9c6a-4a1d2995d0bc','楊修撰挽詩  其二','魏了翁','宋','宋诗','song-poetry','','[]','東都方枕奠，方鎮尚根盤。',48,'全唐诗/poet.song.191000.json','["東都方枕奠，方鎮尚根盤。", "不得裴中立，誰承田季安。", "威稜行閫外，聲績在朝端。", "猶使江陽隸，聞風亦膽寒。"]'),
('9168968e-6f4c-4e7f-8d0e-171116295aad','楊修撰挽詩  其三','魏了翁','宋','宋诗','song-poetry','','[]','玉樹擎雙榦，靈椿老一株。',48,'全唐诗/poet.song.191000.json','["玉樹擎雙榦，靈椿老一株。", "林泉閒富貴，屋漏靜功夫。", "靖節自爲傳，耆英還有圖。", "碑材徒鎮石，此墓不須諛。"]'),
('4a465dc8-b738-46c5-ae12-8f0551927b82','宇文樞密挽詩  其一','魏了翁','宋','宋诗','song-poetry','','[]','人物眇然甚，天胡不憗公。',48,'全唐诗/poet.song.191000.json','["人物眇然甚，天胡不憗公。", "北風鳴槭槭，西火亂蓬蓬。", "襄鄂誰專閫，江淮孰總戎。", "是應當饋嘆，曩日鎮江功。"]'),
('e246a6ef-591c-462b-a090-21dd1dab4ad3','宇文樞密挽詩  其二','魏了翁','宋','宋诗','song-poetry','','[]','夷考公言行，真成肅愍孫。',48,'全唐诗/poet.song.191000.json','["夷考公言行，真成肅愍孫。", "星樞繩懿武，月殿媲隆恩。", "契闊成三世，凄凉隔九原。", "壯夫襟上淚，併爲兩師垣。"]'),
('9bfe6ffb-1ab4-4c20-a687-0883a87dfe54','唐昌文挽詩','魏了翁','宋','宋诗','song-poetry','','[]','重葩殗葉露華濃，不忝家聲得似公。',64,'全唐诗/poet.song.191000.json','["重葩殗葉露華濃，不忝家聲得似公。", "休息生靈牙頰裏，轉移事變笑譚中。", "却將仕宦四千石，換取寬閒五百弓。", "歲路今歸仙壽里，春來原上紙錢風。"]'),
('0ecb180c-47d3-4858-8612-fa97b15e3518','通直郎史君挽詩','魏了翁','宋','宋诗','song-poetry','','[]','亹亹南陔意，孜孜北學宗。',48,'全唐诗/poet.song.191000.json','["亹亹南陔意，孜孜北學宗。", "片言銷巧詆，三語劇崇墉。", "正喜雲隨步，俄驚日下舂。", "樓前半輪月，依舊挂長松。"]'),
('73940f3b-2579-4f08-8adb-5aff4a05c924','劉少監挽詩  其一','魏了翁','宋','宋诗','song-poetry','','[]','端重嗤浮俗，深沈燭事幾。',48,'全唐诗/poet.song.191000.json','["端重嗤浮俗，深沈燭事幾。", "上天陪將相，宥地贊樞機。", "辰告言猶在，朝回事已非。", "空貽郎罷嘆，不見子行歸。"]'),
('f9d2c5f4-cdbe-42fa-b909-fc67b08ecb09','劉少監挽詩  其二','魏了翁','宋','宋诗','song-poetry','','[]','天子龍飛日，東征與子同。',48,'全唐诗/poet.song.191000.json','["天子龍飛日，東征與子同。", "俄將滿舡月，換却打頭風。", "志尚觀其始，規模識所終。", "人才眇然甚，胡不憗遺公。"]'),
('3136b29c-f4f7-4968-9faf-0b21e727a356','游監丞挽詩  其一','魏了翁','宋','宋诗','song-poetry','','["\u8861\u5c71"]','論激回天力，身開夾日勛。',48,'全唐诗/poet.song.191000.json','["論激回天力，身開夾日勛。", "危言起平勃，姦膽落伾文。", "淚灑衡山月，神凄蜀嶺雲。", "若微劉柱史，千古閟清芬。"]'),
('58692379-9562-4f40-9dbf-2303ae7c0677','游監丞挽詩  其二','魏了翁','宋','宋诗','song-poetry','','[]','冰至人猶玩，波頹力不支。',48,'全唐诗/poet.song.191000.json','["冰至人猶玩，波頹力不支。", "摇摇路旁梗，炯炯日中葵。", "學道長身健，憂時兩鬢絲。", "竟摇天老眼，畀以寧馨兒。"]'),
('4b5d9e9a-cda0-43e8-8353-2cf5e9574d88','張運判之母呂宜人挽詩  其一','魏了翁','宋','宋诗','song-poetry','','[]','昔在傷皇辟，子行猶不歸。',48,'全唐诗/poet.song.191000.json','["昔在傷皇辟，子行猶不歸。", "嫠居言有則，喪事禮無違。", "軻母三遷教，萊兒七十衣。", "至今霜月夜，松竹带芳徽。"]'),
('2b3dfa5c-1c16-462d-b9b8-dedd44b6644d','張運判之母呂宜人挽詩  其二','魏了翁','宋','宋诗','song-poetry','','[]','錦鄉閒日月，象服儼山河。',48,'全唐诗/poet.song.191000.json','["錦鄉閒日月，象服儼山河。", "富貴吾無羨，平反爾幾何。", "相依在歲晚，不競得天多。", "欲報無終極，悲風振蓼莪。"]'),
('6795f4c3-b491-4c8c-b097-984a0b226a2f','高承事挽詩','魏了翁','宋','宋诗','song-poetry','','[]','長身拘矮屋，雅志壓華顛。',48,'全唐诗/poet.song.191000.json','["長身拘矮屋，雅志壓華顛。", "已矣寧非命，猗其尚有傳。", "飽餐廣文飯，不擊陸侯鮮。", "惜也文明縣，耆英欠此賢。"]'),
('5affca29-5170-430f-b6a0-990e682e00f0','家涪陵挽詩','魏了翁','宋','宋诗','song-poetry','','[]','聞風唐御史，得意古周官。',48,'全唐诗/poet.song.191000.json','["聞風唐御史，得意古周官。", "治郡當如霸，閒居略似潘。", "慈庭春後寂，書幌夜深寒。", "漫有一區宅，傳家地自寬。"]'),
('e34c498e-49d8-49b8-8dd5-ba207e869762','羅監廟挽詩','魏了翁','宋','宋诗','song-poetry','','[]','春風擢擢秀階庭，歲晚悠然物外身。',64,'全唐诗/poet.song.191000.json','["春風擢擢秀階庭，歲晚悠然物外身。", "不把簪纓傷野趣，肯迂劍騎拂天真。", "種成墳上一枝桂，空老堂前百歲椿。", "鄉里善人今已矣，龍門送客一酸辛。"]'),
('7466dfb9-7634-4084-8ab1-ebe18b2231f7','馬少卿挽詩','魏了翁','宋','宋诗','song-poetry','','[]','重葩殗葉露華濃，不忝家聲得似公。',64,'全唐诗/poet.song.191000.json','["重葩殗葉露華濃，不忝家聲得似公。", "言行端和今世楷，貌心醇質古人風。", "直將趨走二三節，換取寬閒五百弓。", "如此名卿緣手盡，同時更送竹溪翁。"]'),
('73dcf3b5-af5a-4932-bc00-8769e32a4a3a','費參政挽詩  其一','魏了翁','宋','宋诗','song-poetry','','[]','鼎鼐誰無宅，人間晝錦難。',48,'全唐诗/poet.song.191000.json','["鼎鼐誰無宅，人間晝錦難。", "秋風三徑老，夜雨兩峰寒。", "有志時看劍，無心晚據鞍。", "行藏付千載，反覆要人看。"]'),
('87089c52-e1ec-43cc-a604-dd8b1c38e8f9','費參政挽詩  其二','魏了翁','宋','宋诗','song-poetry','','[]','黨論危疑日，幾微細補縫。',48,'全唐诗/poet.song.191000.json','["黨論危疑日，幾微細補縫。", "平舟行浪穩，暖氣拆冰融。", "風雨千閒屋，酸鹹一鼎饔。", "人才關國本，誰念昔培封。"]'),
('8c4163a0-0182-42a8-aef7-73cc3f19eb21','費參政挽詩  其三','魏了翁','宋','宋诗','song-poetry','','[]','曲突有危慮，扣閽無隠情。',48,'全唐诗/poet.song.191000.json','["曲突有危慮，扣閽無隠情。", "揮戈羣啄害，斷鞅一精誠。", "斬錯終何補，征遼禍已成。", "惟公獨知我，勸主不言兵。"]'),
('6d5e0716-d8e1-4e71-b53e-5cee848edf4d','虞萬州妻趙安人挽詩  其一','魏了翁','宋','宋诗','song-poetry','','[]','婦言加婦德，公子嫁公孫。',48,'全唐诗/poet.song.191000.json','["婦言加婦德，公子嫁公孫。", "澹泊於心慊，紛華入耳煩。", "晉秦稱匹國，韓姞爛盈門。", "乃與其夫子，十年江上村。"]'),
('3d406347-852c-47c3-9ffd-03d221599884','虞萬州妻趙安人挽詩  其二','魏了翁','宋','宋诗','song-poetry','','[]','江上有何樂，蕭然吾亦忘。',48,'全唐诗/poet.song.191000.json','["江上有何樂，蕭然吾亦忘。", "午眠春寂歷，晚步水滄浪。", "倦去推門入，忺來索酒嘗。", "清風那復見，江闊莫雲長。"]'),
('52ed0f5b-ac32-46a4-a55b-75a166fb03db','樊仲恂母太碩人李氏挽詩','魏了翁','宋','宋诗','song-poetry','','[]','梁君遯世偕妻孟，崔母祈天爲婦唐。',64,'全唐诗/poet.song.191000.json','["梁君遯世偕妻孟，崔母祈天爲婦唐。", "身是六朝人物舊，眼看三世子孫昌。", "人知翕翕味方雋，誰識耽耽意最長。", "猶恨年齡不滿百，僅成三萬五千場。"]'),
('e4df07fa-3f96-45e0-8609-36ee367c01a3','范聖問之母孺人史氏挽詩','魏了翁','宋','宋诗','song-poetry','','[]','是中無一物，快活不容言。',48,'全唐诗/poet.song.191000.json','["是中無一物，快活不容言。", "以此行州里，留之遺子孫。", "寒泉鴻鴈影，落日鳳皇原。", "三復幽堂誌，夫人不死存。"]'),
('8596a801-ae35-40bf-abdd-d32b0fc5bb56','江州司馬安君挽詩','魏了翁','宋','宋诗','song-poetry','','[]','當年風雨脊令原，共挈兇顱奏凱旋。',64,'全唐诗/poet.song.191000.json','["當年風雨脊令原，共挈兇顱奏凱旋。", "弄破峨眉山月影，慵移湓浦荻花舡。", "浮雲都似夢中覺，妙句猶於身後傳。", "腸斷美人湘水隔，憑鴻寄淚識新阡。"]'),
('210b0001-c93f-4b09-8367-f5cbab819524','李懷安挽詩','魏了翁','宋','宋诗','song-poetry','','[]','鄉邑頼蓍龜，天胡不憗遺。',48,'全唐诗/poet.song.191000.json','["鄉邑頼蓍龜，天胡不憗遺。", "與人交樂易，處世事平夷。", "甚矣古常者，傷哉今已而。", "撫時懷牧守，忍淚讀劉碑。"]'),
('0b71fe9c-85fd-43a4-a83c-bcc8aa965c9a','張隠君挽詩','魏了翁','宋','宋诗','song-poetry','','[]','觸事無非學，非儒果誤身。',48,'全唐诗/poet.song.191000.json','["觸事無非學，非儒果誤身。", "體中識天地，筆底定君臣。", "安樂堂前月，希夷枕上春。", "是應家有子，不止活千人。"]'),
('5a2529d4-1ad2-42a1-92b5-c3afb475d83d','臨邛張夫人之葬某既先事爲之識竁今日月有時而某儼在衰絰義不獲往弔又不能爲文以侑虞殯命兒沖代賦','魏了翁','宋','宋诗','song-poetry','','[]','殗葉重葩兩大門，只憑道義世昏姻。',64,'全唐诗/poet.song.191000.json','["殗葉重葩兩大門，只憑道義世昏姻。", "養成氣質槐爲芷，發見儀容竹有筠。", "自是子能爲國士，何須女必嫁官人。", "世衰俗薄昏成市，三復碑銘憤滿巾。"]'),
('3560f939-bea4-4ad4-bb26-f15cd319a624','黄夫人之葬某新有喪不得爲文以侑虞殯命兒沖代賦','魏了翁','宋','宋诗','song-poetry','','[]','夫人心事與天謀，錢鎛功夫歲晚收。',64,'全唐诗/poet.song.191000.json','["夫人心事與天謀，錢鎛功夫歲晚收。", "秸鞠聲中春滿羽，畢逋枝裏月橫秋。", "將雛欲上空回首，食蔗才甘不到頭。", "况是我翁方念母，兩鄉風雨一般愁。"]'),
('ada4dd28-04a1-4bca-9bab-ebae5fb8a07f','成都杜五一府君之葬某新有喪不得爲文以侑虞殯命兒沖代賦','魏了翁','宋','宋诗','song-poetry','','[]','尚記維川死，今年又哭公。',48,'全唐诗/poet.song.191000.json','["尚記維川死，今年又哭公。", "琴聲辭夜月，書葉卧春風。", "兒女數行淚，親朋十九空。", "我翁方念母，忍淚課兒沖。"]'),
('39ce38bb-db05-4170-b76e-92d7de615ada','吳府君挽詩','魏了翁','宋','宋诗','song-poetry','','[]','人誇駡賊與尊君，我看閑家與事兄。',64,'全唐诗/poet.song.191000.json','["人誇駡賊與尊君，我看閑家與事兄。", "更識爲人謀質實，便知處己事分明。", "夜窗殘夢鸞離照，風壑哀號烏失聲。", "從此長寧鄉下路，兩山明月一般情。"]'),
('46e843f1-b675-40df-a490-6fd2f5c4214c','史宜人挽詩','魏了翁','宋','宋诗','song-poetry','','[]','勉夫惟有義，爲舅可無生。',48,'全唐诗/poet.song.191000.json','["勉夫惟有義，爲舅可無生。", "不是多聞識，那知真重輕。", "子從觀處化，身在吉中行。", "况復無餘憾，堂封勒蔡銘。"]'),
('ce54f97c-cabd-4841-85b8-ffec2ceb084a','家承事挽詩','魏了翁','宋','宋诗','song-poetry','','[]','崑火玉孚尹，喬松冬夏青。',48,'全唐诗/poet.song.191000.json','["崑火玉孚尹，喬松冬夏青。", "塵沙吹海立，風月半窗醒。", "適意問芒屩，無心待屏星。", "風流那復見，食報在寧馨。"]'),
('a2126f4c-c7e6-447a-a8fd-fc22039bfab4','史致政挽詩','魏了翁','宋','宋诗','song-poetry','','[]','口道先生易，躬行君子難。',48,'全唐诗/poet.song.191000.json','["口道先生易，躬行君子難。", "浮榮殘夢覺，活計一般酸。", "日晚烏聲急，風高鴈影寒。", "行藏付千載，反覆要人看。"]'),
('2f94eec0-6aa0-4565-9169-046efaeb3a9b','王宜人挽詩','魏了翁','宋','宋诗','song-poetry','','[]','門譜誰誇郡姓强，是家元自孝廉郎。',64,'全唐诗/poet.song.191000.json','["門譜誰誇郡姓强，是家元自孝廉郎。", "長來但識詩書貴，老去不知簪珥香。", "吏部生涯缾裏粟，夫人宗事橐中裝。", "他年點檢挈菴稿，寧愧歐公誌薛楊。"]'),
('c30f4abc-3863-494c-beb8-7bdda0bfc5cd','李德邁挽詩','魏了翁','宋','宋诗','song-poetry','','[]','鳴嚶出谷邈難親，斷鴈辭行不可羣。',64,'全唐诗/poet.song.191000.json','["鳴嚶出谷邈難親，斷鴈辭行不可羣。", "論事期期箝在口，逢人頟頟齒穿齦。", "乾坤許闊猶有礙，風雨滿前如不聞。", "腸斷天津邵夫子，東籬掩淚立孤雲。"]'),
('73e53680-35a6-48b1-9d7b-ed80aa724cca','知崇慶府致政何君挽詩  其一','魏了翁','宋','宋诗','song-poetry','','[]','外監名父子，元方難弟兄。',48,'全唐诗/poet.song.191000.json','["外監名父子，元方難弟兄。", "鶴空黄壤夢，鴈續紫霄聲。", "山遠玉無脛，春多天有情。", "至今溪上月，猶傍碧梧明。"]'),
('a17b18d5-62e9-43d4-b42a-c28eaebbb493','知崇慶府致政何君挽詩  其二','魏了翁','宋','宋诗','song-poetry','','[]','不把英雄彀，移爲仕進媒。',48,'全唐诗/poet.song.191000.json','["不把英雄彀，移爲仕進媒。", "邑獒群怪吠，竈婢亦驚猜。", "且效功成退，寧須興盡回。", "芸芸終有謝，贏得早歸來。"]'),
('8a2e50a9-f376-4ac1-a353-57c0a0ec7e4b','任重慶挽詩','魏了翁','宋','宋诗','song-poetry','','[]','諸任方衮衮，惜也大任君。',48,'全唐诗/poet.song.191000.json','["諸任方衮衮，惜也大任君。", "曲突人誰信，扣閽天不聞。", "膽隨豪滿幹，齒爲憤穿齦。", "莫挽泉臺恨，周簫咽澗雲。"]'),
('00e599c0-1c81-470b-a6e6-a5add4e486a6','前利路運判沖佑李君挽詩  其一','魏了翁','宋','宋诗','song-poetry','','[]','篤謹寧違俗，清淳不近名。',48,'全唐诗/poet.song.191000.json','["篤謹寧違俗，清淳不近名。", "幾多岐上泣，獨自吉中行。", "歲晚露沾草，山空霜滿荆。", "南溪後月夜，的的爲誰明。"]'),
('b9e2c6ea-4251-416d-84cf-9cf480d8329b','前利路運判沖佑李君挽詩  其二','魏了翁','宋','宋诗','song-poetry','','[]','從橐心知舊，樞庭肺腑親。',48,'全唐诗/poet.song.191000.json','["從橐心知舊，樞庭肺腑親。", "不從呼爾食，寧獨曳其輪。", "吳子傑魁士，黄公忠藎臣。", "所知非所厚，亦足驗爲人。"]'),
('b6111298-2ea9-4a27-900a-ddceeec05c30','楊仲遠挽詩','魏了翁','宋','宋诗','song-poetry','','[]','屬我銘先竁，元符事益光。',48,'全唐诗/poet.song.191000.json','["屬我銘先竁，元符事益光。", "十年黄壤夢，再世短松崗。", "樓外焄蒿集，閣前名節香。", "吳鉤無處挂，芻束寄諸郎。"]'),
('a384b3b3-fed8-465d-af26-f7b0cacd239d','程隠君挽詩','魏了翁','宋','宋诗','song-poetry','','[]','歲凶缾粟罄，屋破褚衣單。',48,'全唐诗/poet.song.191000.json','["歲凶缾粟罄，屋破褚衣單。", "地寂鳥烏樂，天高鴻鴈寒。", "墳前晚生桂，露下草摧蘭。", "只把存耕處，令人反覆看。"]'),
('089e0d47-57d7-4cd7-9327-1d15ba7beec2','通直致政姚君挽詩','魏了翁','宋','宋诗','song-poetry','','[]','一生官偪仄，幾處獄平反。',48,'全唐诗/poet.song.191000.json','["一生官偪仄，幾處獄平反。", "夜雨滴歸思，凱風唳淚痕。", "竟令駒入夢，莫盡桂銷冤。", "點檢慈恩舊，秋空幾斷魂。"]'),
('ec00de69-f174-4268-afe5-cdf3193c66c4','樂隠君挽詩','魏了翁','宋','宋诗','song-poetry','','[]','人畸天則偶，俗隘我常優。',48,'全唐诗/poet.song.191000.json','["人畸天則偶，俗隘我常優。", "謾道蚿憐鼈，終成鵲避鳩。", "蹇馿花露曉，孤鴈稻雲秋。", "想見招魂曲，人人說少游。"]'),
('238c6674-4cac-462c-a159-af9a14c2d26c','許侍郎挽詩  其一','魏了翁','宋','宋诗','song-poetry','','[]','杏園春接袂，蓬省夜分燈。',48,'全唐诗/poet.song.191000.json','["杏園春接袂，蓬省夜分燈。", "權相不吾以，貴人惟子憎。", "雖云殊爵位，均不愧交朋。", "顧影追前事，悠然涕滿膺。"]'),
('03192803-f586-48a3-acd8-f7b86e93fc4f','許侍郎挽詩  其二','魏了翁','宋','宋诗','song-poetry','','[]','近事君知不，王心莫與寧。',48,'全唐诗/poet.song.191000.json','["近事君知不，王心莫與寧。", "融風薄台里，秋雨暗前星。", "鴻集稻粱少，虎嘷川谷腥。", "人才關世道，歛涕爲公銘。"]'),
('205f52b4-4bb7-4c5a-9688-a25ee9bc6e3d','峨眉主簿樂挽詩','魏了翁','宋','宋诗','song-poetry','','[]','尹心隨處驗，舜樂切身看。',48,'全唐诗/poet.song.191000.json','["尹心隨處驗，舜樂切身看。", "春味注胸臆，秋河懸筆端。", "胡爲鐵研弊，纔脫紵袍酸。", "天匪夢夢者，吾於由也觀。"]'),
('9622adee-d616-47c4-9b50-41338e469216','高公權之母郭氏挽詩','魏了翁','宋','宋诗','song-poetry','','[]','婦道始衷終，寧過三者從。',48,'全唐诗/poet.song.191000.json','["婦道始衷終，寧過三者從。", "髧髦維我特，蓬首爲誰容。", "但識同心處，寧拘異域封。", "壇前兩溪水，晝夜自溶溶。"]'),
('5b6a9a09-fa6d-4439-9e3c-f46e2fec9e32','楊處士挽詩','魏了翁','宋','宋诗','song-poetry','','[]','丁年已分與時違，便把書棚囑付兒。',64,'全唐诗/poet.song.191000.json','["丁年已分與時違，便把書棚囑付兒。", "峨嶺秋寒千古意，符谿春暖一筒詩。", "彩雲來往吾何與，草露消磨我自知。", "含笑黄泉應不恨，桂華猶有未開枝。"]'),
('9ad565da-e9c7-4efd-bfd8-6f703015d2f4','教授致政李君挽詩','魏了翁','宋','宋诗','song-poetry','','[]','冠蓋任雲浮，門前日夜流。',48,'全唐诗/poet.song.191000.json','["冠蓋任雲浮，門前日夜流。", "不爲盱豫悔，肯作浚恒羞。", "科第聯五葉，詩書閒一丘。", "芸芸終有謝，贏得早歸休。"]'),
('88714335-7c00-4d43-a348-49ba64aae2a9','魏撫幹挽詩','魏了翁','宋','宋诗','song-poetry','','[]','同姓又同升，知君莫我深。',48,'全唐诗/poet.song.191000.json','["同姓又同升，知君莫我深。", "磨人三寸鐵，行己四知金。", "雪柏擎蒼榦，霜鐘振曉音。", "若人今在否，撫事一沾襟。"]'),
('1a12977a-d602-4102-8dbb-61da5df8680b','韓聖問挽詩','魏了翁','宋','宋诗','song-poetry','','[]','蠟貌寧違俗，規行不競時。',48,'全唐诗/poet.song.191000.json','["蠟貌寧違俗，規行不競時。", "苦思頭沒膝，勤誦涕垂頤。", "州縣頻勸駕，藩方嘗俛眉。", "飄零竟何益，風雨脊令枝。"]'),
('7e4ac89a-20c8-4ee1-8120-b6f414e0a5b4','黎州安撫趙挽詩','魏了翁','宋','宋诗','song-poetry','','[]','不爲軟語混光塵，獨把剛腸敵世紛。',64,'全唐诗/poet.song.191000.json','["不爲軟語混光塵，獨把剛腸敵世紛。", "讀史功夫頭沒膝，疾時風論齒穿齦。", "慈烏反哺終違志，斷鴈辭行不作羣。", "猶有寧馨傳素業，爲求佳傳賁丘墳。"]'),
('2383aa0a-6763-4966-9737-6a7f7575f1af','知廣安軍勾侯挽詩','魏了翁','宋','宋诗','song-poetry','','[]','突兀雙楠樹，翹枝照戶青。',48,'全唐诗/poet.song.191000.json','["突兀雙楠樹，翹枝照戶青。", "春風吹湑湑，秋雨立亭亭。", "蟻夢迷符竹，牛涔兀屏篂。", "但令根本在，有茁媚階庭。"]'),
('9d5f4578-cd6d-4179-9f38-0a771c1ab810','知合州趙侯挽詩','魏了翁','宋','宋诗','song-poetry','','[]','悃愊古循吏，寬和鄉善人。',48,'全唐诗/poet.song.191000.json','["悃愊古循吏，寬和鄉善人。", "鸞宮六老會，月墅四時春。", "轉眼園松老，驚心宰木新。", "來遲傷杜牧，賓主總成塵。"]'),
('20d6f470-481d-4720-9a7e-42a1043a73dd','家夫人挽詩','魏了翁','宋','宋诗','song-poetry','','[]','江鄉推甲乙，家史自名門。',48,'全唐诗/poet.song.191000.json','["江鄉推甲乙，家史自名門。", "作配昔相友，流風今尚存。", "三珠方秀媚，雙劍忽飛騫。", "丹旐蓮峰路，悲雲落日翻。"]'),
('92240f61-7312-40d1-b4de-e367a406cf83','知敘州史侯挽詩','魏了翁','宋','宋诗','song-poetry','','[]','便乘龍歲去，吾黨果何觀。',48,'全唐诗/poet.song.191000.json','["便乘龍歲去，吾黨果何觀。", "春味注眉睫，秋河懸舌端。", "仁心隨處見，民事切身看。", "十載升堂夢，階庭茁紫蘭。"]'),
('e9f3990a-a67d-4d56-81c4-50d57a78f21b','齊安郡向夫人挽詩','魏了翁','宋','宋诗','song-poetry','','[]','祥符名相裔，元祐宰臣孫。',48,'全唐诗/poet.song.191000.json','["祥符名相裔，元祐宰臣孫。", "展也晉秦匹，爛其韓姞門。", "世紛冰似冷，壼範玉如溫。", "千古峨眉月，爭輝北客魂。"]'),
('ec8df1f1-95c7-4cdd-a119-f1b3fc820215','蔡推官','魏了翁','宋','宋诗','song-poetry','','[]','人生宇宙皆同氣，况此根心貫一機。',64,'全唐诗/poet.song.191000.json','["人生宇宙皆同氣，况此根心貫一機。", "安用有生銜父恤，只愁無德報春輝。", "桂芳春老傷何及，樹靜風號願竟違。", "更恨母慈臨訣日，嗟嗟季役未成歸。"]'),
('ab803370-607a-4247-8f51-d86fb7bad967','馮夫人挽詩','魏了翁','宋','宋诗','song-poetry','','[]','解道先天易，能哦擊壤詩。',48,'全唐诗/poet.song.191000.json','["解道先天易，能哦擊壤詩。", "只因居有習，毋謂女無儀。", "在姆師逡立，從夫婦得咨。", "暮年尤慰意，玉壻作門楣。"]'),
('e9985416-9d1c-49fe-9507-45c71e656c0c','費華文挽詩  其一','魏了翁','宋','宋诗','song-poetry','','[]','謹厚傳燕國，寬和似蜀公。',48,'全唐诗/poet.song.191000.json','["謹厚傳燕國，寬和似蜀公。", "材猷今世楷，論建古人風。", "閲世心猶壯，憂時鬢已翁。", "芸芸今有盡，歸去得全終。"]'),
('d7e9839a-ff14-403b-9920-92de4eb1cd31','費華文挽詩  其二','魏了翁','宋','宋诗','song-poetry','','[]','三鳳齊飛日，相期到白頭。',48,'全唐诗/poet.song.191000.json','["三鳳齊飛日，相期到白頭。", "一丘生處樂，萬事死前休。", "風急啼烏夜，霜零斷鴈秋。", "懷人竟何極，緘淚寄西州。"]'),
('2ce5932c-9ef6-4483-be07-03cc462dc1a9','張運判挽詩','魏了翁','宋','宋诗','song-poetry','','[]','悃愊漢循吏，咨詢周使臣。',48,'全唐诗/poet.song.191000.json','["悃愊漢循吏，咨詢周使臣。", "知心三坐主，報國兩門人。", "綵繡方趨戶，絲麻已在身。", "至今寒食路，孺慕鎮如新。"]'),
('defff652-2d01-4acb-9404-57b5880d86bb','李郎中挽詩  其一','魏了翁','宋','宋诗','song-poetry','','[]','太息金泉守，西歸空好音。',48,'全唐诗/poet.song.191000.json','["太息金泉守，西歸空好音。", "孳孳求友意，懇懇愛君心。", "謀道身多阨，憂時力不任。", "懷人今永已，爲世一霑襟。"]'),
('d3e9c252-6297-470d-aa03-c12900911e70','李郎中挽詩  其二','魏了翁','宋','宋诗','song-poetry','','[]','解道公行止，江東老父兄。',48,'全唐诗/poet.song.191000.json','["解道公行止，江東老父兄。", "羣州垂瘵死，膚使爲更生。", "民裕身逾瘠，時危命亦輕。", "潯陽江上月，猶傍諫書明。"]'),
('2d2f2340-9593-4864-babd-4887a28b6f16','武康主簿吳挽詩','魏了翁','宋','宋诗','song-poetry','','[]','羯末誇羣從，凝徽肖一之。',48,'全唐诗/poet.song.191000.json','["羯末誇羣從，凝徽肖一之。", "風花摇切夢，梅雪照詩脾。", "日短烏聲急，天寒鴈影悲。", "廣輪高隠地，千古一漣洏。"]'),
('303b5846-4b33-4be2-925a-8c35144d7d53','天台張氏兄弟挽詩','魏了翁','宋','宋诗','song-poetry','','[]','靜將物理驗良知，父母恩深報稱微。',64,'全唐诗/poet.song.191000.json','["靜將物理驗良知，父母恩深報稱微。", "羣動芸芸看夜息，萬生點點發春輝。", "錯居宇宙猶同氣，况此根心貫一機。", "理道亶然人莫究，是家兄弟庶全歸。"]'),
('298595c6-f034-44ee-8323-b20f8e195f16','度周卿之母蹇太宜人挽詩','魏了翁','宋','宋诗','song-poetry','','[]','八十三年雪檜身，直將簪珥當冠巾。',64,'全唐诗/poet.song.191000.json','["八十三年雪檜身，直將簪珥當冠巾。", "生兒須擬范孟博，論士亦知程伯醇。", "在約能令家有塾，居閒肯使食無賓。", "世間爲母皆如此，扶值三綱不乏人。"]'),
('8a9e77aa-97da-4856-aab4-ebca86e825a8','朱邵州挽詩','魏了翁','宋','宋诗','song-poetry','','[]','杏園猶記賞花同，忍看前旌照眼紅。',64,'全唐诗/poet.song.191000.json','["杏園猶記賞花同，忍看前旌照眼紅。", "民命一絲懸晷刻，仁心觸處作春風。", "棣華韡韡天倫厚，湑葉裳裳世澤隆。", "萬事紛紛緣手盡，只將孝友詔無窮。"]'),
('1f49f0b6-6db1-4537-bf81-5b6554f19eb4','袁侍郎挽詩  其一','魏了翁','宋','宋诗','song-poetry','','[]','學術趨平實，年來似寂寥。',48,'全唐诗/poet.song.191000.json','["學術趨平實，年來似寂寥。", "豈無先後覺，未在始終條。", "此老能深造，諸公獨後彫。", "平生寄心事，髣髴見魚朝。"]'),
('4021a124-bbf6-40f1-b250-786c68aac2c6','袁侍郎挽詩  其二','魏了翁','宋','宋诗','song-poetry','','[]','骯髒常三黜，脂韋或萬鍾。',48,'全唐诗/poet.song.191000.json','["骯髒常三黜，脂韋或萬鍾。", "芸芸終有謝，炯炯此何窮。", "雛穴皆鳴鳳，生涯僅老龍。", "輪囷憂世抱，撫事轉沖沖。"]'),
('30b6e828-574e-4f29-9dd0-669177d68dd6','恭挽寧宗皇帝  其一','魏了翁','宋','宋诗','song-poetry','','[]','內禪踰三甲，中興會百年。',48,'全唐诗/poet.song.191000.json','["內禪踰三甲，中興會百年。", "歸疆纔汶上，勒石未燕然。", "忽悵龍髯墮，旋瞻燕翼傳。", "遺民滿關洛，南望涕縈漣。"]'),
('0040349c-e112-4d24-b792-4693101f89a6','恭挽寧宗皇帝  其二','魏了翁','宋','宋诗','song-poetry','','[]','玉冊宗昭考，寧王德比純。',48,'全唐诗/poet.song.191000.json','["玉冊宗昭考，寧王德比純。", "宮庭天事業，廟室祖精神。", "遣奠俄廞馬，書言痛獲麟。", "人窮天亦慼，雨雪故連春。"]'),
('9fe8d331-f537-4a44-ae0e-e0abeea00f1f','吳府君挽詩','魏了翁','宋','宋诗','song-poetry','','[]','篤信寧違俗，徐行不競時。',48,'全唐诗/poet.song.191000.json','["篤信寧違俗，徐行不競時。", "與人交樂易，處世事平夷。", "甚矣古常者，傷哉今已而。", "龍山春夜月，長照鳳皇枝。"]'),
('40b22b89-f9d8-450a-8aa4-38b733306784','陳寺丞挽詩  其一','魏了翁','宋','宋诗','song-poetry','','[]','人物晨星似，如公正獻家。',48,'全唐诗/poet.song.191000.json','["人物晨星似，如公正獻家。", "皂囊真相業，黄卷舊生涯。", "胡不憗遺老，而興大耋嗟。", "天高那可問，淚眼爲麻查。"]'),
('7bcec6a6-c2d2-4e27-9c94-734e9b7d0c93','陳寺丞挽詩  其二','魏了翁','宋','宋诗','song-poetry','','[]','聖主搜賢詔，愚臣薦士書。',48,'全唐诗/poet.song.191000.json','["聖主搜賢詔，愚臣薦士書。", "高岡看治鳳，靈沼蟄潛魚。", "時數自信詘，帝心誰戚疏。", "臧倉徒擾擾，窮達不關渠。"]'),
('44fe2d6d-49d4-4a72-abce-5b44802df554','陳寺丞挽詩  其三','魏了翁','宋','宋诗','song-poetry','','[]','有子知乎否，蒼生命益危。',48,'全唐诗/poet.song.191000.json','["有子知乎否，蒼生命益危。", "共傷周赫赫，誰叫廟譆譆。", "隨處皆螗斧，何方不繭絲。", "斯人今已矣，撫事轉傷悲。"]'),
('a4107005-7b53-4028-b5c8-8cb50568d5ef','樊迪功挽詩','魏了翁','宋','宋诗','song-poetry','','[]','白鶴招人反舊廬，舊人落落曉星疏。',64,'全唐诗/poet.song.191000.json','["白鶴招人反舊廬，舊人落落曉星疏。", "正傷邢璧埋黄壤，又嘆燕椿非老株。", "不見登山靈運屐，空懸下澤少游車。", "死於平世君奚憾，鴻鴈嗸嗸未奠居。"]'),
('df4adf2c-13d2-48d8-8dd7-68b5f8c1acfd','敘州弟挽詩  其一','魏了翁','宋','宋诗','song-poetry','','[]','與女爲兄弟，前年五十年。',48,'全唐诗/poet.song.191000.json','["與女爲兄弟，前年五十年。", "並驅驂接革，偕立雁羞肩。", "此意春融洩，中年俗糾纏。", "每期身蚤退，白首對床眠。"]'),
('4f3d72fc-e6d6-4f0e-b860-2144a17cbb0c','敘州弟挽詩  其二','魏了翁','宋','宋诗','song-poetry','','[]','禍我天何酷，子歸自古誠。',48,'全唐诗/poet.song.191000.json','["禍我天何酷，子歸自古誠。", "女孥俄別父，宗直亦辭兄。", "家難已稠疊，寇氛方滿盈。", "分明天有眼，不照此時情。"]'),
('c046d41e-ab0e-438e-ab98-1e9cecadc26d','敘州弟挽詩  其三','魏了翁','宋','宋诗','song-poetry','','[]','人物寂寥甚，天心分付誰。',48,'全唐诗/poet.song.191000.json','["人物寂寥甚，天心分付誰。", "禦戎傷畜縮，講學病支離。", "吏橫民重足，時危命一絲。", "若人天亦靳，撫事轉傷悲。"]'),
('7676e41a-11bd-4ab4-bce2-b8b1061a3c24','楊子禮挽詩','魏了翁','宋','宋诗','song-poetry','','[]','事業古人謀，寒鐙耿夜篝。',48,'全唐诗/poet.song.191000.json','["事業古人謀，寒鐙耿夜篝。", "正青諸老眼，枉白一生頭。", "犖确秋難熟，崦嵫日易收。", "可憐鴻影斷，老淚滴監州。"]'),
('5556f605-eb8a-4671-b141-cc2a8b4115d6','文彭州挽詩','魏了翁','宋','宋诗','song-poetry','','[]','二仲嬋嫣起，清修自一家。',48,'全唐诗/poet.song.191000.json','["二仲嬋嫣起，清修自一家。", "踐塗中險阻，宰郡晚光華。", "氣燄奔金虜，威稜憺鐵耶。", "料應九峰下，朝露泣姚花。"]'),
('b041e642-4086-4506-af73-ffb36af6218b','趙德安挽詩','魏了翁','宋','宋诗','song-poetry','','[]','甲申露布告誅曦，丙戌巴臺已磔禧。',64,'全唐诗/poet.song.191000.json','["甲申露布告誅曦，丙戌巴臺已磔禧。", "或謂祿媭非漢患，誰知田李遺唐危。", "安州得禍聞人說，荆莫上功惟我知。", "三十三年舊寮友，朔風吹淚讀殘碑。"]'),
('16129f99-6356-49e4-84f1-d4f6b83a088f','楊叔介挽詩','魏了翁','宋','宋诗','song-poetry','','[]','尚記少年場，英英兀老蒼。',48,'全唐诗/poet.song.191000.json','["尚記少年場，英英兀老蒼。", "鄂不齊挺秀，蘭茁竟摧芳。", "老盡凌雲氣，悲成捉月狂。", "若人奇且折，此事費平章。"]'),
('d0ad2f01-0f65-4fdb-abb4-db65c9f56e75','張通判挽詩','魏了翁','宋','宋诗','song-poetry','','[]','規摹都水監，文采白雲卿。',48,'全唐诗/poet.song.191000.json','["規摹都水監，文采白雲卿。", "奕葉皆華貫，夫君獨屏星。", "滋滋熙世學，藹藹擅詩聲。", "耆老彫零盡，從誰正典刑。"]'),
('e7da3af0-b7ca-40ac-a0cb-5d95d34e5fd4','魚耶孫氏挽詩','魏了翁','宋','宋诗','song-poetry','','[]','可堪風撼木，不見雪盈簪。',48,'全唐诗/poet.song.191000.json','["可堪風撼木，不見雪盈簪。", "嫠緯愁春晝，兒書課夜深。", "米鹽毋我累，惸獨是予心。", "未報熊丸苦，寒堂服已廞。"]'),
('f4513764-4165-45f5-be6a-d3985aabbc13','仲女挽詩','魏了翁','宋','宋诗','song-poetry','','[]','荆江春夢斷，虞殯夜魂孤。',48,'全唐诗/poet.song.191000.json','["荆江春夢斷，虞殯夜魂孤。", "未及陪宗室，應難祔舅姑。", "一時母從子，百歲婦隨夫。", "此禮緣情制，臨風老淚枯。"]'),
('6432c845-3af0-4a53-a92a-0e26469285b3','武康軍僉判師君挽詩','魏了翁','宋','宋诗','song-poetry','','[]','換却野人服，衣之從事衫。',48,'全唐诗/poet.song.191000.json','["換却野人服，衣之從事衫。", "人忻犠被繡，我笑馬羈銜。", "客靜閒尊禁，身彊閣杖函。", "典刑那復見，宰樹閟窯巖。"]'),
('46bde523-173d-46e3-8f4e-d024d5f78552','楊極父挽詩','魏了翁','宋','宋诗','song-poetry','','[]','高堂元祐脚，下澤少游鄉。',48,'全唐诗/poet.song.191000.json','["高堂元祐脚，下澤少游鄉。", "自得林泉趣，不登聲利場。", "年方榮四豆，日已下三商。", "有子翁無咎，存心味更長。"]'),
('75e9bd90-3a10-44cc-a1e7-ebf89359a96e','史合州挽詩','魏了翁','宋','宋诗','song-poetry','','[]','昔忝東川使，知公才諝長。',48,'全唐诗/poet.song.191000.json','["昔忝東川使，知公才諝長。", "莫邪寧是利，薤本未爲彊。", "橫槊悲秋塞，凝香送夕陽。", "邊關正多事，感慨卧龍岡。"]'),
('39b447cc-e145-4910-9c44-6f1b9b6d614b','孺人譙氏挽詩','魏了翁','宋','宋诗','song-poetry','','[]','門閭冰似清，譙女復蘇甥。',48,'全唐诗/poet.song.191000.json','["門閭冰似清，譙女復蘇甥。", "幸有室家樂，寧無兄弟情。", "滅鄫雖未忍，歸衛不容行。", "獨殿諸昆後，鸞封賁九京。"]'),
('ca267e10-2098-45f6-9c73-b346696b203a','李順慶挽詩','魏了翁','宋','宋诗','song-poetry','','[]','蜜紹方聞學，親承太史傳。',48,'全唐诗/poet.song.191000.json','["蜜紹方聞學，親承太史傳。", "才資元近厚，輩行最推賢。", "七任二千石，分符三十年。", "天廷無一跡，歸伴壑龍眠。"]'),
('7cf5bf62-8265-42d8-9b9e-b97291992288','高開國挽詩','魏了翁','宋','宋诗','song-poetry','','[]','並游英俊半歸泉，何事夫君又弱焉。',64,'全唐诗/poet.song.191000.json','["並游英俊半歸泉，何事夫君又弱焉。", "廉退風標留萬口，勤勞心事入塵編。", "團團故步八千石，落落浮名四十年。", "除却江東膚使在，一時舊話向誰傳。"]'),
('93759643-f217-4024-a8fa-ce4d221bc52f','高龍學挽詩','魏了翁','宋','宋诗','song-poetry','','[]','蜀自開禧後，西垂畏廩秋。',288,'全唐诗/poet.song.191000.json','["蜀自開禧後，西垂畏廩秋。", "更經兩單閼，盡棄五邊州。", "新沔依同谷，中梁恃武休。", "匆匆移米嶺，往往阻金牛。", "嶓冢略逋寇，益昌隨解舟。", "近猶趨劍閬，遠或至渝涪。", "棄守儕民旅，奔軍齒寇讎。", "亂生寧有豸，衆潰已無鳩。", "伯也傷時久，民兮作己憂。", "升沈隨分定，行止與天謀。", "高尚辭丹詔，低回佐碧油。", "封疆資屏翰，原隰頼咨諏。", "事變方濡首，人情苦掉頭。", "誓言捐一死，力與障橫流。", "固分爲忠鬼，安能效泣囚。", "訣辭貽子弟，壯語駭朋儔。", "憤極拳穿爪，兵交血染髏。", "不隨蜍志在，甘逐遠巡遊。", "志士聞風起，頑夫背面羞。", "公身無復憾，疆事更誰籌。", "學士標龍直，文階列禁游。", "湛恩沾骨肉，新廟賁林丘。", "三禭雖云厚，百身安足酬。", "遊魂如可作，近事亦知不。"]'),
('8d2fd7bd-246e-40df-94df-04a37139b488','送張總卿護餉益昌','魏了翁','宋','宋诗','song-poetry','','[]','陳陳之粟誇西都，長旗一摇掃地無。',290,'全唐诗/poet.song.191000.json','["陳陳之粟誇西都，長旗一摇掃地無。", "剝民肌血事軍賦，天乎生此桑大夫。", "有唐藩方既旅拒，中朝獨仰江淮租。", "士安雖善操低昂，弘羊百世仍同塗。", "要知元和國計簿，不似末世供軍圖。", "人間遺利或盡取，天下大本須持扶。", "餉臺今得張省主，建置不用新規模。", "但云宅家本忠厚，當爲己責寬宿逋。", "操觚數草便民奏，不用補瘡及寧膚。", "只將常賦供調度，澤中有水民其蘇。", "八十餘年久胡虜，有弓未弛仍張舒。", "軍儲粒粒皆汗禾，植根雖固憂其枯。", "矧今兩虎方血鬭，坐使叢鸇爲吾敺。", "守邊但用平平策，主計不須急急符。", "苔封木牛卧流馬，塞南塞北無單于。", "安西相君坐專閫，與公體國心腸敷。", "智名勇功不挂眼，男粟女布思其餘。", "玉皇正用富民相，當見二公對府持鈞樞。"]'),
('e1ad2f04-e1e4-4948-896c-ee2bbeadd4ab','南閣行','魏了翁','宋','宋诗','song-poetry','','[]','北城之陽有南閣，李家石林丈人作。',316,'全唐诗/poet.song.191000.json','["北城之陽有南閣，李家石林丈人作。", "上有儲皇資善顔，下有先世淳熙脚。", "前瞻平遠後闉闍，左揖蟇頤右龍鶴。", "丙丁架上書衡從，甲乙檻前石參錯。", "有時晨策披氤氳，九萬帝青闖簾幕。", "有時夜几憑泬寥，海牛挂空月爲箔。", "啾嘈市聲不我即，淡沱春風無處着。", "斯干秩秩兄弟好，伐木丁丁友朋樂。", "我亦時爲末至賓，尊前往往追酬酢。", "主人挽我觀南山，南山分明在天角。", "豈不陪朝隮，浮雲翳林薄。", "浮雲白衣蒼狗耳，須臾變態山自若。", "置之姑勿道，願言細商略。", "試觀天地之最中，坎北離南儼成列。", "人以一心位兩間，取象爲離豈徒設。", "譬如南方萬物皆相見，又如日中纖微靡不炤，亭亭當當亦綽綽。", "遠看鳶魚近夫婦，仰觀宇宙俯今昨。", "隨事炯然存，旦晝敢金鑠。", "主人聞此笑而興，謂我此言亦觀噱。", "次成古歌行，聊當南閣說。"]'),
('0dde24ef-d5c4-4f58-a226-cb3680acb35d','山河嘆送劉左史歸簡州','魏了翁','宋','宋诗','song-poetry','','[]','山河兩戒南北分，天地一氣華戎鈞。',384,'全唐诗/poet.song.191000.json','["山河兩戒南北分，天地一氣華戎鈞。", "譬諸指搐非害事，往往四體爲不信。", "惟今醜虜相噬吞，人言雪恥茲其辰。", "盍驅卞莊刺鬭虎，又嗾廬㹱擒狡㕙。", "天王仁愛兼南北，猶遣升勺蘇窮鱗。", "諸公亦復創前誤，閉戶不肯顧鬭鄰。", "流移降附莫皇卹，斬艾驅迫如窮麕。", "誰知炎炎將及我，事體不與開禧倫。", "竟因示弱啟狄侮，羽書赤白驚嚴宸。", "天王坐朝色不怡，我非爾畏民吾民。", "急從雨中徹桑土，更向火後移突薪。", "大官亦復變前說，羣而和者非一人。", "制書丁寧示招納，符檄旁午申拊循。", "臣某奉詔移江介，臣某董師留漢濱。", "西南憂顧誰其寬，即授臣某留川秦。", "夫何廷論忽中變，復議保境思和親。", "迅雷烈風僅翻覆，明虹霽日俄逡巡。", "敵人揶揄膽滿幹，志士憤鬰齒穿齦。", "東由海泗盡襄漢，西起梁沔連房均。", "暴骸蹀血蔽原谷，奪險因糧空窖囷。", "將軍憂恚或自斃，列校偃蹇不可馴。", "縣徵更賦不遺算，郡空少府無餘緡。", "邊頭被兵甫屬耳，公私已屈憂方新。", "靜惟人事百罔一，恃以亡恐惟蒼旻。"]'),
('63ec4daa-0bd2-435c-8645-62eaf7c4ebfd','燕新利路李運使致語口號','魏了翁','宋','宋诗','song-poetry','','[]','怪底梅花破臈前，祇因春色到湖邊。',64,'全唐诗/poet.song.191000.json','["怪底梅花破臈前，祇因春色到湖邊。", "虹飛雲錦看華轡，膾縷蓴絲秩玳筵。", "今日房園供解后，明朝漢省接馨妍。", "一觴遮莫霜天曉，梅角聲中更少延。"]'),
('b59bc511-6beb-4c7c-ad10-8c348a04abef','燕孫節推致語口號','魏了翁','宋','宋诗','song-poetry','','[]','身是書樓東眷孫，老僊况復種僊根。',64,'全唐诗/poet.song.191000.json','["身是書樓東眷孫，老僊况復種僊根。", "高科恰是承先躅，盛事還應表里門。", "堂上承顔情最樂，窗前草制夢猶存。", "着鞭且向長安道，春色如今紫詔溫。"]'),
('39afa0fd-b561-44bf-967d-91753e32c794','墨梅','魏了翁','宋','宋诗','song-poetry','','[]','素王本自離緇𣵀，墨者胡爲亂等差。',40,'全唐诗/poet.song.191000.json','["素王本自離緇𣵀，墨者胡爲亂等差。", "玄裏只知楊子白，皜中謾見聖人汙。", "分付商巖譜此花。"]'),
('05d5b877-933b-4326-b192-a4c44839b3b5','口占','魏了翁','宋','宋诗','song-poetry','','[]','秋風已颯梧猶碧，宿雨纔收稗亦花。',32,'全唐诗/poet.song.191000.json','["秋風已颯梧猶碧，宿雨纔收稗亦花。", "天着工夫供醉眼，東鄰有酒不堪賒。"]'),
('f3726464-2870-4bf4-b6d7-c0bb8ad31f68','偶成  其一','魏了翁','宋','宋诗','song-poetry','','[]','有口即飲酒，有眼只看書。',36,'全唐诗/poet.song.191000.json','["有口即飲酒，有眼只看書。", "看書知古今，治亂能愁予。", "不如一味飲，醉眼昏蘧蘧。"]'),
('d9bc026e-65d1-44aa-b776-a56a20b3428f','偶成  其二','魏了翁','宋','宋诗','song-poetry','','[]','沂水春風弄夕暉，舞雩意得詠而歸。',32,'全唐诗/poet.song.191000.json','["沂水春風弄夕暉，舞雩意得詠而歸。", "爲何與點狂曾晢，箇裏須參最上機。"]'),
('0a7edfa1-61f9-43ab-84dd-df35ef08c37d','題米南宮雲山掛幅','魏了翁','宋','宋诗','song-poetry','','[]','漠漠雲林小小山，誰家茅屋隠松間。',32,'全唐诗/poet.song.191000.json','["漠漠雲林小小山，誰家茅屋隠松間。", "石橋雨過天台遠，采藥仙人去未還。"]'),
('33911e55-44c1-4355-9371-181e78381e07','夏港僧舍','魏了翁','宋','宋诗','song-poetry','','[]','迅商呼不來，午汗如翻漿。',120,'全唐诗/poet.song.191000.json','["迅商呼不來，午汗如翻漿。", "道人空萬緣，解后贊公房。", "虛室千世界，圓滿一鉢囊。", "碧雲護兜率，白日照普光。", "蕭蕭蘆葦中，着此清浄坊。", "鑑師從西來，一喝登慈航。", "唾手舉慧刃，斫斷煩惱韁。", "邀我供煮餠，心地陡清凉。", "官焙破蒼璧，桃笙漲寒江。", "從師問究竟，室西照殘陽。"]'),
('55fe9134-eabe-4512-91bf-6cb59a4af4fb','題石洞','魏了翁','宋','宋诗','song-poetry','','[]','跨澗飛虹入洞門，石梯級級樹森森。',64,'全唐诗/poet.song.191000.json','["跨澗飛虹入洞門，石梯級級樹森森。", "兩崖對立自賓主，一水長流無古今。", "仙子吹笙招鶴舞，騷人得句伴猿吟。", "箇中便是蓬萊境，何必迢迢海上尋。"]'),
('5c0efec8-586a-4527-9574-ed79a488768c','遊上天竺','魏了翁','宋','宋诗','song-poetry','','[]','風波滿平地，世路繞羊腸。',48,'全唐诗/poet.song.191000.json','["風波滿平地，世路繞羊腸。", "急欲逃塵網，遥登選佛場。", "雲深午猶暝，竹密夏生凉。", "興逸忘歸去，高眠借石牀。"]'),
('845c9d38-1fa3-49fc-b833-286e9197deef','句','魏了翁','宋','宋诗','song-poetry','','[]','乾闕一鈎金。',6,'全唐诗/poet.song.191000.json','["乾闕一鈎金。"]'),
('43d0906d-9466-48fd-bdbb-2d3dd9f24b4a','關山月','鄒登龍','宋','宋诗','song-poetry','','[]','行人十年歸不得，夜上戍樓看明月。',104,'全唐诗/poet.song.191000.json','["行人十年歸不得，夜上戍樓看明月。", "樓中星斗連太白，樓外關山鴈飛絕。", "鴈飛絕，歸不得，鏡裏青蛾怨離別。", "前年出幽燕，明月何團圓。", "去年上祁連，明月復嬋娟。", "月明照我長枕戈，胡兒未滅將柰何。", "憑誰寄書問常娥，征衲不來霜霰多。"]'),
('d1492585-2ba1-48ef-98e0-5e65db6959a9','從軍行','鄒登龍','宋','宋诗','song-poetry','','[]','年少良家子，投身事西北。',60,'全唐诗/poet.song.191000.json','["年少良家子，投身事西北。", "金鳴鬭馬嘶，蕭蕭短兵發。", "夜戰祁連山，斷甲濺腥血。", "番部带箭降，番酋連陣沒。", "勒功紀燕然，椎鼓歸漢闕。"]'),
('896be44d-b27f-45ec-bc8d-6d6efca238d8','結客少年場','鄒登龍','宋','宋诗','song-poetry','','[]','并兒任氣俠，年少肝膽雄。',60,'全唐诗/poet.song.191000.json','["并兒任氣俠，年少肝膽雄。", "錦臂金彈丸，銀鞍玉花驄。", "腰插三尺劍，手開二石弓。", "輕生重大義，一戰朔庭空。", "斬取戎王頭，捷奏甘泉宮。"]'),
('02e34884-2861-4ede-9725-6966a6630d24','秋夜長曲','鄒登龍','宋','宋诗','song-poetry','','[]','碧簾掛雨秋容老，寂寞江城暝煙草。',64,'全唐诗/poet.song.191000.json','["碧簾掛雨秋容老，寂寞江城暝煙草。", "流蘇帳冷屏山低，蜜炬香銷睡常早。", "夢驚離緒牽愁入，翠被寒侵淚花濕。", "思美人兮天一方，烏啼月落西風急。"]'),
('33bef139-2630-4bf8-b460-07804846a3ec','青樓曲','鄒登龍','宋','宋诗','song-poetry','','[]','青樓女兒十五六，翠掠雲鬟妙裝束。',64,'全唐诗/poet.song.191000.json','["青樓女兒十五六，翠掠雲鬟妙裝束。", "千金學舞拜部頭，新來教得凉州曲。", "錦韉少年被花惱，醉把金釵換香草。", "西風樓前秋鴈飛，舞衣狼籍花顛倒。"]'),
('2d4e566e-3eab-4ce8-8d10-e53946f38dde','採蓮曲','鄒登龍','宋','宋诗','song-poetry','','[]','平湖淼淼蓮風清，花開映日紅妝明。',64,'全唐诗/poet.song.191000.json','["平湖淼淼蓮風清，花開映日紅妝明。", "一雙鸂鶒忽飛去，爲驚花底蘭橈鳴。", "蘭橈蕩漾誰家女，雲妥髻鬟黛眉嫵。", "采采荷花滿袖香，花深忘却來時路。"]'),
('7cf1ca40-fd29-4086-83b2-d3418b1dd030','江南春','鄒登龍','宋','宋诗','song-poetry','','[]','玲瓏樓閣江城晚，楊柳絲絲凝碧煙。',32,'全唐诗/poet.song.191000.json','["玲瓏樓閣江城晚，楊柳絲絲凝碧煙。", "飛燕不歸春滿地，百花香裏聽啼鵑。"]'),
('4d8c036d-fb43-4918-8ad9-385e2de15eaf','長門怨','鄒登龍','宋','宋诗','song-poetry','','[]','怨殺宮門不忍開，無情孤月暗蒼苔。',32,'全唐诗/poet.song.191000.json','["怨殺宮門不忍開，無情孤月暗蒼苔。", "而今痛惜珊瑚枕，曾是君王賜御來。"]'),
('76a8e8ff-f6c6-49ec-afe8-833126d192ed','巫山高','鄒登龍','宋','宋诗','song-poetry','','[]','巫山巃嵸巫峽曲，一十二峰淺凝綠。',64,'全唐诗/poet.song.191000.json','["巫山巃嵸巫峽曲，一十二峰淺凝綠。", "老猿化石懸巔崖，矗矗陵雲掃壇竹。", "九靈少女列仙從，佩玉鳴鑾乘綵鳳。", "飛魂走魄歸瑶宮，紫簫吹斷荆王夢。"]'),
('d630c697-08bb-4f94-b109-a701e0346382','雪霽梅月曲','鄒登龍','宋','宋诗','song-poetry','','[]','羌玄圃兮玉英，蹇冰輪兮太清。',44,'全唐诗/poet.song.191000.json','["羌玄圃兮玉英，蹇冰輪兮太清。", "猗縞袂兮誰子，粲一笑兮傾城。", "倚橫吹兮寄哀思，擥幽香兮補騷情。"]'),
('6bd10cfa-948c-4381-b4e0-e20d6637cace','遊仙','鄒登龍','宋','宋诗','song-poetry','','[]','人命如朝露，壽非金石堅。',108,'全唐诗/poet.song.191000.json','["人命如朝露，壽非金石堅。", "安得傅六翮，飄飄凌紫烟。", "夕夢一道士，羽衣何翩躚。", "邀我與之去，同上扶桑巔。", "道遇青童君，授以東華篇。", "讀之三百遍，忽若骨已仙。", "道士復謂我，玄訣未可傳。", "賜我以瓊漿，飲之享遐年。", "明發寂無覩，孤鶴翔九天。"]'),
('df661344-3984-426d-bab0-43d4622f1105','詠懷','鄒登龍','宋','宋诗','song-poetry','','[]','洪河相綿纏，嘉宅良可卜。',84,'全唐诗/poet.song.191000.json','["洪河相綿纏，嘉宅良可卜。", "蒼松蔭長蹊，叢梅馥四屋。", "過庭白水流，飛鳴漱寒玉。", "遊目俯靈景，抱杖委繁俗。", "長吟暢幽懷，理琴展清曲。", "豈不企淩厲，而乃傷局促。", "吉士抗遐蹤，幽幽聚靈族。"]'),
('ffcf94a7-2960-46b7-a1bf-94b4ad8c173b','步出城東門','鄒登龍','宋','宋诗','song-poetry','','[]','步出城東門，與子各執手。',72,'全唐诗/poet.song.191000.json','["步出城東門，與子各執手。", "遥望冢纍纍，悲風發隴首。", "長松自青青，枯根带骨朽。", "人生如朝露，嘉命那可久。", "世無王子喬，何訣以固壽。", "感慨徒悲傷，歡言且飲酒。"]'),
('b35886a1-bc21-4a0b-bfda-6f2c97ba5a63','山上有白雲','鄒登龍','宋','宋诗','song-poetry','','[]','山上有白雲，浮陰翳陽光。',48,'全唐诗/poet.song.191000.json','["山上有白雲，浮陰翳陽光。", "亭亭颯繽紛，出岫高飛翔。", "飛翔長在望，遠匪千里隔。", "莫以秋風來，吹散無蹤跡。"]'),
('8063b332-d707-421b-b7f3-1405e2f70cb9','秋夜懷菊山沈莊可','鄒登龍','宋','宋诗','song-poetry','','[]','凉風動金旻，奄忽寒節至。',48,'全唐诗/poet.song.191000.json','["凉風動金旻，奄忽寒節至。", "百卉俱萎垂，梧桐亦飄墜。", "明月入我牖，展轉不能寐。", "顧影重傷心，思君長下淚。"]'),
('bf607d41-6239-4e18-8bc9-60ed15f8db38','歲晚懷愚齋趙叔愚壺山宋謙父','鄒登龍','宋','宋诗','song-poetry','','[]','忽忽歲將暮，烈烈北風凉。',72,'全唐诗/poet.song.191000.json','["忽忽歲將暮，烈烈北風凉。", "霏霏雨素雪，皎皎南枝芳。", "懆懆念良友，煢煢在他鄉。", "盈盈一水隔，迢迢道路長。", "悠悠無信音，戚戚重感傷。", "翩翩化雙鶴，去去與同翔。"]'),
('85394478-93b1-4751-a505-4a907e4fb394','月洲李賈友山捧檄來淦訪我梅下示教禁體物語詠梅佳句今歲梅開月洲仙去追和元韻感此良友','鄒登龍','宋','宋诗','song-poetry','','[]','庭前有奇樹，幽艷發寒柯。',48,'全唐诗/poet.song.191000.json','["庭前有奇樹，幽艷發寒柯。", "寂寂衆芳歇，綿綿生意多。", "孤根依嶺表，高節委巖阿。", "清友今何在，悠悠空逝波。"]'),
('2b175ce8-619f-4384-8572-13dbd082b3e4','和竹里蘇材叔見梅懷友韻','鄒登龍','宋','宋诗','song-poetry','','[]','徘徊江路側，何以慰相思。',48,'全唐诗/poet.song.191000.json','["徘徊江路側，何以慰相思。", "陽彩來寒樹，貞姿倚暮籬。", "飄零懷遠道，遼索負芳時。", "佇立幽吟苦，餘懷將訴誰。"]'),
('d6af80df-5dff-486f-a053-50546a5f4b13','西郊梅開懷吟軒周獻父','鄒登龍','宋','宋诗','song-poetry','','[]','仲冬寒氣盛，玄雲停故陰。',48,'全唐诗/poet.song.191000.json','["仲冬寒氣盛，玄雲停故陰。", "嘉樹厲清節，孤芳潔素心。", "幽幽熒歲落，皎皎隔塵侵。", "折寄無來使，山川迥且深。"]'),
('acb069d4-0567-4876-b42f-c55d13a2f654','滕閣懷古','鄒登龍','宋','宋诗','song-poetry','','[]','凭高獨展眺，風葉亂鳴秋。',48,'全唐诗/poet.song.191000.json','["凭高獨展眺，風葉亂鳴秋。", "鑾舞自空閣，漁歌尚晚舟。", "卷簾山歷歷，倚檻水悠悠。", "月出江城暮，凄凉萬古愁。"]'),
('07b082c5-f311-4867-9b61-3062987ce5a9','寄雲林楊少雲自衡之桂','鄒登龍','宋','宋诗','song-poetry','','[]','問訊楊夫子，經年客異鄉。',48,'全唐诗/poet.song.191000.json','["問訊楊夫子，經年客異鄉。", "南浮湘水遠，西望楚天長。", "五嶺梅花發，孤城草色荒。", "白雲遥滿目，曷久住炎方。"]'),
('881bfbe5-46d2-4115-b62c-e5059b104b43','寄呈後村劉編修','鄒登龍','宋','宋诗','song-poetry','','["\u8861\u5c71"]','衆作紛紛等噪蟬，先生中律更鈎玄。',64,'全唐诗/poet.song.191000.json','["衆作紛紛等噪蟬，先生中律更鈎玄。", "如開元可二三子，自晚唐來數百年。", "人競寶藏南嶽藁，商留金易後村編。", "儻令舐鼎隨雞犬，凡骨從今或可仙。"]'),
('bf46223a-9105-454d-87e6-63d358b232af','戴式之來訪惠石屏小集','鄒登龍','宋','宋诗','song-poetry','','[]','詩翁香價滿江湖，肯訪西郊隠者居。',64,'全唐诗/poet.song.191000.json','["詩翁香價滿江湖，肯訪西郊隠者居。", "瘦似杜陵常戴笠，狂如賈島少騎馿。", "但存一路征行藁，安用諸公介紹書。", "篇易百金寧不售，全編遺我定交初。"]'),
('8241d1de-1e39-49e1-a553-09bbb9a9a74f','江居','鄒登龍','宋','宋诗','song-poetry','','[]','獨作幽居計，江邊屋數間。',48,'全唐诗/poet.song.191000.json','["獨作幽居計，江邊屋數間。", "水流天自在，心遠地寬閑。", "鉏月栽梅樹，移雲疊石山。", "白鷗盟欲結，倚杖看潺湲。"]'),
('0ee732e3-9993-4509-a865-0e42f771fa7f','溪村','鄒登龍','宋','宋诗','song-poetry','','[]','兀兀小橋西，人家住繞溪。',48,'全唐诗/poet.song.191000.json','["兀兀小橋西，人家住繞溪。", "雲山當戶入，竹樹出簷齊。", "風急花初盡，春深鶑亂啼。", "稻畦新雨足，穉子亦鉏犁。"]'),
('be7e4e6e-c41a-4353-a6de-d5abf614c706','題杜少陵草堂圖','鄒登龍','宋','宋诗','song-poetry','','[]','背郭好林塘，誅茅作草堂。',48,'全唐诗/poet.song.191000.json','["背郭好林塘，誅茅作草堂。", "因吟白鴉谷，爲卜碧雞坊。", "籠竹和煙浄，江梅带雪香。", "四松經喪亂，閲世幾風霜。"]'),
('00ca30ef-c1b3-4362-a2e3-50edad154733','遊玉笥山','鄒登龍','宋','宋诗','song-poetry','','[]','玉笥凌空後，玄都詔吏仙。',48,'全唐诗/poet.song.191000.json','["玉笥凌空後，玄都詔吏仙。", "荒壇深覆草，峭壁響流泉。", "石洞隨龍蟄，金丹許鶴傳。", "夜深搗藥鳥，啼破翠微煙。"]'),
('4b8fa539-e7a4-4fa1-a0ec-5a1c8489a85c','入投龍洞','鄒登龍','宋','宋诗','song-poetry','','[]','行入投龍洞，青青見竹竿。',48,'全唐诗/poet.song.191000.json','["行入投龍洞，青青見竹竿。", "暮雲生道樹，夜月滿仙壇。", "枯蘚沿崖古，長松繞澗寒。", "三生清浄福，獨此愧黄冠。"]'),
('ee490110-bf19-4f76-a8d7-a93518cbb04d','上慧力寺','鄒登龍','宋','宋诗','song-poetry','','[]','今代空王宅，前朝處士家。',48,'全唐诗/poet.song.191000.json','["今代空王宅，前朝處士家。", "牛車回象藏，鹿苑發龍華。", "松密風生樹，江空月在沙。", "闍黎飯鐘後，邀我試新茶。"]'),
('44f8aeb4-8492-4e65-9661-674be56d4eac','寄蒼山曾子實','鄒登龍','宋','宋诗','song-poetry','','[]','東湖從此別，嘉會邈無期。',48,'全唐诗/poet.song.191000.json','["東湖從此別，嘉會邈無期。", "望遠音書阻，思君歲月馳。", "春雲山隔斷，秋雨鴈歸遲。", "欲見崆峒使，梅花寄一枝。"]'),
('b912a73e-842c-4a07-951e-a1cf41cfa60a','幽事','鄒登龍','宋','宋诗','song-poetry','','[]','閑携小斧刪梅樹，自縛枯藤補菊籬。',32,'全唐诗/poet.song.191000.json','["閑携小斧刪梅樹，自縛枯藤補菊籬。", "燒柏子香讀周易，滴荷花露寫唐詩。"]'),
('cee69e1a-c44b-405c-b2ae-0faf72da976a','遊仰山寺','鄒登龍','宋','宋诗','song-poetry','','[]','施地開金剎，神因結佛緣。',48,'全唐诗/poet.song.191000.json','["施地開金剎，神因結佛緣。", "怪松盤獺徑，古木護龍淵。", "雲裹春山亂，禽啼夜月圓。", "路遥歸不得，好借上方眠。"]'),
('0e0c8049-191f-458b-a994-2ec91b5378ee','宮詞','鄒登龍','宋','宋诗','song-poetry','','[]','內人倚遍玉樓東，曉色開雲臘雪融。',32,'全唐诗/poet.song.191000.json','["內人倚遍玉樓東，曉色開雲臘雪融。", "羯鼓一聲花盡拆，三郎自喚作天公。"]'),
('2ed4e83d-34c1-4736-9895-964f8218823f','梅花','鄒登龍','宋','宋诗','song-poetry','','[]','約臂金寒拓綺疏，搔頭玉重壓香酥。',32,'全唐诗/poet.song.191000.json','["約臂金寒拓綺疏，搔頭玉重壓香酥。", "含章簷下新妝額，試啟菱花得似無。"]'),
('4cd4747f-0c2f-4fce-919c-142f92e4297f','送表兄趙奏院赴南外知宗','鄒登龍','宋','宋诗','song-poetry','','[]','御屏往往題名字，朝路彬彬藹薦書。',64,'全唐诗/poet.song.191000.json','["御屏往往題名字，朝路彬彬藹薦書。", "天許留中監邸奏，日求補外得堂除。", "暫煩龍種司瑶籍，行立鴛班侍玉輿。", "丙枕或思前夜席，庚郵寧肯後鋒車。"]'),
('80f3dda8-87ac-4226-b041-c25e866c8e3a','王氏山居','鄒登龍','宋','宋诗','song-poetry','','[]','聞道山居好，林深遠俗情。',48,'全唐诗/poet.song.191000.json','["聞道山居好，林深遠俗情。", "茶煙熏壁暗，蘿月射窗明。", "學稼修禾譜，栽花識藥名。", "無人覺幽隠，爲有讀書聲。"]'),
('10fa8e17-f189-4c94-930a-661049b9bcc8','送雲巢曾校勘赴召','鄒登龍','宋','宋诗','song-poetry','','[]','高卧雲巢久，雲生處士衣。',48,'全唐诗/poet.song.191000.json','["高卧雲巢久，雲生處士衣。", "忽聞頒詔札，催入侍經幃。", "朝野名雖盛，山林志莫違。", "好歸清澗隠，富貴有危機。"]'),
('9fd55d85-6bea-43dd-b5a4-76979ea1a404','水亭','鄒登龍','宋','宋诗','song-poetry','','[]','闌檻玲瓏直又橫，半臨池水着新亭。',64,'全唐诗/poet.song.191000.json','["闌檻玲瓏直又橫，半臨池水着新亭。", "擬招鷺宿栽添葦，怕礙魚行掠去萍。", "五月藕花千樣錦，四時山色一般青。", "有閑來此尋幽賞，莫看人間淡墨屏。"]'),
('365fc50e-538e-4c18-a24e-b5691dec8239','趙承遠雲扃','鄒登龍','宋','宋诗','song-poetry','','[]','聞道幽居好，棲雲結數椽。',48,'全唐诗/poet.song.191000.json','["聞道幽居好，棲雲結數椽。", "庭深關竹雨，衣潤染茶煙。", "嵐氣生朝壁，湍聲入夜絃。", "半生飛動意，未得痼林泉。"]'),
('201f46d6-2296-4900-881e-2153029099f1','嘲禿筆','周獻甫','宋','宋诗','song-poetry','','[]','中書君己不中書，椎鈍無心費指呼。',32,'全唐诗/poet.song.191000.json','["中書君己不中書，椎鈍無心費指呼。", "別有管城堪任使，從教駡作筆頭奴。"]'),
('7d766b82-34ac-4736-81d5-d1ef802c7058','齋扉','周獻甫','宋','宋诗','song-poetry','','[]','暫別齋扉數日餘，重來整頓案頭書。',64,'全唐诗/poet.song.191000.json','["暫別齋扉數日餘，重來整頓案頭書。", "硯池乾恐蚍蜉入，筆管閑容果臝居。", "葉長密留梅實少，笋生多補竹莖疏。", "匆匆未暇供吟課，鶑送清聲一起予。"]'),
('05114220-f9f6-4c4a-a450-edb39aa95e44','羃窗','周獻甫','宋','宋诗','song-poetry','','[]','薄紙新糊就，翛然一室清。',48,'全唐诗/poet.song.191000.json','["薄紙新糊就，翛然一室清。", "有風寒不到，無月夜能明。", "暫隔前山色，時敲落葉聲。", "凍蠅可憎汝，鑽撲漫營營。"]'),
('7cfa559f-ffd1-4351-8aff-3f752da3a167','鄒震父遷居界步','周獻甫','宋','宋诗','song-poetry','','[]','買得林廬在水西，眼前幽事總相宜。',64,'全唐诗/poet.song.191000.json','["買得林廬在水西，眼前幽事總相宜。", "溪山處分鶑看管，梅竹添差鶴護持。", "旋理小園增野趣，先留隙地作樓基。", "却來界步晴嵐底，收拾湄湘八景詩。"]'),
('b4cb1d2d-cd6c-4f2f-a954-d140d430b3fc','吟軒','周獻甫','宋','宋诗','song-poetry','','[]','何以號吟軒，疎窗矮屋椽。',48,'全唐诗/poet.song.191000.json','["何以號吟軒，疎窗矮屋椽。", "紙抄唐絕句，壁寫宋詩篇。", "閑或支頤坐，慵來枕肘眠。", "讀他三兩意，心下自欣然。"]'),
('3be630fe-dc45-4590-93fe-35176b87d4b3','送石深之歸沃洲','謝耘','宋','宋诗','song-poetry','','[]','嬾踏紅塵地，結廬巖壑間。',48,'全唐诗/poet.song.191000.json','["嬾踏紅塵地，結廬巖壑間。", "酒催清夜別，身伴白雲還。", "賀老湖邊月，支公屋外山。", "沃洲吟不盡，天與老翁閑。"]'),
('805b8ef2-e215-410a-b210-b097ba241066','句','謝耘','宋','宋诗','song-poetry','','[]','路深容馬窄，樓小插花多。',12,'全唐诗/poet.song.191000.json','["路深容馬窄，樓小插花多。"]'),
('b84f3522-fc78-4d80-adb6-5a959c1d94dd','遊涪溪  其一','程以謙','宋','宋诗','song-poetry','','[]','憶昔經行三十秋，重來創見古東樓。',64,'全唐诗/poet.song.191000.json','["憶昔經行三十秋，重來創見古東樓。", "涪溪天造渾無恙，鐵鎖雲橫欲斷流。", "兩客後來誰更重，一樽今日意慵浮。", "懷人萬古高山仰，賸喜夤緣得再遊。"]'),
('8bae0094-9a21-4fb7-90de-b605c2201852','遊涪溪  其二','程以謙','宋','宋诗','song-poetry','','[]','重憶□都擾擾時，自憐解事作癡兒。',64,'全唐诗/poet.song.191000.json','["重憶□都擾擾時，自憐解事作癡兒。", "風聲鶴唳從渠駭，斗折蛇行笑我危。", "地險向來誇峻國，天誅□許恃滇池。", "氈裘未省相知否，更欲憑君一問之。"]'),
('12db1f60-e5b6-40b5-9cb7-39de60cd36ed','汨羅廟','許晟大','宋','宋诗','song-poetry','','[]','白鶴真人朝玉京，故留僊屬鎮山精。',32,'全唐诗/poet.song.191000.json','["白鶴真人朝玉京，故留僊屬鎮山精。", "時人却道投潭死，不得其平所以鳴。"]'),
('748a50b8-6128-4a5b-a910-c54d9e63828f','臨終偈','釋普濟','宋','宋诗','song-poetry','','[]','記得黄梅與我時，忽然天氣報君知。',32,'全唐诗/poet.song.191000.json','["記得黄梅與我時，忽然天氣報君知。", "逆行順化無交涉，撒手毗盧頂上歸。"]'),
('9effb6fb-6392-4b33-847c-93773e8742ed','臨終偈','釋文雅','宋','宋诗','song-poetry','','[]','薩埵裝嚴已現成，老僧恰合去遊循。',32,'全唐诗/poet.song.191000.json','["薩埵裝嚴已現成，老僧恰合去遊循。", "有人問着西來意，天上無僧地絕塵。"]'),
('2b8454a8-cf11-40c2-b339-df16a85b06e6','題濮村','李遇','宋','宋诗','song-poetry','','[]','乞與東風十日晴，放教杖屨步雲輕。',64,'全唐诗/poet.song.191000.json','["乞與東風十日晴，放教杖屨步雲輕。", "客閑到處俱詩往，春色濃時載酒行。", "別去江山如識面，重來花鳥更關情。", "一官休羨無氈冷，官冷元來愈覺清。"]'),
('40d9e038-19f8-4489-b058-6eb68123981b','詠西湖江湖偉觀樓','李遇','宋','宋诗','song-poetry','','["\u897f\u6e56", "\u6d1e\u5ead\u6e56"]','舉目看來皆畫屏，只因欄檻接蒼冥。',64,'全唐诗/poet.song.191000.json','["舉目看來皆畫屏，只因欄檻接蒼冥。", "江湖二水一船白，吳越兩山相對青。", "雲北雲南何處沒，潮生潮落幾時停。", "西偏不被斜陽礙，直見家山與洞庭。"]'),
('a7f79b52-c91c-402a-b31d-dce0b0d9d2fa','登騎石山  其一','黄汝嘉','宋','宋诗','song-poetry','','[]','江城樓閣闢嵯峨，如此隨風燕雀何。',64,'全唐诗/poet.song.191000.json','["江城樓閣闢嵯峨，如此隨風燕雀何。", "古木望中松柏少，好花開處杏桃多。", "徐殷舊宅僧爲主，褚氏閒亭鶴占坡。", "花落花開今古事，青山無語野樵歌。"]'),
('bae49463-bfd1-40d1-9141-afb8618814db','登騎石山  其二','黄汝嘉','宋','宋诗','song-poetry','','[]','一亭平倚此山巔，展盡郊原極目天。',64,'全唐诗/poet.song.191000.json','["一亭平倚此山巔，展盡郊原極目天。", "高下樓臺微带雨，參差樹木遠含煙。", "品題物象詩聯軸，管領江山酒滿船。", "官冗不妨登覽興，塵襟到此自翛然。"]'),
('cf3b0785-c421-4c21-ba50-61f2a6ab3e62','高山堂','梁佐','宋','宋诗','song-poetry','','[]','巍巔層閣倚雲平，一凭闌干醉魄醒。',64,'全唐诗/poet.song.191000.json','["巍巔層閣倚雲平，一凭闌干醉魄醒。", "霽雨亂山生淡碧，带風寒竹有餘青。", "孤猨傍石來深磵，幽鳥衝烟入畫屏。", "却重高僧仙景象，蓬萊不獨在滄溟。"]'),
('d0b3a1ea-f815-4151-beec-a5a82f2f5f0e','高山堂和節度使梁公韻','史安之','宋','宋诗','song-poetry','','[]','閣憑嵬構敞軒扃，一望塵凡目暫醒。',64,'全唐诗/poet.song.191000.json','["閣憑嵬構敞軒扃，一望塵凡目暫醒。", "巖嶂遠供千疊翠，松篁還聳四時青。", "登臨雅愛恣吟筆，圖畫尤宜作座屏。", "我欲從君遊未得，壯心方欲翥南溟。"]'),
('2dfff877-0bb5-4952-8b75-56cbd63bb6e5','謁梅都官墓  其一','滕珂','宋','宋诗','song-poetry','','[]','百年詩老卧空山，猶憶當時語带酸。',64,'全唐诗/poet.song.191000.json','["百年詩老卧空山，猶憶當時語带酸。", "贏得兒童喚夫子，可憐名位祇都官。", "手編新史唐文備，骨立殘碑漢籀漫。", "落日牛羊上丘隴，草埋翁仲獨峨冠。"]'),
('056275d9-2782-47b6-b33a-0dae7b580faa','謁梅都官墓  其二','滕珂','宋','宋诗','song-poetry','','[]','宛陵城南柏山寺，行到西廂見舊祠。',64,'全唐诗/poet.song.191000.json','["宛陵城南柏山寺，行到西廂見舊祠。", "人物欲觀嘉祐老，銘文空有醉翁辭。", "銀章粉墨誰舒卷，金薤琳琅自陸離。", "每見河豚起春岸，永懷風致細哦詩。"]'),
('9b47ba77-c491-4391-b08b-7a274c51a817','會稽頌  其一','諸葛興','宋','宋诗','song-poetry','','[]','瞻越山兮鏡之東，鬰喬木兮岑叢。',217,'全唐诗/poet.song.191000.json','["瞻越山兮鏡之東，鬰喬木兮岑叢。", "倚青霞兮窆石，枕碧流兮寶宮。", "端黻冕兮穆穆，列俎豆兮雍雍。", "梅爲梁兮挾風雨，倏而來兮忽而去。", "芝産殿兮間見，橘垂庭兮猶古。", "壁騰輝兮桂薦瑞，書金簡兮緘石匱。", "朝萬玉兮可想，探靈文兮何秘。", "嗟洚水兮橫流，民昏墊兮隠憂。", "運大智兮無事，錫洪範兮攸疇。", "身勞兮五嶽，迹書兮九州。", "亶王心兮不矜，迄四海兮歌謳。", "猗聖宋兮中興，駐翠蹕兮稽城。", "獨懷勤兮曠代，粲奎文兮日星。", "揚舲兮拊鼓，吳歈兮鄭舞。", "奠桂酒兮蘭肴，庶幾髣髴兮菲食卑宮之遺矩。"]'),
('789af441-a919-4efd-9ef1-31949595532c','會稽頌  其二','諸葛興','宋','宋诗','song-poetry','','[]','肇三聖兮傳一中，建人極兮參洪濛。',170,'全唐诗/poet.song.191000.json','["肇三聖兮傳一中，建人極兮參洪濛。", "元圭錫兮汝績，昭華歸兮汝躬。", "大道公兮均嬗繼，家天下兮繇姒氏。", "嵩石兮發祥，謳歌兮與子。", "誓甘野兮服叛，養國老兮貴齒。", "席不重兮味不貳，琴瑟屏兮鐘鼓置。", "思皇訓兮克儉，心敬承兮敢墜。", "祀四百兮綿景祚，兆大橫兮垂異世。", "越山兮蜿蜒，鏡水兮漪漣。", "煥祠宮兮屹峙，肅廡祀兮愉然。", "端冕兮龍章，執圭兮琳琅。", "想規重兮矩疊，恍韶奏兮鏗鏘。"]'),
('92655d23-c444-4462-8874-fa166b534935','會稽頌  其三','諸葛興','宋','宋诗','song-poetry','','[]','披竹簡兮典謨，聖手斷兮唐虞。',172,'全唐诗/poet.song.191000.json','["披竹簡兮典謨，聖手斷兮唐虞。", "登群龍兮輔翌，萃一堂兮都俞。", "知人兮帝之哲，動天兮帝之德。", "畫象兮民不犯，舞干兮苗已格。", "迨一旅兮中興，嚴廟貌兮稽陵。", "感會遇兮風雲，崇像飾兮股肱。", "憤夷楚兮陵上國，忽庭堅兮祀俄息。", "泚麟筆兮特書，喟夷吾兮有力。", "何汲汲兮詭誕，謂明良兮相賊。", "姦雄託兮自文，慨齊東兮毋惑。", "仰而觀兮典禮秩，俯而察兮草木殖。", "功之遠兮難名，民之思兮無斁。"]'),
('4fb4251c-a255-408a-93e0-49b2f2e9cba7','會稽頌  其四','諸葛興','宋','宋诗','song-poetry','','[]','睇禹陵兮巋然，邃珍館兮蟺蜎。',192,'全唐诗/poet.song.191000.json','["睇禹陵兮巋然，邃珍館兮蟺蜎。", "敞別室兮遺象，崇英霸兮千年。", "諗越民兮非黷祀，推世家兮自遷史。", "肇無餘兮開國，傳後裔兮奮起。", "痛夫椒兮深衄，同國人兮勞佚。", "采蕺兮食何味，嘗膽兮志密篤。", "封以內兮種所司，閫以外兮蠡所知。", "羌厲志兮澡恥，迄乘時兮决機。", "盟上國兮王致胙，按山南兮恢土宇。", "陟鑑臺兮睨東海，矩天門兮模地戶。", "惜規圖兮不弘，幾弓藏兮犬烹。", "蹇七術兮遺恨，悵五湖兮遐征。", "尚蟬嫣兮復續，終與享於鼻祖之庭。"]'),
('dbe50745-581e-4b5c-b4e4-f54e3cf426e2','會稽頌  其五','諸葛興','宋','宋诗','song-poetry','','[]','書畀姒兮力溝洫，民奠居兮勤稼穡。',154,'全唐诗/poet.song.191000.json','["書畀姒兮力溝洫，民奠居兮勤稼穡。", "降嬴劉兮言水利，嘉鄴渠兮夸鄭國。", "慨元光兮瓠子决，彼鄃封兮河之北。", "悼一言兮貽時害，諉天事兮非人力。", "昔越守兮得賢侯，慮遠久兮爲民謀。", "鏡一湖兮陂萬頃，備潴洩兮歲有秋。", "寧殺身兮利人，抑洙泗兮稱仁。", "嗟後來兮私己，田吾湖兮寖湮。", "湖之復兮疇繼，侯之心兮萬世。", "酌清流兮擷蘭芷，奉明薦兮非昵祀。"]'),
('778142b1-3004-4b7d-b4c9-090b3da96331','會稽頌  其六','諸葛興','宋','宋诗','song-poetry','','[]','典午西兮金谷輩，渡而東兮藹多士。',148,'全唐诗/poet.song.191000.json','["典午西兮金谷輩，渡而東兮藹多士。", "嘉內史兮屏浮華，淡物累兮頤天粹。", "升冶城兮遐想，友東山兮雅志。", "修禊事兮蘭亭，觴曲水兮群英。", "追雩風兮涵泳，渺萬化兮均平。", "紀清遊兮感慨，剡形忘兮神詣。", "蔚翔鳳兮一札，寶連城兮千祀。", "太傅起兮爲蒼生，扶晉鼎兮蹙苻秦。", "內史歸兮樂山水，師萬石兮飭子孫。", "出與處兮兩賢，意易地兮皆然。"]'),
('910ac3c5-79c6-47b5-8549-da892f9322d3','會稽頌  其七','諸葛興','宋','宋诗','song-poetry','','[]','山簇簇兮環湖，水淼淼兮縈紆。',187,'全唐诗/poet.song.191000.json','["山簇簇兮環湖，水淼淼兮縈紆。", "人何遊兮明鏡，鳥何飛兮畫圖。", "懷賀老兮今昔，想逸致兮林廬。", "老之襟兮天闊，老之神兮秋月。", "飛翰兮龍鸞，吐詞兮冰雪。", "際熙運兮開元，司縟典兮春官。", "凌玉霄兮倚華蓋，驂駿馭兮升西崑。", "俄清夢兮綿綿，恍乘雲兮登仙。", "覲紫皇兮玉宸，聆九奏兮鈞天。", "牋天公兮遂志，鼓予枻兮錦里。", "吾朋兮鷗鷺，吾賓兮煙水。", "野服兮蹁躚，斑衣兮娭戲。", "緬高賢兮非苟於去就，其庶幾兮東門之傅鴟夷之子。"]'),
('164aac97-411c-41a8-9142-ebe03dde9689','會稽頌  其八','諸葛興','宋','宋诗','song-poetry','','[]','虬髯起兮龍翔，耀兵威兮八方。',147,'全唐诗/poet.song.191000.json','["虬髯起兮龍翔，耀兵威兮八方。", "法羽林兮嚴禁衛，握鈎陳兮掃欃槍。", "視諸將兮噲等伍，咨舊臣兮忠且武。", "聳萬目兮矩矱，衛九重兮心膂。", "維東南兮都會，辱吾王兮鎮撫。", "暢威惠兮千載，隤福祥兮茲土。", "瞻衮服兮煌煌，薦蕙肴兮葵觴。", "匪震懾兮羅池，亶愛思兮桐鄉。", "王之澤兮流後裔，更累葉兮奮忠義。", "孰旌表兮陪廟祀，顯一門厲斯世。"]'),
('2db96609-58a7-42cb-aefb-faaadd206404','會稽頌  其九','諸葛興','宋','宋诗','song-poetry','','[]','悄叢祠兮江之湄，懔予心兮肅祗。',74,'全唐诗/poet.song.191000.json','["悄叢祠兮江之湄，懔予心兮肅祗。", "表卓行兮尚之祀，垂妙辭兮淳之碑。", "嗟窈窕兮踐天性，一念烈兮萬古鏡。", "山眉兮蒼蒼，江練兮茫茫。", "江之水兮可謁，娥之靈兮不可歇。"]'),
('42a6a81a-b8ec-49f9-9252-ef50b4ea55b7','春閒','王宗道','宋','宋诗','song-poetry','','[]','最喜逍遥泉石間，幽居四面遶青山。',64,'全唐诗/poet.song.191000.json','["最喜逍遥泉石間，幽居四面遶青山。", "草迷荒徑人稀到，花壓重門晝自關。", "古剎風傳鐘磬遠，平疇雨過桔槹閒。", "荷鉏手劚園中筍，佐酒三杯壯客顔。"]'),
('64484c3b-3fd4-4c5c-82c3-489f5effcfe4','觀邸報','張自明','宋','宋诗','song-poetry','','[]','西風颯颯雨瀟瀟，小小人家短短橋。',32,'全唐诗/poet.song.191000.json','["西風颯颯雨瀟瀟，小小人家短短橋。", "獨倚闌干數鵝匹，一聲孤雁在雲霄。"]'),
('9322314f-e9da-4d12-843d-4628021de4dc','和方信孺題雲崖軒','張自明','宋','宋诗','song-poetry','','[]','萬里風煙倚瘦藜，湘南曾自一登陴。',64,'全唐诗/poet.song.191000.json','["萬里風煙倚瘦藜，湘南曾自一登陴。", "雲崖知在宜山麓，水月傳誇古洞奇。", "四字丹書無夢見，千峰蒼玉有誰詩。", "門前繫馬松陰下，鴉背斜陽影屢移。"]'),
('85fdcf70-3ec8-46a8-882f-ee814d079b9d','遊朝陽洞次孫機宜韻  其一','張自明','宋','宋诗','song-poetry','','[]','綠野年來喜有秋，行春到處小淹留。',64,'全唐诗/poet.song.191000.json','["綠野年來喜有秋，行春到處小淹留。", "朝陽亭上初披霧，水月巖中更枕流。", "竹徑不容周俗駕，桃蹊還泊晉漁舟。", "遨頭自愧非元老，濫總師干乏壯猷。"]'),
('cd3ea45a-cd9b-4800-9a88-2e15d7c54136','遊朝陽洞次孫機宜韻  其二','張自明','宋','宋诗','song-poetry','','[]','乘軺初至憶前秋，豈意持麾尚此留。',64,'全唐诗/poet.song.191000.json','["乘軺初至憶前秋，豈意持麾尚此留。", "立屋得僧成宴喜，遊山如謝欠風流。", "勸酬同把菊花盞，來往自操蓮葉舟。", "向晚洞門煙漸鎖，祗應歸興更宜猶。"]'),
('b44c6470-4101-4b82-a451-8f29fa2292b5','水月洞','張自明','宋','宋诗','song-poetry','','[]','癸水江頭石似浮，銀河影裏月如鈎。',64,'全唐诗/poet.song.191000.json','["癸水江頭石似浮，銀河影裏月如鈎。", "無人弄杵看蟾兔，有客乘槎訪斗牛。", "自古鵲橋傳七日，何年桂子落三秋。", "金輪待欲長無缺，玉斧仍須妙手修。"]'),
('4aa8f8e7-c11e-4365-a7e4-a5046bff0799','棲霞洞','張自明','宋','宋诗','song-poetry','','[]','玉洞沉沉鎖碧虛，月華曾伴日華居。',64,'全唐诗/poet.song.191000.json','["玉洞沉沉鎖碧虛，月華曾伴日華居。", "刀圭影觸金丸彈，蟬蛻形留錦鯉魚。", "舊隠已荒三徑草，仙人忽授數行書。", "丹霞自有棲真處，十里松風可跨馿。"]'),
('c1d6d31f-51c0-4c2b-8103-a2c14e248a97','遊華景洞','張自明','宋','宋诗','song-poetry','','[]','拂破蒼苔覓舊題，五言覓得晚唐詩。',64,'全唐诗/poet.song.191000.json','["拂破蒼苔覓舊題，五言覓得晚唐詩。", "巖光人憶遺名好，華景天開一段奇。", "鐵鎖掣關躔壁壘，玉梯穿路透瑶池。", "古心未展閒游戲，慙愧平生華子期。"]'),
('3db6387a-7191-4f68-b737-381667a25fed','清秀山次韻','張自明','宋','宋诗','song-poetry','','[]','甲子循環各一時，又逢青犬護巖扉。',64,'全唐诗/poet.song.191000.json','["甲子循環各一時，又逢青犬護巖扉。", "金墉城鎖瑶池苑，蒼玉樓鋪錦地衣。", "萬里西風生木末，數聲湘竹叫雲歸。", "明朝天上秋期近，問訊河邊織女機。"]'),
('e1e8d2da-0cff-476d-aaf5-0067035ce887','龍隠菴','張自明','宋','宋诗','song-poetry','','[]','南山山北北山南，一洞中分路口三。',64,'全唐诗/poet.song.191000.json','["南山山北北山南，一洞中分路口三。", "孤鶴叫雲聲自遠，懶龍慳雨睡方酣。", "襄公淡墨留蒼壁，太史高風拂翠嵐。", "百尺巖前清絕地，道人先我著茅菴。"]'),
('19cb70a7-3ef7-4ae6-9791-428ba0744a1a','白龍洞','張自明','宋','宋诗','song-poetry','','[]','白龍洞口白龍臺，一俯南天眼豁開。',32,'全唐诗/poet.song.191000.json','["白龍洞口白龍臺，一俯南天眼豁開。", "蒼壁漫題三數字，後人還笑我曾來。"]'),
('98d71650-efcb-4e8f-ad01-f703596df783','丹霞巖','張自明','宋','宋诗','song-poetry','','[]','玉玲瓏外玉崔巍，曾與三賢識面來。',32,'全唐诗/poet.song.191000.json','["玉玲瓏外玉崔巍，曾與三賢識面來。", "自有此山纔有此，遊人于此合裴回。"]'),
('a63e51d4-31fd-47da-b273-170b7b42ae5b','小殊山','上官渙酉','宋','宋诗','song-poetry','','[]','雙岫西南聳，東山小更殊。',48,'全唐诗/poet.song.191000.json','["雙岫西南聳，東山小更殊。", "形分閩嶺秀，名自隠翁呼。", "日映光濃淡，雲深色有無。", "須憑恕先手，畫作遠山圖。"]'),
('860130d1-0e35-425a-bd70-6ff2b0c1822c','擬西北有高樓','吳泳','宋','宋诗','song-poetry','','[]','高樓何岧嶤，一柱西北隅。',96,'全唐诗/poet.song.191000.json','["高樓何岧嶤，一柱西北隅。", "橫當子午道，峻直參井墟。", "曲瓊卷飛霞，儼儼僊人居。", "上通三重階，下蔭十二衢。", "傍樓玉簫女，織翠紛華裾。", "僊人顧之笑，授以青琅書。", "遡言欲從之，媒拙而理疎。", "丹梯目成久，須憑大垂手。"]'),
('a3badc77-f1c9-4052-a7f6-0962eb434233','夫遠征','吳泳','宋','宋诗','song-poetry','','[]','采蘩浴春蠶，夫婿今遠離。',120,'全唐诗/poet.song.191000.json','["采蘩浴春蠶，夫婿今遠離。", "貧無金釵別，愁有玉筯垂。", "朝同火伴去，莫獨衾裯隨。", "百夫十夫長，千里萬里期。", "去期日已遠，征郎不顧返。", "生理日就貧，歲年亦云晚。", "雖有乳下男，不能充夫丁。", "昨日府帖下，籍已書其名。", "官軍獨備北，頗恤東西民。", "勿言征錢輕，抽徵將到人。"]'),
('1f389146-1ad8-4560-b9e1-744f76fe84f4','采葛行','吳泳','宋','宋诗','song-poetry','','[]','黄葛溪上生，青條谷中垂。',96,'全唐诗/poet.song.191000.json','["黄葛溪上生，青條谷中垂。", "薄言采其絲，緝彼綌與絺。", "縫作公子裳，遠寄閨人思。", "絺兮凄以風，不值當暑時。", "輕鮮未及御，棄置忽若遺。", "雖則遭棄捐，肯爲風雨移。", "朝暮蒙楚中，采采以慰饑。", "君看葛婦歌，嘗膽味若飴。"]'),
('ea921d4b-a52a-4d3d-a4fe-cb20eb24bf89','桂','吳泳','宋','宋诗','song-poetry','','[]','南之山叢叢，桂樹生也直。',120,'全唐诗/poet.song.191000.json','["南之山叢叢，桂樹生也直。", "朱華自成林，不雜衆芳植。", "上有青鸞棲，因之爲羽翼。", "移根上林苑，零露滋曉色。", "豈不罹凝寒，高標竦孤特。", "丹心能自渥，身性不加飾。", "所以離騷詞，嘉其秉炎德。", "相觀穹壤間，人統形氣識。", "陽根爲剛明，陰質爲闇塞。", "靈均莫能招，聊與花辯惑。"]'),
('9e2a462b-67ba-40f1-909b-450cd82afbc6','都大華文監丞權府事之明年天子詔將直禁近邦之人有以三瑞爲獻者曰雙蓮曰岐麥曰九穗禾皆斯世之上瑞而萃於一時人目之以爲盛遂采民謠集成歌頌曲三首以紀其美','吳泳','宋','宋诗','song-poetry','','[]','短短菰蒲洲，陰陰葭菼陂。',96,'全唐诗/poet.song.191000.json','["短短菰蒲洲，陰陰葭菼陂。", "有斐嘉芙蓉，雙蒂媚漣漪。", "如龍舒兩娥，如沅湘二妃。", "豈伊玉池種，而乃生污泥。", "斑然爛雲錦，襲人芳菲菲。", "兩美諒必合，佳人製爲衣。", "下承朝露滋，上戴夕日輝。", "駕言折芳馨，歸以遺所思。"]'),
('c4d9cfb1-e575-4dd0-82de-980f0af0e73e','詠懷','吳泳','宋','宋诗','song-poetry','','[]','何草秋不枯，何葉秋不黄。',96,'全唐诗/poet.song.191000.json','["何草秋不枯，何葉秋不黄。", "白露以潤之，薿薿含晶光。", "幽蘭自華滋，時菊仍菲芳。", "粲粲園中葵，亦得晞朝陽。", "被恩有如此，後時果何傷。", "惟有警夜鶴，庭前獨旁皇。", "豈不欲九臯，翅翎莫能長。", "湛湛被露斯，幽吟遂成章。"]'),
('890cce72-5aa2-4362-b1f4-dc521962c600','送新蓬州程倅  其一','吳泳','宋','宋诗','song-poetry','','[]','美人其猶龍，渴飲金泉水。',84,'全唐诗/poet.song.191000.json','["美人其猶龍，渴飲金泉水。", "水狹又飛去，一息蓬池耳。", "是時天氣清，衆綠事盥洗。", "遐征溘埃風，長袂躡螭尾。", "天階甫一尺，民社猶千里。", "還須手帝澤，爲俗洗瘡痏。", "餘力裁新詩，或可代封匭。"]'),
('8f28760f-7b01-4d03-864c-a97637614a27','送新蓬州程倅  其二','吳泳','宋','宋诗','song-poetry','','[]','宛宛黄柳絲，錐錐雜花垂。',84,'全唐诗/poet.song.191000.json','["宛宛黄柳絲，錐錐雜花垂。", "柳解織別愁，花能送春歸。", "思君遠行邁，遊子心依依。", "有絃不解揮，有鏡不復治。", "豈是真不能，持此欲遺誰。", "河梁此時曲，淚爲生別滋。", "但期如水萍，所寄良不移。"]'),
('29b2385a-3649-4b48-8135-867dc1d66bcb','送陳和仲常博倅嘉禾  其一','吳泳','宋','宋诗','song-poetry','','[]','柳色媚別駕，桐花夾行舟。',48,'全唐诗/poet.song.191000.json','["柳色媚別駕，桐花夾行舟。", "慈湖一片心，不上富貴鈎。", "撇却雲霧窗，分渠月波樓。", "但有月長清，何妨波漫流。"]'),
('686e2632-6d40-4508-a0c2-2fe0557b4984','送陳和仲常博倅嘉禾  其二','吳泳','宋','宋诗','song-poetry','','[]','俗士騎戶限，癡官摸床脣。',48,'全唐诗/poet.song.191000.json','["俗士騎戶限，癡官摸床脣。", "名節與官爵，豈以全畀人。", "子方貴良貴，我亦仁景仁。", "終始議論間，但保一色醇。"]'),
('ab65ad37-9f6e-4f5e-b091-3cee9c24cb47','送陳和仲常博倅嘉禾  其三','吳泳','宋','宋诗','song-poetry','','[]','未及與君別，先歌送君詩。',48,'全唐诗/poet.song.191000.json','["未及與君別，先歌送君詩。", "浙西數年來，風景非昔時。", "紅蠶不上箔，青麥空生陂。", "六經政之本，無用別出奇。"]'),
('11b51e40-3b24-4fe7-bb1c-b9409fd45078','送長兒槃赴金陵典斛  其一','吳泳','宋','宋诗','song-poetry','','[]','皤皤六十翁，碌碌三男子。',96,'全唐诗/poet.song.191000.json','["皤皤六十翁，碌碌三男子。", "阿柴冠尚癡，阿㭲晬欲死。", "槃也年未彊，早爲貧出仕。", "家庭所訓誨，仕亦當念此。", "敬則能蒞官，敏則能决事。", "事長如嚴師，擇交必端士。", "僮亦人子耳，勿以盛氣使。", "只效龍伯高，芳名播青史。"]'),
('45bb062d-fc94-4d47-a57c-04bd8bf5cca8','送長兒槃赴金陵典斛  其二','吳泳','宋','宋诗','song-poetry','','[]','悲莫悲生離，老至悲轉切。',84,'全唐诗/poet.song.191000.json','["悲莫悲生離，老至悲轉切。", "阿爹領賓送，諸母持酒別。", "大婦前致辭，忽忽顔不悅。", "歸來眎季女，一夕亦永訣。", "人事長如此，有懷向誰說。", "淚緣親愛滋，心以憂患折。", "去去勿重陳，秦淮對明月。"]'),
('9ea67040-6837-4387-b3ea-d8a5020a264b','送長兒槃赴金陵典斛  其三','吳泳','宋','宋诗','song-poetry','','[]','仕歷四千石，官聯六尚書。',84,'全唐诗/poet.song.191000.json','["仕歷四千石，官聯六尚書。", "耕無田二頃，居無宅一區。", "余豈不念子，皇皇事田廬。", "多藏損其志，厚殖益爾愚。", "貧乃好消息，此言誠不迂。", "子官視庾氏，俸廩頗有餘。", "疎花會結果，小水長通渠。"]'),
('ea3137db-6c19-4f47-a1dc-75869718e3b4','送長兒槃赴金陵典斛  其四','吳泳','宋','宋诗','song-poetry','','[]','援以書戒子，子竟不若翁。',84,'全唐诗/poet.song.191000.json','["援以書戒子，子竟不若翁。", "陶以詩責兒，兒只如頑童。", "房公豈不智，集此書屏風。", "堂基未及搆，手澤俱成空。", "乃知貴胄門，美業真難終。", "子雖有良質，須用磨琢功。", "射御亦是學，不妨隨元戎。"]'),
('6a12152f-fc47-4f34-9b53-c61320996285','送長兒槃赴金陵典斛  其五','吳泳','宋','宋诗','song-poetry','','[]','玄雲拖榆塞，白露塗楓林。',84,'全唐诗/poet.song.191000.json','["玄雲拖榆塞，白露塗楓林。", "靡靡秋未夕，邊馬已南侵。", "子方從軍去，川陸迥且深。", "虎兕嗥曠野，猩猱嘯高岑。", "獨見金城外，迎人柳陰陰。", "主人敬愛客，秉義如斷金。", "好將少年行，轉作節婦吟。"]'),
('2e2365be-95db-4783-91dd-c88dc0384abf','壽魏鶴山  其一','吳泳','宋','宋诗','song-poetry','','[]','人生瀛海內，中氣胚腪之。',96,'全唐诗/poet.song.191000.json','["人生瀛海內，中氣胚腪之。", "真元會清淑，間代儲英奇。", "扶摇六月息，濯羽於咸池。", "冰壺貯虛明，璧玉含清輝。", "阿閣引鳳巢，小山結桂枝。", "肯遺金門步，乞取青藜歸。", "要福不椒醑，延年不瓊糜。", "至仁彌爾性，純嘏無窮期。"]'),
('90db2e25-1210-49aa-95e9-b341b413bbbb','壽魏鶴山  其二','吳泳','宋','宋诗','song-poetry','','[]','濂溪雅愛蓮，程子樂觀魚。',96,'全唐诗/poet.song.191000.json','["濂溪雅愛蓮，程子樂觀魚。", "生機不停息，天理原平鋪。", "美人湖上來，挹繡天東隅。", "清氣蕩喧濁，德風振纖枯。", "人酣鶑花國，雨滿菜豆區。", "肯縻爾好爵，而奪渠貞符。", "鷹鸇好彈擊，乃謂鸞鳳疎。", "願言崇明德，永作國璠璵。"]'),
('5f42d70a-7580-43e1-9f6f-3e870743d15a','壽鄒都大','吳泳','宋','宋诗','song-poetry','','[]','大儀斡四運，環轉當初陽。',192,'全唐诗/poet.song.191000.json','["大儀斡四運，環轉當初陽。", "天根起自復，氣踵生以黄。", "卓然五陰中，標示君子祥。", "芳芸豈不馥，碩果終自香。", "有開南國彥，氣稟惟純剛。", "况逢子之半，弧矢射四方。", "浩然祖鄒人，清介如道鄉。", "源流義理熟，滋養苗脈長。", "自登蜀道來，玉節明於霜。", "潢池有佩犢，紫邏無羝羊。", "星回參井間，草木爛以光。", "種善如種禾，去惡如去稂。", "只從一念中，坰野皆斯臧。", "玉𥹋不用餐，石髓不用嘗。", "台背而兒齒，好德自爾康。", "笑渠役役者，日景以線量。"]'),
('d5ac9e76-12b2-40e8-9f5f-9b057bf07d09','壽楊崇慶二首  其一','吳泳','宋','宋诗','song-poetry','','[]','英英赤文鳳，生此岷之陽。',96,'全唐诗/poet.song.191000.json','["英英赤文鳳，生此岷之陽。", "覽輝孤竹根，振翼千仞岡。", "德音乃鸑鷟，下引鵷與凰。", "承旗從華蓋，吹玉朝紫皇。", "顧瞻朱丘深，殆似阿閣長。", "肯以令儀榘，而使繒弋傷。", "集須集桐花，食不食藻粱。", "竚看發丹咮，舜殿歌明康。"]'),
('b55eac5d-f8bb-4e4b-b209-d4b42e72b26e','壽楊崇慶二首  其二','吳泳','宋','宋诗','song-poetry','','[]','清露團火旻，素月分白道。',96,'全唐诗/poet.song.191000.json','["清露團火旻，素月分白道。", "三湖足秋色，天以賜賀老。", "紅蕖正酣酣，翠籊方稍稍。", "閒情觀池魚，生意玩庭草。", "旨酒常在壺，瑶琴弗離抱。", "靈臺儻清明，豈不長壽考。", "方朔謾竊桃，安期苦嘗棗。", "願言西風時，眠食常健好。"]'),
('8b871420-8090-42fe-bb2c-4227d19139c6','壽范漕  其一','吳泳','宋','宋诗','song-poetry','','[]','春山蕨方芽，春院桐始華。',48,'全唐诗/poet.song.191000.json','["春山蕨方芽，春院桐始華。", "暄風蕩紅紫，還似綠幄遮。", "老僊坐鹿園，凈眼閲歲華。", "會須乘五羊，結佩凌飛霞。"]'),
('0004ed27-b521-441d-8dd6-5d19715abca6','壽范漕  其二','吳泳','宋','宋诗','song-poetry','','[]','豫章富人物，山谷人中豪。',48,'全唐诗/poet.song.191000.json','["豫章富人物，山谷人中豪。", "雖從老坡來，頗服舂陵高。", "泰和善鼓琴，涪水不擬騷。", "安知百世士，於此還一遭。"]'),
('80d34883-2edb-4632-8c3b-f272e1a5663e','壽范漕  其三','吳泳','宋','宋诗','song-poetry','','[]','入窗月疎疎，滿坐春盎盎。',48,'全唐诗/poet.song.191000.json','["入窗月疎疎，滿坐春盎盎。", "事機儘盤錯，收入經濟藏。", "魚方在沸鼎，獨以袽沃漲。", "靜言平寇功，當置裴李上。"]'),
('3a9d1ffd-f5fe-4bf1-8e0c-fb3970d28f30','壽范漕  其四','吳泳','宋','宋诗','song-poetry','','[]','鷹鸇好彈擊，自謂居使之。',48,'全唐诗/poet.song.191000.json','["鷹鸇好彈擊，自謂居使之。", "鳳凰不鷙搏，羣狡亦莫欺。", "但使德意多，何用風采爲。", "西臺十六州，人自春熙熙。"]'),
('c2eb8183-8ec0-4339-91d0-32089ef33d24','壽范漕  其五','吳泳','宋','宋诗','song-poetry','','[]','方朔謾竊桃，安期苦嘗棗。',48,'全唐诗/poet.song.191000.json','["方朔謾竊桃，安期苦嘗棗。", "世間長生訣，自致元有道。", "碩果終是香，靈根不曾老。", "作詩頌僖公，俾爾彌壽考。"]'),
('b3f05349-9119-4d54-8081-2646fb0968c3','擬古三章留別果山同官  其一','吳泳','宋','宋诗','song-poetry','','[]','邊馬思北依，晨風思北飛。',84,'全唐诗/poet.song.191000.json','["邊馬思北依，晨風思北飛。", "役役會有還，之子胡不歸。", "欲歸又北征，適與風馬期。", "憂端來無方，人則莫之知。", "不傷道里遠，所惜光景移。", "肯以蘭桂心，化作秋草萎。", "行道各努力，吾亦從此辭。"]'),
('c5d0e9a0-05a5-450d-8bc9-dc2d60c7d908','擬古三章留別果山同官  其二','吳泳','宋','宋诗','song-poetry','','[]','巴之水泠泠，青山復成圍。',84,'全唐诗/poet.song.191000.json','["巴之水泠泠，青山復成圍。", "含暉排戶來，頗若有所思。", "謂雲爲無心，終日長不飛。", "謂草非有情，盍爲乎忘歸。", "凡物各有繫，余豈縻於斯。", "俯川觀魚泳，仰空看鵬垂。", "一笑有會心，釣弋何所施。"]'),
('5e86aa5e-b797-4bfd-bebd-9e9dbc26c4cb','擬古三章留別果山同官  其三','吳泳','宋','宋诗','song-poetry','','[]','同門二三友，星弁嘗蟬聯。',84,'全唐诗/poet.song.191000.json','["同門二三友，星弁嘗蟬聯。", "一日兩會面，三日一共筵。", "花時棋聲裏，雨夜詩籌前。", "斗酒相爲娛，餘歡則陶然。", "永言懷及茲，餘愁浩如山。", "未別已足惜，別後誰慰顔。", "陸揚未可俟，寄聲斷鴻邊。"]'),
('12b4f2db-b8b7-43e0-9df7-caf6daea93f9','用葵軒送定叟平時兄弟間首句送季永弟赴省','吳泳','宋','宋诗','song-poetry','','[]','平時兄弟間，如友相箴規。',204,'全唐诗/poet.song.191000.json','["平時兄弟間，如友相箴規。", "每於和順中，切切而偲偲。", "筆硯三十年，風雨無停披。", "草衣而糲食，穴坯而敗帷。", "子文實勝僕，而我先子飛。", "子不以脫穫，便廢鋤與犁。", "有文績如絲，有鋒利如錐。", "拓開大規橅，不作小榦枝。", "果然昇春官，粗愜心所期。", "對床味可永，今又征行西。", "此別固不惜，豈無深長思。", "庭萱日就蕪，門戶一線微。", "子若不努力，誰與相扶持。", "文章但平易，毋以驕出之。", "共登青雲程，了此一段奇。", "却歸坐北窗，脫去名利羈。", "於皇太極藴，力與求真知。"]'),
('f0cd0aad-b9e8-42fd-b9a2-f50df5e8fddb','送李雁湖大參赴遂寧  其一','吳泳','宋','宋诗','song-poetry','','[]','拍拍雁湖水，深深歸雁亭。',120,'全唐诗/poet.song.191000.json','["拍拍雁湖水，深深歸雁亭。", "雁歸三四年，相伴湖水清。", "燕私豈不樂，國爾終含情。", "龍章倏夜下，驚赴鷗鷺汀。", "鴻雁雙翥翰，眷焉乃東征。", "載辭龍鵠椒，復問鶑花程。", "輶軒騖華轂，高蓋羅翠旌。", "康屯豈無學，銷暴不以兵。", "蔚藍舊草木，再色新威明。", "寄聲受廛者，明府如父兄。"]'),
('406d930a-14b5-4cac-86b0-ede6d4e3ee48','送李雁湖大參赴遂寧  其二','吳泳','宋','宋诗','song-poetry','','[]','恢恢大儀中，扶立惟三綱。',132,'全唐诗/poet.song.191000.json','["恢恢大儀中，扶立惟三綱。", "國風怨以怒，王道蕩無章。", "栖栖魯東家，秉筆修天常。", "廉陛不亂紀，冠履不易方。", "斯今世運頹，禮義維楫亡。", "三邊且病痱，羣盜方鴟張。", "兵如潰隄螘，民甚赬尾魴。", "厲階倘不夷，零露將侵裳。", "李侯世柱史，識此治亂防。", "揮袂別廣筵，振衣登高岡。", "願言茂遠猷，挽河洒天狼。"]'),
('ab3dfb21-0116-45b1-827e-8c8caf924746','劉園九日燕同寮效陶謝體','吳泳','宋','宋诗','song-poetry','','[]','霜林剪生綃，煙樹織晴綺。',144,'全唐诗/poet.song.191000.json','["霜林剪生綃，煙樹織晴綺。", "萬寶新告成，百工亦休止。", "嘉辰屬南山，勝事如栗里。", "謬爲陶長官，寧惜此中醉。", "良朋况知心，健會不論齒。", "鴟夷自挈携，猩筆漫游戲。", "清歡別有趣，真樂本無味。", "菊花之隠逸，亦欲妃君子。", "獨於蕭艾中，保此生色睟。", "凉颸忽吹衣，白露皓如洗。", "兌隨數至剝，剝落從此始。", "擬將九九節，便作陽月紀。"]'),
('fc606031-3fa7-4da2-9188-a3ccab6b3d2e','九日閒居讀陶詩有懷  其一','吳泳','宋','宋诗','song-poetry','','[]','天蓋不住旋，日車不停馳。',84,'全唐诗/poet.song.191000.json','["天蓋不住旋，日車不停馳。", "西風下木葉，那復有靜時。", "造物尚爾勞，人生能無爲。", "我於大化中，縱浪何所羈。", "倦則熟午睡，饑則愛晨炊。", "既無大患及，亦無好爵縻。", "但得長如此，樂焉復何疑。"]'),
('fcff4ade-e2c0-4bea-a1bd-c04e5f171fb5','九日閒居讀陶詩有懷  其二','吳泳','宋','宋诗','song-poetry','','[]','虬龍能負熊，行雨雲霄間。',96,'全唐诗/poet.song.191000.json','["虬龍能負熊，行雨雲霄間。", "犛牛不執鼠，野性長在山。", "才者常苦勞，拙者常得閒。", "靜中閲物理，役役會有還。", "所以陶徵君，猛歇名利關。", "書不求甚解，褐不求常完。", "是中有真意，此外無戚顔。", "懷哉千載人，卷書一長嘆。"]'),
('f5090245-b3c8-4fdf-bbeb-d715fb5afc92','九日閒居讀陶詩有懷  其三','吳泳','宋','宋诗','song-poetry','','[]','閒意不在遠，吾廬自成趣。',84,'全唐诗/poet.song.191000.json','["閒意不在遠，吾廬自成趣。", "竹陰混午醉，菜甲疏曉露。", "庭草更不除，樹禽日相語。", "每繙架上帙，旋讀輒忘去。", "佳友或會心，往往談至莫。", "以茲率爲常，彌覺太多事。", "却思對床眠，尋味所樂處。"]'),
('d0f12c65-eebe-45a2-abb0-f7eb51f8efb6','九日閒居讀陶詩有懷  其四','吳泳','宋','宋诗','song-poetry','','[]','天地大廬舍，誰使渠滔滔。',84,'全唐诗/poet.song.191000.json','["天地大廬舍，誰使渠滔滔。", "擬如原卜居，卷屋皆波濤。", "又思囚山賦，匪虎吾狴牢。", "獨惟安樂窩，邵子差雄豪。", "駕言欲問津，蔽吾以蓬蒿。", "頗思振衣起，濁酒且自陶。", "一生任運耳，目送冥鴻高。"]'),
('789be3f0-8c2d-40d4-bf47-91147d8d8786','壽范潔齋二首  其一','吳泳','宋','宋诗','song-poetry','','[]','明河耿高樹，素月流澄瀛。',132,'全唐诗/poet.song.191000.json','["明河耿高樹，素月流澄瀛。", "嫋嫋來金風，秋意浩以盈。", "美人自西方，鍾此一氣清。", "如潭貯皎潔，如室生虛靈。", "姱節麗有暉，高情澹無營。", "昔含雞舌香，曾以鳳咮鳴。", "不登金張館，嘗抱箕濮情。", "倏焉冰山銷，揭若黄道明。", "衆星已牢落，太白猶光熒。", "英風自骨鯁，心事元夷平。", "會須朝紫皇，提筆福蒼生。"]'),
('cfed79ef-032a-4c83-bd1d-1566bded7758','壽范潔齋二首  其二','吳泳','宋','宋诗','song-poetry','','[]','玉山一何高，堂與青雲齊。',132,'全唐诗/poet.song.191000.json','["玉山一何高，堂與青雲齊。", "上連寶臺峻，下瞰金璧低。", "中有二老僊，駕鶴俱不歸。", "苔封箕山碣，霧濕太史題。", "豈期芸省郎，再析侯藩珪。", "芳猷紹前印，英氣截雲霓。", "理亂如理繩，牧民如牧羝。", "燕開登南樓，就以雲作梯。", "喜年玩秋稼，撫物觀春荑。", "不貪老氏寶，不秘莊生倪。", "至仁彌爾性，壽齒今復齯。"]'),
('db35ba65-93e0-4d44-ba8f-0bfbc567cfb0','題承天心老萬佛閣','吳泳','宋','宋诗','song-poetry','','[]','我聞諗禪師，斷薪接繩床。',156,'全唐诗/poet.song.191000.json','["我聞諗禪師，斷薪接繩床。", "楊岐初住時，撒雪滿屋堂。", "庭松下法子，缾水注道漿。", "看來古佛心，不爲屋有亡。", "心公自別宗，眼碧髭又霜。", "更接十千衆，建此新道場。", "梯空插璇題，會海結寶方。", "自營不住心，每唱無底囊。", "如明珠走盤，如利刀截肪。", "以茲衆生故，苦爲諸佛忙。", "寥寥一貞境，渺渺萬法航。", "泥空竟成著，墮有終是盲。", "青燈落簷花，吾道千丈光。"]'),
('65dd73bf-e288-4363-a475-d29eda5a4946','和趙尚書無辯詩  其一','吳泳','宋','宋诗','song-poetry','','[]','夫子動以易，孟軻性其天。',48,'全唐诗/poet.song.191000.json','["夫子動以易，孟軻性其天。", "或毀或沮之，於我何加焉。", "天地猶有憾，伊人得無言。", "笑彼狥人者，區區欲求全。"]'),
('fc58f2a0-bdd5-4468-8122-4ba0568c97ff','和趙尚書無辯詩  其二','吳泳','宋','宋诗','song-poetry','','[]','熱不棲惡木，渴不飲盜泉。',48,'全唐诗/poet.song.191000.json','["熱不棲惡木，渴不飲盜泉。", "佳兵不祥器，只爲名使然。", "孔明桑百株，楊子田一廛。", "靜樂豈無此，行藏却由天。"]'),
('dfc8a390-5fd8-43dd-ab07-7693b2d5d6e2','和趙尚書無辯詩  其三','吳泳','宋','宋诗','song-poetry','','[]','猘犬吠漢月，黄雲塞江天。',48,'全唐诗/poet.song.191000.json','["猘犬吠漢月，黄雲塞江天。", "江淮我家門，守地何擇焉。", "婦嘗勸減竈，苦口爲母言。", "早使言得行，家門更安全。"]'),
('a41ab9d3-cc56-46b3-afea-888bcb3bfe05','和趙尚書無辯詩  其四','吳泳','宋','宋诗','song-poetry','','[]','詞人工爲文，瀑瀑如飛泉。',48,'全唐诗/poet.song.191000.json','["詞人工爲文，瀑瀑如飛泉。", "辯士說利害，燄燄火始然。", "浮華不經實，胡取三百廛。", "吾生信拙爾，道勝還諸天。"]'),
('c5267c56-703a-429d-b9c1-3654ff609057','程順子升齋','吳泳','宋','宋诗','song-poetry','','[]','雨養焦穀芽，清晨勃然興。',156,'全唐诗/poet.song.191000.json','["雨養焦穀芽，清晨勃然興。", "風入春筍節，一夕長數層。", "地道元敏樹，生意實可徵。", "一息不滋長，枯荄莽丘陵。", "所以務學者，進德長如登。", "禮義所封植，忠和所薰蒸。", "湛然清明氣，於此中夜存。", "德盛仁既熟，始如日之升。", "今人廢下學，乃以高自矜。", "譬之凌霄花，霄竟不可凌。", "子歸且近思，從下觀上騰。", "謙謙以自牧，洞洞如不勝。", "舜顔亦人耳，毋謂人鮮能。"]'),
('46e43898-30e1-4d98-b35c-85178781cb03','和曹憲金華山韻上李雁湖  其一','吳泳','宋','宋诗','song-poetry','','[]','楚臺快談風，梁園騁歌雪。',48,'全唐诗/poet.song.191000.json','["楚臺快談風，梁園騁歌雪。", "濫觴起九章，流波到七發。", "雕空竟何事，如以紙帖月。", "巽巖錦褧衣，雁湖木霏屑。"]'),
('256ef7a6-1f05-4757-bba6-3484f44141b3','和曹憲金華山韻上李雁湖  其二','吳泳','宋','宋诗','song-poetry','','[]','百卉冬具腓，喬松立霜雪。',48,'全唐诗/poet.song.191000.json','["百卉冬具腓，喬松立霜雪。", "老枝自擎重，既晚逾秀發。", "勁挺真大臣，回邪走妖月。", "金非百鍊剛，那不因翠屑。"]'),
('6d5351bc-5c24-4050-bc57-746816a789ef','和曹憲金華山韻上李雁湖  其三','吳泳','宋','宋诗','song-poetry','','[]','浮名鏡邊塵，驕氣爐上雪。',48,'全唐诗/poet.song.191000.json','["浮名鏡邊塵，驕氣爐上雪。", "胡爲認而有，引滿猶不發。", "有懷東方人，書眼高照月。", "紓徐如行雲，去就不爾屑。"]'),
('9229db9a-fb4c-4403-b6eb-50490295e713','和曹憲金華山韻上李雁湖  其四','吳泳','宋','宋诗','song-poetry','','[]','奔鯨甫息波，猘子還吠雪。',48,'全唐诗/poet.song.191000.json','["奔鯨甫息波，猘子還吠雪。", "憂端壓不住，耿耿及明發。", "師費輒千金，糧儲亡三月。", "智哉陶士行，先貯頭與屑。"]'),
('f6e5b79b-3ef7-42a8-8bc0-22eee5e7faca','和曹憲金華山韻上李雁湖  其五','吳泳','宋','宋诗','song-poetry','','[]','椅梧未成琴，脩幹埋積雪。',48,'全唐诗/poet.song.191000.json','["椅梧未成琴，脩幹埋積雪。", "嶰竹斷成律，其竅春自發。", "所遇時使然，誰與指摽月。", "仙翁急抽關，乞我雲母屑。"]'),
('477f35ac-d990-4ae0-81a3-52ca2bbd2c0b','七夕聞鵲  其一','吳泳','宋','宋诗','song-poetry','','[]','涷雨略洗車，炎暉復如磝。',96,'全唐诗/poet.song.191000.json','["涷雨略洗車，炎暉復如磝。", "桃笙眠未熟，屋角乾鵲噪。", "借問鵲何來，下上音載好。", "此聲固非惡，枉爲閒者告。", "適情便爲喜，喜不繇汝報。", "用靜則爲吉，吉不緣汝召。", "蕭牘尚我踈，行人爲誰到。", "勸子莫饒舌，移語朱門道。"]'),
('e0b897f3-20a5-4304-b6c4-9149771869a7','七夕聞鵲  其二','吳泳','宋','宋诗','song-poetry','','[]','黄姑西不娶，織女東未嬪。',132,'全唐诗/poet.song.191000.json','["黄姑西不娶，織女東未嬪。", "絳河咫尺間，可望不可親。", "欲遣烏作使，烏黠言未馴。", "欲詔鳳爲媒，鳳老咮不靈。", "獨有雕陵鵲，造梁河之漘。", "頻年事填河，頭禿弗愛身。", "胡然此今夕，疆疆語依人。", "熠燿渡機石，鷿鵜窺漢津。", "鵲昔號神女，至此不復神。", "緬思成橋事，謾語抑不倫。", "直須明河水，盡洗千秋塵。"]'),
('5abd7639-a3fc-4304-8af3-2ff7677168d3','變歐陽子秋聲','吳泳','宋','宋诗','song-poetry','','[]','銀河耿高樹，璧月流中庭。',84,'全唐诗/poet.song.191000.json','["銀河耿高樹，璧月流中庭。", "有聲西南來，厥聞浩以盈。", "或泠泠爲風，或殷殷如霆。", "元戎嘯中軍，猛士赴敵營。", "但聞人馬行，弗省金鐵鳴。", "天地始氣肅，乾坤亦塵清。", "豈有一草木，而不知秋聲。"]'),
('5adf2fce-f7bf-4c2f-980d-8ba10b7b8f80','和虞滄江見寄宴坐聞秋香','吳泳','宋','宋诗','song-poetry','','[]','春芳如麗人，驕色不肯除。',144,'全唐诗/poet.song.191000.json','["春芳如麗人，驕色不肯除。", "秋芳如高士，一味甘恬虛。", "我闥本洞然，香風來虛徐。", "滋蘭露承掌，延桂月滿裾。", "門巷柳濯濯，林塘竹疎疎。", "真意儼分列，遠心更莊舒。", "庭前兩好鶴，知幾年歲餘。", "或睨立倚窗，或飲於清渠。", "常恐緇塵染，回視根性初。", "蹇余滄江人，人豈不鶴如。", "起尋月中句，遥睇花外車。", "八表方雲昏，尚無返莊廬。"]'),
('713f3016-f852-4027-9ab9-5cfc4940ee9e','塞雁','吳泳','宋','宋诗','song-poetry','','[]','鴛鴦在魚梁，在在能戢翼。',108,'全唐诗/poet.song.191000.json','["鴛鴦在魚梁，在在能戢翼。", "黄鳥止丘隅，止止得所息。", "相彼雁與鴻，胡然生塞北。", "城暗候火驚，雲低空弦逼。", "官軍夜擊鼓，奴或告之亟。", "師老糧莫支，健兒恐烹食。", "哀鳴號窮邊，莽是狐兔窟。", "天地生爲心，曷使至此極。", "所以周宣詩，矜人要安集。"]'),
('402bbafb-73fc-45d5-aa17-749c92698cc1','送游景仁夔漕分韻得喜字','吳泳','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','桐花繁欲垂，柳色澹如洗。',84,'全唐诗/poet.song.191000.json','["桐花繁欲垂，柳色澹如洗。", "深谷艤行舟，怱怱春莫矣。", "廬山蕨已肥，荆渚魚正美。", "提携赤藤杖，炊煮白粲米。", "佳處有會心，歲月不須紀。", "繫船且夷猶，却待荻花水。", "江平風浪澄，再與歌至喜。"]'),
('d91e3fb0-341e-4589-8abb-87c276b70809','送鮮于漕  其一','吳泳','宋','宋诗','song-poetry','','[]','文字微妙訣，到底元平夷。',96,'全唐诗/poet.song.191000.json','["文字微妙訣，到底元平夷。", "詞人不能工，變怪生崛奇。", "汶上大夫者，得法靈均師。", "修辭滋其平，不以怒出之。", "白雲自多態，流水長清漪。", "作者云已往，知者其爲誰。", "九誦的子孫，八鸞行康逵。", "天將龢其聲，復見風騷遺。"]'),
('41bf2c52-0257-47c3-8b1a-c451a60de2f2','送鮮于漕  其二','吳泳','宋','宋诗','song-poetry','','[]','樹德必欲滋，去疾必欲除。',96,'全唐诗/poet.song.191000.json','["樹德必欲滋，去疾必欲除。", "世人亡分明，蒿蘭同一鋤。", "鳳兮德之美，誰不相稱譽。", "翻韝下霜雲，義蓋非鶻如。", "煌煌繡衣彩，炯炯清冰壺。", "衣以將直指，冰以勵廉隅。", "持此踰二年，相視如一初。", "去去登烏府，昏鴉遶林呼。"]'),
('ec20559a-9ff2-466d-974f-b2a7c2c07b37','蹇應叔自宜興寄近詩和馬字韻  其一','吳泳','宋','宋诗','song-poetry','','[]','仲連本策士，元亮非隠者。',48,'全唐诗/poet.song.191000.json','["仲連本策士，元亮非隠者。", "舉世莫知我，懸車息其馬。", "艤船陽羨頭，停策計山下。", "山水自娛人，無煩絲竹寫。"]'),
('17723f1a-10b3-4b70-ac6f-6dc716bc161c','蹇應叔自宜興寄近詩和馬字韻  其二','吳泳','宋','宋诗','song-poetry','','[]','吾老百世休，輟書學耕者。',48,'全唐诗/poet.song.191000.json','["吾老百世休，輟書學耕者。", "祈年占土牛，喜雪掘玉馬。", "海鮝带鹵燒，谿蓴和豉下。", "却憶古蠶叢，晤言莫能寫。"]'),
('48633f34-3bb5-4e2a-82c7-39f922906a4c','天馬引','吳泳','宋','宋诗','song-poetry','','[]','隴西之野龍駒驤，追風脇月坤爲裳。',120,'全唐诗/poet.song.191000.json','["隴西之野龍駒驤，追風脇月坤爲裳。", "竚雲亭亭廣顙直，夾鏡炯炯雙瞳光。", "飯以玉山禾，飲以瑶池漿。", "自成骨格異赭白，活出神采遺玄黄。", "三千牝，十二閑，俛視但覺皮毛凡。", "飲江曾濡六轡濕，致遠又逐雙旌揚。", "牧則在坰野，貢則歸天潢。", "寫圖仍上穆天子，跛蹩但笑羣觝羊。"]'),
('edd2190a-5134-4fb7-b528-56c1e1460422','擬湖邊採蓮婦','吳泳','宋','宋诗','song-poetry','','[]','短裙纈蕖衣製荷，採蓮女兒凭船歌。',96,'全唐诗/poet.song.191000.json','["短裙纈蕖衣製荷，採蓮女兒凭船歌。", "歌酣弭棹解塵襪，微步演迤凌寒波。", "薄言采采湖之沚，買鏡無錢賤生理。", "遥知浪水不可照，只仗清流作知己。", "蓀爲橈，桂爲棹，脈脈環湖翠煙草。", "急歸掩關中夜思，欲致美人伊有道。"]'),
('008f9ceb-dac2-467b-92da-b4e3f3e8749f','促促詞','吳泳','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','促促復促促，急柱危絃無好曲。',110,'全唐诗/poet.song.191000.json','["促促復促促，急柱危絃無好曲。", "樂日常少苦日多，男耕女桑長不足。", "麥方在場綃在軸，里正登門田吏趣。", "東隣女兒當窗看，西家阿㜷闌道哭。", "閒時輸官猶自可，况是兵符急如火。", "近聞官家榜村路，運糧多要人夫去。", "妾貧猶足備晨炊，不願身爲泰山婦。"]'),
('22d5bc46-46a7-4bee-a150-ac62fef794a3','獸之窮','吳泳','宋','宋诗','song-poetry','','[]','獸之窮，逼我牆，韓盧走兔無窟藏。',108,'全唐诗/poet.song.191000.json','["獸之窮，逼我牆，韓盧走兔無窟藏。", "江麋假息尚撲朔，穴鼠無技猶張皇。", "我𩚵豈不甘，我纓豈不長。", "貍步張侯虎爲落，𤜵未及獻弓先亡。", "獸之窮，莫抵當，澤虞不戒專諸忙。", "春蒐猶禁塞榆白，秋戰不耐涇水黄。", "昔聞養鷹志在逐，無使飽食棲平岡。"]'),
('2f464fc3-8282-4f24-8573-be4e9ca3c61e','梁父吟','吳泳','宋','宋诗','song-poetry','','[]','梁父吟，維山高高維水深。',116,'全唐诗/poet.song.191000.json','["梁父吟，維山高高維水深。", "白石爛兮飯牛曲，滄浪清兮鼓枻音。", "艾薪豈不賢，反被妻子瘖。", "投筆豈不壯，交友不諒心。", "用則宗彜在東序，不用土缶埋汾陰。", "梁父吟，問梁父，青史功名在何處。", "長須旨酒置高堂，莫使青葵委零露。", "臨風惝恍歌一曲，鳳舞鸞翔應簫玉。"]'),
('c81686c6-d710-44b0-bcef-c3e87d1c9e79','漢中行','吳泳','宋','宋诗','song-poetry','','[]','漢中在昔稱梁州，地腴壤沃人煙稠。',380,'全唐诗/poet.song.191000.json','["漢中在昔稱梁州，地腴壤沃人煙稠。", "稻畦連陂翠相屬，花樹遶屋香不收。", "年年二月春風尾，戶戶澆花壓醪子。", "長裙闊袖低蓋頭，首飾金翹競奢侈。", "自從鐵騎落武休，勝事掃迹隨江流。", "道傍人荒鳥滅沒，獨有梨花伴寒食。", "君不見當年劫火然，携老扶幼奔南山。", "又不見拗項橋邊事，七八千兵同日死。", "死則義魄猶有歸，存則偷生漫如此。", "三人共，一椀燈，通夜紡績衣鬅鬙。", "八口同，半間屋，煮𥻰椎冰常不足。", "家糧一石五券錢，一半入口一半官。", "男擔軍裝出邊去，女荷畚鍤填濠還。", "官知民貧當愛惜，兵者衛民貧不恤。", "且如今年春，又經征戰苦。", "風塵未動力已罷，殆以饑羊飼豺虎。", "梁山奕奕水湯湯，知他見幾玉節郎。", "昨日漢川過，香氣夾道花成行。", "還撾青鼉鼓，復擁白鵲旗，帳犀殿後車懸鴟。", "營中聞之暖挾纊，盡道節制吾父師。", "東軍本皆孝順兒，好在良牧綏牧之。", "太清魚不蕃，太緩琴不理。", "師中有吉當自求，度外無功更誰喜。", "秋風淅淅吹芙蓉，山童喚我歌漢中。"]'),
('c4a5f44d-1ecf-40da-901c-570c4d2121b2','堰上行上周憲','吳泳','宋','宋诗','song-poetry','','[]','堰上行，桃花灼灼春水生。',256,'全唐诗/poet.song.191000.json','["堰上行，桃花灼灼春水生。", "水纔一石泥數斗，彌漫滮池浸渠口。", "樹以淇園竹，菑以漢堤石。", "石填竹落知幾丁，駕作青霓千百尺。", "一夫搴茭前，一夫荷鍤去。", "旋燒香紙祭水庸，更酌村醪賽田祖。", "鹿頭北，海眼西，綿洛一带填淤肥。", "苧麻漚池禾稻長，雖有旱暵無凶饑。", "今年狼頭窺井絡，羅堰九星幾缺角。", "匪天十風五日雨，陸海將貧水維濁。", "上帝憫下民，親遣蒼水使。", "西門驂前白渠後，指畫田塍若鱗次。", "新堰舉，舊堰修，野媼含笑谿童謳。", "自言春種皆茁土，桔槹長閒卧畦圃。", "明朝百役非所知，且樂豐年踏車舞。", "燕泥新濕花雨斑，四牡趣嚮東郊還。", "地平天成九功敘，今秋都築沙堤路。"]'),
('3a55a598-df53-49cb-bb6d-f1ee962ef75c','贈星翁郭若水','吳泳','宋','宋诗','song-poetry','','[]','月臨南斗退之懼，宮直南箕蘇子憂。',132,'全唐诗/poet.song.191000.json','["月臨南斗退之懼，宮直南箕蘇子憂。", "片文隻字不經世，赤口白舌空招尤。", "我生之初函二氣，地則五行天五緯。", "羅計二宿括半天，太陰一星宅時位。", "郭生本是郭璞徒，推步太精言轉迂。", "按圖只說萬言錦，經野未辨天官書。", "大遊正照參井鄉，蚩尤不歛旗方張。", "瞥將巧歷莫推算，爲我占取峨眉太白何時康。"]'),
('c6b423e3-dd53-4150-a6d5-e4f5e1a454f5','遊大玲瓏小玲瓏','吳泳','宋','宋诗','song-poetry','','[]','小玲瓏，大玲瓏，平林突起羣玉峰。',164,'全唐诗/poet.song.191000.json','["小玲瓏，大玲瓏，平林突起羣玉峰。", "霜鉶剪取碧磈䃬，雷斧鑿破青嵌崆。", "自有此山生此石，鬼削天劖更無迹。", "泗濱浮出瑞玉磬，周廟橫陳古蒼璧。", "蒼官儼冠劍，翠官披琅玕。", "好風吹月來，光動九琳軒。", "守庵道人形野倨，白領方袍草爲屨。", "頗奇二士入洞來，引向高亭最幽處。", "他山豈無石，弄假不似真。", "平泉馬鹿跡何在，南墅甲乙名灰塵。", "說真辯假無時了，山童隔竹敲茶臼。"]'),
('dca4fdd0-1cb4-41b0-b98c-832fca60b9a4','洪都病中夢與太白同登峨嵋亭有賦','吳泳','宋','宋诗','song-poetry','','[]','翠浮天宇兩眉修，不著塵寰半點愁。',128,'全唐诗/poet.song.191000.json','["翠浮天宇兩眉修，不著塵寰半點愁。", "錦袍仙人去不返，乘月忽作斯亭遊。", "月懸水底不受捉，牛渚磯翻酒星落。", "氣湧如山白浪掀，聲悲動地終風作。", "我思弔古登翠微，點檢舊題無白詩。", "生平白眼睨力士，焉肯嫵媚歌峨嵋。", "楊林渡頭采石口，一處風寒幾兵守。", "寄語中流把柁翁，莫使江山落人手。"]'),
('f48b9779-4d5e-4a52-bdc1-82202a0471f3','壽范翁','吳泳','宋','宋诗','song-poetry','','[]','辛夷如雪芳事闌，飛絮卷地春風酣。',224,'全唐诗/poet.song.191000.json','["辛夷如雪芳事闌，飛絮卷地春風酣。", "連陂和雲割青麥，隔塢趁日繰紅蠶。", "今年夏氣清較早，雨後西山翠如掃。", "女兒負笈男带鋤，誇說皇華使家好。", "使家天上一角麟，手握雨露呵星辰。", "綠林無風草木靜，紫塞有備煙塵靖。", "鹿園鎮日長徙倚，心事如平一池水。", "蓀蘭不惜手種植，蕭艾依前力鋤薙。", "槐龍影轉花又黄，造化乃爲諸生忙。", "春闈法細靡罅縫，選吏親校如秤量。", "老僊自是文盟主，曾抱長蛟著繁露。", "好將鼻祖三昧法，直嚮金華講經去。", "有香不炷旃林香，有酒不酌瑶池觴。", "願公歲歲常壽考，賸寄詩筒祝難老。"]'),
('2437c871-aebf-41f5-acf4-fa6e4581c7ab','西湖訪梅','吳泳','宋','宋诗','song-poetry','','["\u897f\u6e56"]','欲休不休歲垂晚，似冷不冷霜復晴。',112,'全唐诗/poet.song.191000.json','["欲休不休歲垂晚，似冷不冷霜復晴。", "起撐湖船訪梅去，一點兩點藏林坰。", "主林無神花氣薄，樹影庚庚香漠漠。", "誰能細玩復與臨，靜處測破梅花心。", "橋西水北弄明月，醥酒獨對青山斟。", "自有此山無此客，富有他花無此格。", "西湖處士不可招，鴉點孤村暮雲碧。"]'),
('b5d9c004-5c37-48bc-b429-5ce54bfdb00c','祁山歌上制帥聞敵退清水縣作','吳泳','宋','宋诗','song-poetry','','[]','祁山之西當太白，戰士彎弓抱明月。',314,'全唐诗/poet.song.191000.json','["祁山之西當太白，戰士彎弓抱明月。", "散燒煙火夜宿兵，遥見狼頭一星滅。", "明朝探騎前來報，爲言敵死秦川道。", "牌使前呼大隊回，鵝車砲坐埋青草。", "黄河口，清水頭，水聲嗚咽河不流。", "軍中遺言更慘酷，靈夏名王亦屠戮。", "中間被掠邊丁苦，牧放牛羊食禾黍。", "牛羊得食人轉饑，日想南朝拜降去。", "朝廷有道督府雄，三關之險風不通。", "健兒長鎗及馬腹，壯士勁弩當心胸。", "帳犀前把石門隘，遥望紅旗圍盡解。", "輿師等第喝銀帛，三將同時賜金带。", "凱還吹落桃花風，捷書屢奏甘泉宮。", "綸巾蕭然羽扇凈，一字不說平夷功。", "離鴻迤邐集中澤，鴉噪山田忙種麥。", "七方新堡高插雲，腐鼠何能更相嚇。", "書生每夕繙青史，爭戰場中看千古。", "狸亡虎滅自有期，天道何嘗厭中土。", "夾城雲赤戈劍明，通衢夜白鐘鼓清，更待公歸戮力就太平。"]'),
('1cfd0c7c-7abc-4fd6-a421-8512bcd465f4','壽梁漕','吳泳','宋','宋诗','song-poetry','','[]','維日在婁春事殷，維桐始華天氣新。',188,'全唐诗/poet.song.191000.json','["維日在婁春事殷，維桐始華天氣新。", "亂紅遶樹綠幄均，櫻筍又薦冰盤珍。", "知是燕胎協卜、牛宿會辰，繡衣立當霄漢春。", "驪駕飛度天河津，帕中玉屑糧未陳。", "鏡裏寶月光逼真，廉如一條冰照人，健如九臯鶴離羣。", "舌根不道煙火塵，鼻端那受富貴熏。", "手探囊方皆木神，袖出薦紙生煙雲。", "兕觥祇酌春酒醇，衣佩更取秋蘭紉。", "民居安安鴻鴈賓，吏膽帖帖烏鳶馴。", "王母之桃莊生椿，寧如洙泗一字仁。", "願言福星當紫宸，光照鄰女長無貧。"]'),
('79d01fdc-0b65-4794-adf7-6d69cbce72f0','送李伯勇分教閬州','吳泳','宋','宋诗','song-poetry','','[]','明王不興威鳳衰，直筆無傳老麟死。',166,'全唐诗/poet.song.191000.json','["明王不興威鳳衰，直筆無傳老麟死。", "春秋大誼炳如日，讀者昏昏視爲史。", "濂溪之後伊川程，文字雖少源流真。", "抉開寶藏得胡子，一洗紙上千秋塵。", "伯兮有勇弗可遏，高閣諸儒祖河洛。", "羣玉洞見標月指，衆醉醒聞候風鐸。", "當年進書一布衣，能取天上清名歸。", "秋澄講幄玉色動，春拂祕館芸香霏。", "紅塵不踏東華路，綠綺還携閬風去。", "舟行若上離堆山，莫把魯公雄文勁筆埋沒蒼苔間。"]'),
('94f6d971-37c4-47c2-9719-54dc7535fd54','瑞麥歌','吳泳','宋','宋诗','song-poetry','','[]','爰采麥矣岷之陽，麥秀蘄兮登我場。',124,'全唐诗/poet.song.191000.json','["爰采麥矣岷之陽，麥秀蘄兮登我場。", "岐岐而生自天産，兩兩而並維星祥。", "我行其野逢酇長，酇長忻然持穗往。", "自言此穗實秀時，六稻俱垂惟麥仰。", "晉之四穟唐六岐，雖有其物無其時。", "我君聖武綏萬邦，我侯駿德爲藩維。", "君臣堯舜禹，十風五日雨。", "干戈偃息將兆和，拍手齊唱崆峒歌。"]'),
('8428abcc-2211-4693-800a-69b13cf20e67','同程季予遊李園和張仁溥','吳泳','宋','宋诗','song-poetry','','[]','頑雲不雨風稱雄，掃花晚坐蓬萊宮。',100,'全唐诗/poet.song.191000.json','["頑雲不雨風稱雄，掃花晚坐蓬萊宮。", "幅巾野服纔相逢，華茵解下金線狨。", "人道青田雙鶴、平輿二龍，笑揖羣彥時一中。", "百寮之山直叢叢，回廊窈窕庭陰濃。", "園禽語變春事空，水花色靜天機融。", "歸來笑傲掀短篷，溪澄月白聞笙鴻。"]'),
('28ff098d-d7a4-4b3a-ab65-312ab290d7bb','賦半齋送張清卿分教嘉定','吳泳','宋','宋诗','song-poetry','','[]','斗城將軍半段鎗，漢宮美人半額粧。',140,'全唐诗/poet.song.191000.json','["斗城將軍半段鎗，漢宮美人半額粧。", "碧眼禪僧坐空室，花雨半床雲半窗。", "道如大路皆可遵，不間不界難爲人。", "卓哉聖人門，猶惜二三子。", "冉求只向中道畫，季路僅及升堂止。", "窮山必到嵩華顛，窮水必極崑崙源。", "若非身心實造詣，未免口耳空啾喧。", "子歸試取羣書讀，飽秣吾駒飯吾僕。", "却將全體爲渠說，盪出峨眉半輪月。"]'),
('880e4c64-8afc-4880-b680-0f474942c396','八月十四夜神泉官滿再別同官','吳泳','宋','宋诗','song-poetry','','[]','有客有客白其馬，日倚垂楊問行者。',165,'全唐诗/poet.song.191000.json','["有客有客白其馬，日倚垂楊問行者。", "式微式微胡不歸，未歸滿耳聞別詩。", "斷絃再續情緒惡，別酒重稔味如蠟。", "袖中雖有金錯刀，滿鏡愁雲莫能割。", "是時月露秋平分，庭前喚月月不譍。", "就令喚得山頭月，照我離筵越愁絕。", "陶靖節，潘安仁，種秫滿畦花滿城。", "潘花陶酒總陳迹，不如昭文氏之琴不鼓無虧成。", "芭蕉潄潄連夜雨，桂子紛紛落庭戶。", "旅雁無儔顧影單，明朝且嚮龍巖去。"]'),
('027c9c8c-04ba-467f-b3e9-47873f872d0b','送毅夫總領淮西','吳泳','宋','宋诗','song-poetry','','[]','莫沽金陵酒，莫折金城柳。',188,'全唐诗/poet.song.191000.json','["莫沽金陵酒，莫折金城柳。", "但觀二十四橋月，夜夜凄凉照淮口。", "孤墉不下兵轉饑，河水淺狹紅賊窺。", "就今秋高不飲馬，安得會有休兵時。", "赤雲燒空秋岸闊，雨少潮低運溝涸。", "莫從局外鑒全勝，緊向棋心尋活著。", "昨夜歸來聞好語，大兒踏歌小兒舞。", "喜言邊敵歸故巢，且省沿邊轉般苦。", "邊民之苦自古然，其媼荷鋤翁戍邊。", "老翁無力助王國，但願主聖羣公賢。", "上卿奉使亦奇事，肯爲邊氓勞撫字。", "酒酣拂劍歌皇華，柂樓紅濕汀蓼花。"]'),
('0c98ab26-d6fc-4c96-89a4-4521e930cd59','新江行壽張憲亨泉','吳泳','宋','宋诗','song-poetry','','[]','君不見堯時伯禹作司空，應龍尾畫江道通。',388,'全唐诗/poet.song.191000.json','["君不見堯時伯禹作司空，應龍尾畫江道通。", "又不見秦時李冰作太守，犀牛厭勝水晶走。", "蜀江開鑿四萬八千載，二后英靈儼如在。", "雖然陵谷有變遷，水嚮東流不曾改。", "西岷山，南溷崖，神營化造如劃開。", "蜀人好怪漫弗省，龍豈能智犀豈能禳菑。", "年來江塞崖据險，水束三川激如箭。", "陽侯吸哦佛不靈，黑蠣磨牙蚖吐焰。", "五月尾，六月頭，瓜蔓水退，礬山水流。", "中間青沫最湍駛，風雨瞬息能湛舟。", "鮫人淵客弗敢睨，而况商婦能無愁。", "懷哉古人智如此，胡不鏟盡白險直使平如洲。", "使家河源來，弭節青衣國。", "橫槎展拓萬里天，力浚江南障江北。", "百夫荷鍤，千夫荷鋤，號召海若同鑿疏。", "經營不越四弦望，白練剪出澄江圖。", "輕軺晨興亦勞苦，繡爛衣明濕煙雨。", "不惟佛灘之耻可湔雪，名與離堆傳之萬萬古。", "乃知天地間，靡事不可爲。", "若鳥獸草木，驅虎豹象犀。", "藏冰肦冰凌人掌，出火內火烜氏司。", "吾身代天事，到手那得辭。", "决川道海亦常理，竈門老婢不慣駭且疑。", "好將新江水，都爲一洗之。"]'),
('2f1739c3-da9b-4439-9cf0-7ff522cfaf7e','和李憲使  其一','吳泳','宋','宋诗','song-poetry','','[]','關上青牛去，林間白鶴歸。',48,'全唐诗/poet.song.191000.json','["關上青牛去，林間白鶴歸。", "月函書味澹，霜浸道根肥。", "草樹連生色，魚梁閟殺機。", "晚年偏好易，落處是麻衣。"]'),
('4f7145e8-ab5f-4eb5-99da-c246d68fb6fa','和李憲使  其二','吳泳','宋','宋诗','song-poetry','','[]','比歲兵戈息，山民幸有秋。',48,'全唐诗/poet.song.191000.json','["比歲兵戈息，山民幸有秋。", "麥畦翻雨種，瓜圃带霜收。", "墐戶夕熏鼠，荷蓑晨飯牛。", "使家廉到骨，清議在鋤耰。"]'),
('563bbd94-0607-4ef4-aaf3-8e0f885b1ea0','和李憲使  其三','吳泳','宋','宋诗','song-poetry','','[]','春日成都寺，桐華一院芳。',48,'全唐诗/poet.song.191000.json','["春日成都寺，桐華一院芳。", "窗疎紅卷跋，焙煖雪吹香。", "論事惟三代，評詩宗晚唐。", "開編疑未瑩，今欲扣山房。"]'),
('36939d0c-00a7-4ff7-93e9-e0d319ec0b6a','送楊子達入國學','吳泳','宋','宋诗','song-poetry','','[]','鸞鳳久束咮，賢關時一鳴。',48,'全唐诗/poet.song.191000.json','["鸞鳳久束咮，賢關時一鳴。", "子今觀上國，志豈爲浮名。", "母線絲絲直，爺詩字字情。", "別離非所惜，回看錦衣榮。"]'),
('d971ae8e-e0b3-4160-adaf-eb9daec8e36f','雪夜','吳泳','宋','宋诗','song-poetry','','[]','雲蒸黄野潤，月瑩皓庭清。',48,'全唐诗/poet.song.191000.json','["雲蒸黄野潤，月瑩皓庭清。", "夜靜悄人迹，溪流皆雪聲。", "帳吹燈彩暗，爐撲火花明。", "遥想鷄人誤，鳴歌報六更。"]'),
('d5d36b10-b1d6-4b6c-a770-04a023687ddc','霅溪舟中讀唐人詩','吳泳','宋','宋诗','song-poetry','','[]','大雅聲纔息，騷人詞競興。',48,'全唐诗/poet.song.191000.json','["大雅聲纔息，騷人詞競興。", "語工終離道，味泊祇如僧。", "霜夜杜荀鶴，秋風張季鷹。", "撫編吟魄動，飛雨灑船燈。"]'),
('268886ef-43b5-44b2-9709-51a6adeda414','冬至','吳泳','宋','宋诗','song-poetry','','[]','閒居罕人事，慵把曆頭開。',48,'全唐诗/poet.song.191000.json','["閒居罕人事，慵把曆頭開。", "雷自地中復，風從天末來。", "絪縕初熟酒，的皪未開梅。", "道盡真光景，堯夫好秀才。"]'),
('df45ae4b-9b3d-4620-9ac7-ccb54c360ea2','挽羅宗卿','吳泳','宋','宋诗','song-poetry','','[]','曉月璿源澹，春風璧水香。',48,'全唐诗/poet.song.191000.json','["曉月璿源澹，春風璧水香。", "一條冰透骨，五色鳳鳴崗。", "翳彼菟裘老，傷哉寶鑑亡。", "囊封尚生意，今與日爭光。"]'),
('1d693235-6793-4b25-a75d-18c777382b9c','挽鄭文昌','吳泳','宋','宋诗','song-poetry','','[]','何代無豪傑，惟公氣獨剛。',48,'全唐诗/poet.song.191000.json','["何代無豪傑，惟公氣獨剛。", "束身同絞紟，遺訓闢緇黄。", "定力老逾壯，英魂凜不忘。", "蜀名省科調，猶說鄭文昌。"]'),
('b8bd939b-4c92-43da-96bb-d72f84b7d914','別歲','吳泳','宋','宋诗','song-poetry','','[]','故鄉於此時，釀熟歲豬肥。',48,'全唐诗/poet.song.191000.json','["故鄉於此時，釀熟歲豬肥。", "骨董羹延客，屠酥酒餉兒。", "竈塗醉司命，門貼畫鍾馗。", "多少傷懷事，溪雲带夢歸。"]'),
('9afd8300-38c3-49d5-b1bb-8e389427ed05','和制垣金泉山','吳泳','宋','宋诗','song-poetry','','[]','昔日南充縣，卑棲枳棘鸞。',48,'全唐诗/poet.song.191000.json','["昔日南充縣，卑棲枳棘鸞。", "道根隨境悟，屐齒過橋寒。", "夢覺松花白，重來鶴頂丹。", "僊翁梨棗熟，亦欲傅脩翰。"]'),
('7bb10311-ba08-4e0c-be88-d636d9d50de1','小雪','吳泳','宋','宋诗','song-poetry','','[]','卧病連三月，起來幾半人。',48,'全唐诗/poet.song.191000.json','["卧病連三月，起來幾半人。", "腕柔妨草聖，目眩隔花神。", "頹魄豈常望，殘芳不再晨。", "徘徊盼庭樹，猶喜小陽春。"]'),
('f9221c90-4221-442e-a2a9-8090bce982a6','壽李雁湖  其一','吳泳','宋','宋诗','song-poetry','','[]','間氣生賢哲，斯文擅正宗。',48,'全唐诗/poet.song.191000.json','["間氣生賢哲，斯文擅正宗。", "咮鳴直是鳳，時見恍猶龍。", "信史傳緗簡，元勳在鼎鐘。", "惟存霜後節，景仰彼高松。"]'),
('344702d5-14ef-4dd6-ab9d-5c6e43db0800','壽李雁湖  其二','吳泳','宋','宋诗','song-poetry','','[]','往在黄樞府，璇題護兩扉。',48,'全唐诗/poet.song.191000.json','["往在黄樞府，璇題護兩扉。", "剪除當路棘，紉補坐朝衣。", "風急操舟濟，江空擲釣歸。", "年年湖上雁，旭旦望南飛。"]'),
('0a55c5e6-cba7-4e60-b9d4-52dd385da28e','壽李雁湖  其三','吳泳','宋','宋诗','song-poetry','','[]','起從通德里，出守巽巖州。',48,'全唐诗/poet.song.191000.json','["起從通德里，出守巽巖州。", "上相先聲到，兇徒悍氣柔。", "鴻居新勞徠，鳥戶舊綢繆。", "已築沙堤路，歸歟贊大猷。"]'),
('31ab4d14-6cb8-4a6c-b981-40d4af431b63','壽李雁湖  其四','吳泳','宋','宋诗','song-poetry','','[]','金碧蒼巖下，神光射斗箕。',48,'全唐诗/poet.song.191000.json','["金碧蒼巖下，神光射斗箕。", "豆灰浮琯後，梅蘤破冰時。", "正是生申日，誰爲壽卯詩。", "今年真六一，說與醉翁知。"]'),
('d9fb3664-f903-49f2-a989-9d03c4a7bf45','和晏子忠  其一','吳泳','宋','宋诗','song-poetry','','[]','天地肇開闢，江山誰主盟。',48,'全唐诗/poet.song.191000.json','["天地肇開闢，江山誰主盟。", "岸深沙走白，石秀水含清。", "魚自春來美，猿雖曉不驚。", "汀洲生杜若，薄欲采其英。"]'),
('4e3ea2fc-79a0-4b24-b5fd-501049a1669b','和晏子忠  其二','吳泳','宋','宋诗','song-poetry','','[]','每逢耆舊問，誇說太平年。',48,'全唐诗/poet.song.191000.json','["每逢耆舊問，誇說太平年。", "橘柚三冬富，荷花萬頃聯。", "斷巖書姓氏，勝迹已蹄筌。", "羣盜方如蝟，渠鞭恐著先。"]'),
('f14be62a-7908-469c-a871-108cb805635b','和晏子忠  其三','吳泳','宋','宋诗','song-poetry','','[]','我往纔秋莫，君來恰歲寒。',48,'全唐诗/poet.song.191000.json','["我往纔秋莫，君來恰歲寒。", "離鴻書落莫，歸馬路平寬。", "白社論心易，文壇出手難。", "近來詩思澀，風雪立雕鞍。"]'),
('23420749-5dff-4154-aa13-452af251c74d','出關','吳泳','宋','宋诗','song-poetry','','[]','曉带鷄星出，春從鳥道餐。',48,'全唐诗/poet.song.191000.json','["曉带鷄星出，春從鳥道餐。", "霧漫旗彩壞，霜落劍花寒。", "天險今雖在，人謀昔所難。", "臨關能虎視，一亮亢曹瞞。"]'),
('bcac49e6-0bde-42c4-919c-99153e7de9ae','冬日','吳泳','宋','宋诗','song-poetry','','[]','四時平似準，冬日頗傷暄。',48,'全唐诗/poet.song.191000.json','["四時平似準，冬日頗傷暄。", "暖驟狂花坼，霜輕野草繁。", "林鳶饑跕水，山鬼暗窺垣。", "便擬懸車計，無人爲買園。"]'),
('d31ddf83-db32-42d6-8718-0b6dc38af437','霜朝','吳泳','宋','宋诗','song-poetry','','[]','欵乃湖歌斷，瓏璁晚色歸。',48,'全唐诗/poet.song.191000.json','["欵乃湖歌斷，瓏璁晚色歸。", "鷺翹窺水鏡，鴟凍泊垣衣。", "密坐懸書帳，清吟刮硯澌。", "歲寒誰耐久，獨有翠兄知。"]'),
('79d3ca42-7a2d-417b-897b-69fd34ffce26','壽胡興元三首  其一','吳泳','宋','宋诗','song-poetry','','[]','幾代貞元會，還生忠簡孫。',48,'全唐诗/poet.song.191000.json','["幾代貞元會，還生忠簡孫。", "清風拔薤本，愛日護葵根。", "疋馬馳周道，分公翰蜀門。", "保安橋上路，手滌瘴雲昏。"]'),
('743ed49d-437b-4c6b-8b73-fd351f366be6','壽胡興元三首  其二','吳泳','宋','宋诗','song-poetry','','[]','皂蓋開藩日，黄河洗甲時。',48,'全唐诗/poet.song.191000.json','["皂蓋開藩日，黄河洗甲時。", "柳陰承羽葆，花氣撲旌麾。", "兵悍須柔止，民碞莫勝之。", "麥頭如得雪，來歲可休師。"]'),
('59b1f593-ae80-42d5-8c54-a48bad262090','壽胡興元三首  其三','吳泳','宋','宋诗','song-poetry','','[]','耿耿三秋別，悠悠四月餘。',48,'全唐诗/poet.song.191000.json','["耿耿三秋別，悠悠四月餘。", "菊潭聞上壽，梅驛急馳書。", "簇蘤紅成陣，駢筵翠曳裾。", "封侯平四十，前路儘寬舒。"]'),
('f6d18a6f-1d33-42aa-8f1c-921bcd685a8e','壽丞相慶七十五首  其一','吳泳','宋','宋诗','song-poetry','','[]','幾代貞元會，重逢上相生。',48,'全唐诗/poet.song.191000.json','["幾代貞元會，重逢上相生。", "閲人冰鑑浄，遇事玉衡平。", "日月黄扉永，風塵紫邏清。", "勛名兼壽考，何必會耆英。"]'),
('c03e598b-2b55-4ad0-a18c-522eef09aad5','壽丞相慶七十五首  其二','吳泳','宋','宋诗','song-poetry','','[]','昨夜聞宣鎖，虛皇注意深。',48,'全唐诗/poet.song.191000.json','["昨夜聞宣鎖，虛皇注意深。", "三師分漢制，一尺瀉商霖。", "未白憂邊髮，仍丹報國心。", "黄封留壽酒，且把斗杓斟。"]'),
('e406a5b8-2ece-4eac-96d4-0f511f85d141','壽丞相慶七十五首  其三','吳泳','宋','宋诗','song-poetry','','[]','渤海兵戈靜，全淮版籍歸。',48,'全唐诗/poet.song.191000.json','["渤海兵戈靜，全淮版籍歸。", "紅繅蠶繭大，紫擘蟹螯肥。", "柳港添生色，榆關閟殺機。", "君王新御殿，莫使諫書稀。"]'),
('0a45b244-c716-4021-888e-f677b38ccfc9','壽丞相慶七十五首  其四','吳泳','宋','宋诗','song-poetry','','[]','誕日逢今日，新年勝故年。',48,'全唐诗/poet.song.191000.json','["誕日逢今日，新年勝故年。", "良風宜望歲，甲雨不妨田。", "浙米多堪糴，京交漸直錢。", "隆興須再見，人道魯公賢。"]'),
('f345267b-70ac-40d4-94de-4fb71276f6f3','壽丞相慶七十五首  其五','吳泳','宋','宋诗','song-poetry','','[]','自闢翹材館，才隨數路求。',48,'全唐诗/poet.song.191000.json','["自闢翹材館，才隨數路求。", "蘭苕和露摘，橘柚带霜收。", "味適方調鼎，裝輕不駕舟。", "有懷吟未盡，獨鶴遠山頭。"]'),
('2d80c895-dc7a-47a8-89cc-ee2fb678230c','和張周玉訪別','吳泳','宋','宋诗','song-poetry','','[]','白露下百草，年光驚易徂。',48,'全唐诗/poet.song.191000.json','["白露下百草，年光驚易徂。", "郵亭人折柳，別浦雁銜蘆。", "社甕應藏酒，秋盤好斫鱸。", "賢渠陶靖節，晚歲覺迷塗。"]'),
('7fea7231-c2f5-4b03-a32a-817fec7e5fec','挽李寺丞','吳泳','宋','宋诗','song-poetry','','[]','文獻中原舊，箕裘戶部清。',48,'全唐诗/poet.song.191000.json','["文獻中原舊，箕裘戶部清。", "官終一麾守，事歷五廷評。", "掛壁琴無譜，傳家硯有名。", "東風吹畫翣，溪上若爲情。"]'),
('59697bb4-5a9c-4970-b543-bb2242950b2e','挽李郎中  其一','吳泳','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','少日聲名偉，中年學問腴。',48,'全唐诗/poet.song.191000.json','["少日聲名偉，中年學問腴。", "氣緣經事老，形爲愛民癯。", "吭引朝陽鳳，魂驚古冢狐。", "遺忠攄不盡，英爽射匡廬。"]'),
('4b55647b-ef90-402b-aa8f-ca272c4a2ec1','挽李郎中  其二','吳泳','宋','宋诗','song-poetry','','[]','河洛輟微響，朱張傳古心。',48,'全唐诗/poet.song.191000.json','["河洛輟微響，朱張傳古心。", "世隨人影落，君嚮路頭尋。", "蔓草侵山徑，柔荑死樹林。", "良朋更能幾，百感集孤斟。"]'),
('ac9a30a4-989a-449c-af0e-db304dbf3959','挽青陽俞夫人','吳泳','宋','宋诗','song-poetry','','[]','彼美宜家室，之媛友瑟琴。',48,'全唐诗/poet.song.191000.json','["彼美宜家室，之媛友瑟琴。", "漆園歌未歇，澧浦珮還沉。", "懿範貽彤管，佳銘得藁砧。", "卧龍山下路，風雨亂愁心。"]'),
('0199b8af-a5fa-4abf-9e03-ab5a6cc9013d','挽貴平大夫','吳泳','宋','宋诗','song-poetry','','[]','介介汝谿叟，青衫三十年。',48,'全唐诗/poet.song.191000.json','["介介汝谿叟，青衫三十年。", "澹如彭澤柳，廉過石門泉。", "漫仕曾無意，遺文竟有傳。", "浮山讀書處，定跨玉蜍仙。"]'),
('d4127013-91af-4b4a-a506-3356824293b9','挽王夫人','吳泳','宋','宋诗','song-poetry','','[]','婉娩嫺詩畫，僮僮被典章。',48,'全唐诗/poet.song.191000.json','["婉娩嫺詩畫，僮僮被典章。", "有齊先祭潔，薄澣展衣香。", "唁衛心雖切，傷周義不忘。", "勉哉君子正，彤管尚遺芳。"]'),
('82f47e6a-14b7-47b4-a36f-c73cb5cb5a9a','挽鄭夫人','吳泳','宋','宋诗','song-poetry','','[]','淑行繇真履，慈根自夙知。',48,'全唐诗/poet.song.191000.json','["淑行繇真履，慈根自夙知。", "性情詩調適，內外禮維持。", "春閤青蘋亂，秋原白木悲。", "只今哀窈窕，手線授衣時。"]'),
('057a6d0c-a8d4-4ebc-9474-f8dd1ad0819a','挽雍處士','吳泳','宋','宋诗','song-poetry','','[]','折柳詩名遠，滋蘭德本深。',48,'全唐诗/poet.song.191000.json','["折柳詩名遠，滋蘭德本深。", "撻禽能起孝，訓鯉只平心。", "半夜酒星落，千山薤露吟。", "芭蕉溪上水，嗚咽不堪斟。"]'),
('ac2adb26-70a4-49de-86fa-0f0766339bbe','挽游監簿  其一','吳泳','宋','宋诗','song-poetry','','[]','好漢三巴傑，危言九陛忠。',48,'全唐诗/poet.song.191000.json','["好漢三巴傑，危言九陛忠。", "王前留孟子，國爾念周公。", "日馭龍堆出，天昏虎踞雄。", "收聲諸老盡，銘有後谿翁。"]'),
('6415ef23-24e1-4302-8e13-f80b650b2979','挽游監簿  其二','吳泳','宋','宋诗','song-poetry','','[]','昔上金泉去，翁方玉局閒。',48,'全唐诗/poet.song.191000.json','["昔上金泉去，翁方玉局閒。", "橘中春響雹，壺裏曉行山。", "迂叟空扶杖，坡仙不賜環。", "每思生處所，壯淚爲公潸。"]'),
('69fadf3c-5ecf-42c0-b843-0a761131ea59','塞下','吳泳','宋','宋诗','song-poetry','','[]','黄雲連隴樹，紅日下溪榆。',120,'全唐诗/poet.song.191000.json','["黄雲連隴樹，紅日下溪榆。", "氈帳三千里，蜂屯十萬夫。", "魯芻肥廄馬，漢粟遺城狐。", "虎韔空涵月，犀渠半網蛛。", "游軍聲勃崒，巡徼語嚨胡。", "柳脆藩籬薄，桑乾塹壘孤。", "突炎將及燕，逋尾又侵烏。", "曲引梅花落，謠聞小麥枯。", "將軍金騕褭，輕俠繡蝥弧。", "十二營田利，知誰上此圖。"]'),
('4ec25b10-0edf-4960-b646-4b6a93a31d8b','壽安宣相','吳泳','宋','宋诗','song-poetry','','[]','磊落堪輿氣，崢嶸社稷身。',288,'全唐诗/poet.song.191000.json','["磊落堪輿氣，崢嶸社稷身。", "地傾曾鎮靜，天造要經綸。", "倉首懷公輔，中原仗老臣。", "綸揚申命寵，渥照午橋新。", "司馬還辭洛，汾陽再入秦。", "乾坤重拆洗，宇縣細縫紉。", "汰擊鯨波濁，風清虎穴塵。", "綠林戡大盜，紫邏息罷民。", "魴尾喁喁活，龍驤帖帖馴。", "按行光弼壘，斜岸武侯巾。", "究宅歌鴻雁，參謀集鳳麟。", "星營羅粲粲，雷轂隠轔轔。", "飛輓通關表，耕屯集渭濱。", "軍容俄再色，威令復重信。", "烽火閒荆楚，塵沙卷劍岷。", "馬騰雲隴月，士飽雪山春。", "來石非無傑，平江亦有人。", "誓功俱不再，方德信誰鄰。", "弓矢宜專晉，鉤膺遂錫申。", "鶻銜凌井鉞，龍節壓參神。", "衛幙論功盛，韋門送喜頻。", "河陽分鎮日，許國授弓辰。", "勳業當如此，恩榮實邁倫。", "一忠摩皜日，二節貫蒼旻。"]'),
('f4cd1e3f-c3a1-4316-b905-426fccde59fd','壬辰恭和御製聞喜宴詩','吳泳','宋','宋诗','song-poetry','','[]','清問諄諄許盡言，以書爲轍道爲軒。',64,'全唐诗/poet.song.191000.json','["清問諄諄許盡言，以書爲轍道爲軒。", "鑑觀萬古知成法，條析羣疑見大原。", "櫻苑近頒天上句，燕杯新带雨邊恩。", "燃藜夜取雲章讀，照乘驪珠炳若存。"]'),
('40891267-040f-439e-b942-69cc8d01c0c6','乙未恭和御製聞喜宴詩','吳泳','宋','宋诗','song-poetry','','[]','聖學希天善牖民，風霆鼓舞氣如神。',64,'全唐诗/poet.song.191000.json','["聖學希天善牖民，風霆鼓舞氣如神。", "轉回姚姒文章古，作起殷周禮樂新。", "有限科名非究竟，無窮經術要紛綸。", "事君自昔無他道，不有其身是致身。"]'),
('b0dfc102-ffb6-4e40-adcb-52dc8074701e','谿亭春日  其一','吳泳','宋','宋诗','song-poetry','','[]','不必尋芳出遠郊，八分春盡屬亭臯。',64,'全唐诗/poet.song.191000.json','["不必尋芳出遠郊，八分春盡屬亭臯。", "漫波綠皺一溪水，暖日紅蒸千樹桃。", "烏遶屋簷呈卦兆，鶴窺庭戶聽離騷。", "靜中識得生生意，堂下蘼蕪更不耨。"]'),
('70814d09-6419-4db9-81ca-6f4980d28c5c','谿亭春日  其二','吳泳','宋','宋诗','song-poetry','','[]','春事無邊著語難，得逢佳處輒停驂。',64,'全唐诗/poet.song.191000.json','["春事無邊著語難，得逢佳處輒停驂。", "河豚漸美誇梅十，芳草如屏說柳三。", "小韻作詩防跌宕，淺杯斟酒怕沉酣。", "買山那得青錢在，只欲花間結小菴。"]'),
('77c11f1a-2e35-44d8-bf09-1aca20f0608c','又和洪司令春日','吳泳','宋','宋诗','song-poetry','','[]','房湖曾別苦吟身，兩度東風似一塵。',64,'全唐诗/poet.song.191000.json','["房湖曾別苦吟身，兩度東風似一塵。", "柳外游絲難繫日，麥邊馴雉亦驚春。", "玄都君子皆通貴，栗里先生祇一貧。", "珍重龍陽賢太守，時將詩句惱陳人。"]'),
('b354c567-87cf-4424-a73a-f69b15d2d271','送成都添倅李微之分韻得巫字','吳泳','宋','宋诗','song-poetry','','[]','本住陵陽處士廬，不妨名字落青都。',64,'全唐诗/poet.song.191000.json','["本住陵陽處士廬，不妨名字落青都。", "題輿带閣添新號，抱史還山只故吾。", "秀水穩宜眠夏簟，惠泉香可煮秋菰。", "勸君莫動騷人曲，椰葉蓪花降女巫。"]'),
('18d6b4af-f064-4c47-b480-54ee25f43834','湖亭酌王史君紀事并呈看花諸君子','吳泳','宋','宋诗','song-poetry','','[]','紅雨斑斑點嫩苔，朱輪軋軋碾輕埃。',64,'全唐诗/poet.song.191000.json','["紅雨斑斑點嫩苔，朱輪軋軋碾輕埃。", "園公不作橘中隠，康節肯從花外來。", "鶑囀樹林添道韻，鷗分江色獻詩材。", "籃輿便載春歸去，誰管酴醿芍藥開。"]'),
('5d3167e3-30c4-4c64-a22d-6dd32e721ba7','王巽堂三十年不到湖亭丙戌春再來非舊矣用前韻以俟後遊','吳泳','宋','宋诗','song-poetry','','[]','庭院深深鎖綠苔，掃花無帚半塵埃。',64,'全唐诗/poet.song.191000.json','["庭院深深鎖綠苔，掃花無帚半塵埃。", "紅霞滿樹劉郎去，青子垂枝杜牧來。", "乍可放閒寬酒地，不能隨俗貯香材。", "醉翁自有山間樂，更取林霏手斫開。"]'),
('333a7fd6-8916-4839-818c-08ac5bb6af1f','老將','吳泳','宋','宋诗','song-poetry','','[]','一從十五長邊城，少見兵戈日太平。',64,'全唐诗/poet.song.191000.json','["一從十五長邊城，少見兵戈日太平。", "代馬依風都護道，飛鳶熏霧伏波營。", "紅雕腊軟君王賜，青兕裘輕子女情。", "昨夜點行新部曲，鐵衣偏奏苦寒聲。"]'),
('e0166172-b40b-4c23-9a8a-cd7ae4dbce92','永嘉鹿鳴宴','吳泳','宋','宋诗','song-poetry','','[]','人間富貴易浮沈，只有斯文無古今。',64,'全唐诗/poet.song.191000.json','["人間富貴易浮沈，只有斯文無古今。", "義理工夫元坦易，聖賢言語不艱深。", "莫隨近世諸儒轍，要識開山一祖心。", "待得了他科舉債，梅花月下聽瑶琴。"]'),
('0aee91d0-1e14-41bb-a1e6-0ae2cff5b54a','和張亨泉宴鹿鳴','吳泳','宋','宋诗','song-poetry','','[]','平生湖海獨元龍，門作丹梯倚太空。',64,'全唐诗/poet.song.191000.json','["平生湖海獨元龍，門作丹梯倚太空。", "還我蛾眉千頃月，借渠羊角一帆風。", "文隨脚跡機難活，學到源頭理自通。", "何代不生田表聖，諸君切在敏前功。"]'),
('f5b4b079-edd2-4935-87a8-902a3625a7a8','宣城鹿鳴宴','吳泳','宋','宋诗','song-poetry','','[]','儒臣簪筆典州麾，重爲江山緝舊儀。',64,'全唐诗/poet.song.191000.json','["儒臣簪筆典州麾，重爲江山緝舊儀。", "宴序古來元有禮，鹿鳴廢後更無詩。", "科名到手還須耐，文字當場莫好奇。", "更盡工歌笙一曲，明年春灑上林枝。"]'),
('a998e0ae-bff6-46ac-ba54-049f64a661b7','至日示諸甥姪','吳泳','宋','宋诗','song-poetry','','[]','莫風浩蕩忽吹葭，一室陽春病已差。',64,'全唐诗/poet.song.191000.json','["莫風浩蕩忽吹葭，一室陽春病已差。", "把酒認爲天一水，見梅題作玉真花。", "燕常會族寧隨儉，祭則從先不尚華。", "過此肥冬疆事靜，亦呼槃也早還家。"]'),
('8066a10f-0e73-415a-9392-3f90eedfb082','題望湖亭','吳泳','宋','宋诗','song-poetry','','[]','祥雲宮殿半荒蕪，獨有亭基下瞰湖。',64,'全唐诗/poet.song.191000.json','["祥雲宮殿半荒蕪，獨有亭基下瞰湖。", "水氣淼茫吞八極，地形磐礴跨三吳。", "一輪紅日射銅闕，數點青山浮玉壺。", "欲問湖邊諸澳長，長洲盜賊已平無。"]'),
('c0a0c759-375f-4904-887a-1a81bff01269','和季永弟賦袁尊固海棠','吳泳','宋','宋诗','song-poetry','','[]','觱篥聲中氣序過，谿頭燕子又歸窠。',64,'全唐诗/poet.song.191000.json','["觱篥聲中氣序過，谿頭燕子又歸窠。", "清涵夜色花無睡，翠洗晨粧臉半酡。", "紅萼尚懷鄉國舊，錦心空抱客愁多。", "飲酣樂極翻成感，淚濕臙脂雪滿坡。"]'),
('140de7c4-b611-4adc-b840-b88a689d0088','張仁溥寄游滄浪詩用韻一首非爲滄浪作也','吳泳','宋','宋诗','song-poetry','','[]','卉木萋萋二月寒，杏垂紅雨涕浪浪。',64,'全唐诗/poet.song.191000.json','["卉木萋萋二月寒，杏垂紅雨涕浪浪。", "無司花女太幽絕，有索酒郎多醉狂。", "弄影莫陪張子野，斷腸空憶賀橫塘。", "春來亦欲尋詩社，却怕詩工與道妨。"]'),
('b5b4438b-d31a-4828-b8ca-a8dcfeedbf91','讀黄子實詩卷','吳泳','宋','宋诗','song-poetry','','[]','唐人漫自說金華，山谷雲孫自當家。',64,'全唐诗/poet.song.191000.json','["唐人漫自說金華，山谷雲孫自當家。", "玄色釀成真一酒，別機織出象生花。", "緬懷友義留巫峽，難割閨情下漢嘉。", "看徹一編酬未得，夜深窗月凈籠紗。"]'),
('45888f9c-2098-4e1f-b3b3-64380780060b','壽李雁湖  其一','吳泳','宋','宋诗','song-poetry','','[]','當年指李記生辰，柱史疑爲法報身。',64,'全唐诗/poet.song.191000.json','["當年指李記生辰，柱史疑爲法報身。", "魚鳥泳飛南閣曉，風花經緯石林春。", "手繙萬軸談無底，胸著千年汲愈新。", "試看喬松霜雪後，凜然一節照時人。"]'),
('06559f6e-1ffe-4fa7-b0fa-bdc8e5cf2fce','壽李雁湖  其二','吳泳','宋','宋诗','song-poetry','','[]','自卷朝衣濯雁湖，勳名籍籍在黄樞。',64,'全唐诗/poet.song.191000.json','["自卷朝衣濯雁湖，勳名籍籍在黄樞。", "時聞走卒稱司馬，猶有羣兒問大蘇。", "赴隴尺書馳鶴板，起家萬石綰麟符。", "宵衣炯炯思黄髮，正藉元勳出手扶。"]'),
('e34858e9-7dd9-4179-b04e-12abb65e5f52','壽李雁湖  其三','吳泳','宋','宋诗','song-poetry','','[]','洶洶風濤卒未清，便提小隊按行營。',64,'全唐诗/poet.song.191000.json','["洶洶風濤卒未清，便提小隊按行營。", "一言刑省朝歌盜，單騎恩懷渤海兵。", "豐德自應通綠籍，長年何必飯黄精。", "勸公剩壓蘭英酒，爲作涪川小太平。"]'),
('01ac2482-febf-441e-8ec0-643d9e404f61','壽李雁湖  其四','吳泳','宋','宋诗','song-poetry','','[]','身駕青牛老子車，行雲來去自紓徐。',64,'全唐诗/poet.song.191000.json','["身駕青牛老子車，行雲來去自紓徐。", "精神健好充黄野，骨法清真貫玉廬。", "六十二年康節詠，五千餘卷玉川書。", "石林莫作盤居計，黄紙看看又詔除。"]'),
('9126f698-f130-45b4-a719-2c5c973ee58b','壽范漕  其一','吳泳','宋','宋诗','song-poetry','','[]','粲粲桐花昨夜風，吹香還到鹿園中。',64,'全唐诗/poet.song.191000.json','["粲粲桐花昨夜風，吹香還到鹿園中。", "前生出處黄山谷，後代風流范蜀公。", "灑落一襟涵霽月，精神滿面貫晴虹。", "直須整頓坤維了，歸侍祥雲一朶紅。"]'),
('a3aecb3d-330d-412b-ac8d-3a301625b985','壽范漕  其二','吳泳','宋','宋诗','song-poetry','','[]','自從繡紱解麒麟，一片忠誠只爲民。',64,'全唐诗/poet.song.191000.json','["自從繡紱解麒麟，一片忠誠只爲民。", "涪水竹枝秋送客，漢嘉火樹夜迎神。", "玄蜂赤螘三垂靜，白黍黄雞萬井春。", "儘使蜀人翻覆看，皇華禮樂只如新。"]'),
('261165ce-6163-4903-a771-1893afe0df8f','壽范漕  其三','吳泳','宋','宋诗','song-poetry','','[]','伏波老子縛長虬，典護蘭闈更兩秋。',64,'全唐诗/poet.song.191000.json','["伏波老子縛長虬，典護蘭闈更兩秋。", "學問只從苗脈看，辭章不嚮語言求。", "俱稱脚跡門生好，無復顔行執事羞。", "夾袋中間富人物，更須爲國貢琳球。"]'),
('97cf684a-9269-43ca-8776-6bc762a016ab','壽范漕  其四','吳泳','宋','宋诗','song-poetry','','[]','福星一點夜堂深，藻泮花泉共照臨。',64,'全唐诗/poet.song.191000.json','["福星一點夜堂深，藻泮花泉共照臨。", "歌詠春風曾點瑟，體當生意宓君琴。", "喬松已作參天色，寸草猶持報主心。", "但翼斯文扶壽脈，年年一穗爇犀沉。"]'),
('2ba434da-2247-48a2-aeb6-20f375fab28e','客中和程丞相雪','吳泳','宋','宋诗','song-poetry','','[]','蕭蕭客歲澹如家，耿耿青燈凍不花。',64,'全唐诗/poet.song.191000.json','["蕭蕭客歲澹如家，耿耿青燈凍不花。", "窗外曉添梅意韻，田間春透麥精華。", "書來頗復懷歸雁，杯散何繇覓畫蛇。", "明日雪晴鄉社去，辛盤隨俗點春茶。"]'),
('70c2f319-086d-443c-b798-38b52351f41c','和杜樞密雪  其一','吳泳','宋','宋诗','song-poetry','','[]','紫宸朝動雞人唱，一片天光接絳河。',64,'全唐诗/poet.song.191000.json','["紫宸朝動雞人唱，一片天光接絳河。", "花樣繡韉衝曉去，霙鋪毬路带春多。", "邊無疋馬比寧地，土有遺蝗奈凍何。", "檠重玉龍猶未老，莫將圖畫寫披蓑。"]'),
('f974c555-b761-4cca-930f-6eb5e3b33a4e','和杜樞密雪  其二','吳泳','宋','宋诗','song-poetry','','[]','一自金鑾陡下坡，更無津可問明河。',64,'全唐诗/poet.song.191000.json','["一自金鑾陡下坡，更無津可問明河。", "雲蒸黄野風寒薄，雪皎皓庭幽思多。", "高艷未能攀屈宋，寒灰聊復撥陰何。", "聚星堂上如相問，竟日長鑱對短蓑。"]'),
('a5776d62-c76f-49fc-b294-731c0c7158dd','和趙西里賦雪','吳泳','宋','宋诗','song-poetry','','[]','謬守無奇只靠天，一編周易一爐烟。',64,'全唐诗/poet.song.191000.json','["謬守無奇只靠天，一編周易一爐烟。", "抽毫難出相如右，覓句敢居靈運前。", "酒酌山羊方餞臘，籥鳴土鼓又祈年。", "何時獨放扁舟往，淡月西村古柳邊。"]'),
('e7eb7bfe-e4ff-4bd6-9bcd-1fdb2bbbeb4c','和張仁溥賦雪','吳泳','宋','宋诗','song-poetry','','[]','北風聲熄南山微，誰息風雅呼於時。',64,'全唐诗/poet.song.191000.json','["北風聲熄南山微，誰息風雅呼於時。", "歌黄三章未純古，敘白一段空愛奇。", "臺高皆羨雨花落，簷短獨愁冰柱垂。", "墨客如林筆如冢，莫於詩上更題詩。"]'),
('ae9ce18d-f993-44f4-85ed-f4a33178d2b9','清曉踏雪送季武博','吳泳','宋','宋诗','song-poetry','','[]','送客陵陽第一峰，臨分莫遏順帆風。',64,'全唐诗/poet.song.191000.json','["送客陵陽第一峰，臨分莫遏順帆風。", "人行水驛梅花外，詩在昭亭雪界中。", "破屋但留黄蘗老，高風難覓紫芝翁。", "筍輿訪別驚回首，無數寒鴉點碧空。"]'),
('110fcd41-46e2-4ad5-b6e8-f1245ca2550f','嘉熙丁酉七月上澣遊大滌題住山龔沖妙艮泓軒','吳泳','宋','宋诗','song-poetry','','[]','舊與清泉白石盟，身閒方作洞霄行。',64,'全唐诗/poet.song.191000.json','["舊與清泉白石盟，身閒方作洞霄行。", "青山延客元無鎖，碧澗流花似有情。", "古洞欲隨仙隠去，高岡終待鳳來鳴。", "道人喚我松間飲，坐拂寒雲月未生。"]'),
('a069850e-7148-4b21-a093-b298253f1ed1','壽張亨泉提刑三首  其一','吳泳','宋','宋诗','song-poetry','','[]','蓮花峰下發源深，胸次渟涵幾古今。',64,'全唐诗/poet.song.191000.json','["蓮花峰下發源深，胸次渟涵幾古今。", "事苟及民須著手，文非爲道不關心。", "扶持世界歸儒效，轉斡天機自筆箴。", "主靜工夫人不識，火陽五月正根陰。"]'),
('ce9defb2-440a-4dbe-bf0f-787e341d694b','壽張亨泉提刑三首  其二','吳泳','宋','宋诗','song-poetry','','[]','二年煙雨漢臯亭，玉節西來照雪明。',64,'全唐诗/poet.song.191000.json','["二年煙雨漢臯亭，玉節西來照雪明。", "慷慨報君渾是膽，馳驅將母莫非誠。", "稻禾水足青疇潤，烽火宵閒紫邏清。", "鸞鳳莫將鷹隼看，及時須爲國家鳴。"]'),
('c854acca-242c-47ec-87e6-414ef51fea44','壽張亨泉提刑三首  其三','吳泳','宋','宋诗','song-poetry','','[]','末學紛紛競爲人，公能康濟自家身。',64,'全唐诗/poet.song.191000.json','["末學紛紛競爲人，公能康濟自家身。", "形軀元備人間世，肝肺盡收天下春。", "觀我自應知愛重，識心須會起經綸。", "壽觥難著皇華語，抱取峨眉月半輪。"]'),
('f1254300-0fcb-42d5-8b51-fcf14fd4f6d8','壽崔侍郎三首  其一','吳泳','宋','宋诗','song-poetry','','[]','天開碧落洗雲扉，暫輟僊郎下紫微。',64,'全唐诗/poet.song.191000.json','["天開碧落洗雲扉，暫輟僊郎下紫微。", "獨有素琴隨從橐，更無侍史護朝衣。", "霜清潦浄榮名薄，棗熟花香道力肥。", "列炬照空還歲晚，明年仍傍火城歸。"]'),
('fe9c570a-369c-478a-b572-607ab6118ed8','壽崔侍郎三首  其二','吳泳','宋','宋诗','song-poetry','','[]','胸次知蟠幾監書，事隨天理只平鋪。',64,'全唐诗/poet.song.191000.json','["胸次知蟠幾監書，事隨天理只平鋪。", "來從京兆德星社，攬取西峨明月湖。", "民豈無衣須補綻，極元有柱要撐扶。", "欲知天授西平意，繡帽臨戎爲萬夫。"]'),
('00f689dd-27fd-40e7-99b1-f924b9c1b847','壽崔侍郎三首  其三','吳泳','宋','宋诗','song-poetry','','[]','小隊元戎未弭旌，羣飛鶴雁已充庭。',64,'全唐诗/poet.song.191000.json','["小隊元戎未弭旌，羣飛鶴雁已充庭。", "只緣匹馬修途健，喚起三刀昨夢醒。", "犀麈自揮坤宇靜，鯨風不漲海波停。", "牛頭衮衮春無際，捻出三詩壽蜀星。"]'),
('69ccfaeb-ac03-418c-8f99-7b4480d04b8b','壽周提刑二首  其一','吳泳','宋','宋诗','song-poetry','','[]','分得濂溪一派清，皇皇仁義不貪名。',64,'全唐诗/poet.song.191000.json','["分得濂溪一派清，皇皇仁義不貪名。", "金華學道行持到，禹穴題輿去就輕。", "一節以趨何簡易，十年不調轉光明。", "匡時富有經綸在，若木華邊緩轡行。"]'),
('677ddc95-8af3-4691-bf8e-427872790b62','壽周提刑二首  其二','吳泳','宋','宋诗','song-poetry','','[]','自乞銀符守漢嘉，就持漢節問梅花。',64,'全唐诗/poet.song.191000.json','["自乞銀符守漢嘉，就持漢節問梅花。", "庭扉訟少閒徽棘，堰水流多漚紵麻。", "論擊回邪羝觸角，化銷彊暴鼠無牙。", "更看植杖扶犁叟，清議依前說使家。"]'),
('40c72c32-010a-4ecb-8355-d1c5be9445db','壽史石泉二首  其一','吳泳','宋','宋诗','song-poetry','','[]','胸次玻瓈湛不摇，高風炯炯揭冰條。',64,'全唐诗/poet.song.191000.json','["胸次玻瓈湛不摇，高風炯炯揭冰條。", "崑墟已瀉南軒派，蜀貢猶傳北斗杓。", "問學有源天一水，文章無盡海門潮。", "三灘五渡多人物，難得公家月指標。"]'),
('f89f1270-367d-4ed7-b078-d454c0824913','壽史石泉二首  其二','吳泳','宋','宋诗','song-poetry','','[]','露洗秋容一片清，遠山高與雪爭明。',64,'全唐诗/poet.song.191000.json','["露洗秋容一片清，遠山高與雪爭明。", "賢侯元是嶽神降，上相先從佛臘生。", "畫戟不妨當燕寢，白囊無復到雞城。", "新來連日西郊雨，還作山間小太平。"]'),
('d6bf4a64-ae52-4d25-9a2b-74ed82be73d3','壽某翁','吳泳','宋','宋诗','song-poetry','','[]','當日麻衣抑未猜，貴公元自有僊材。',64,'全唐诗/poet.song.191000.json','["當日麻衣抑未猜，貴公元自有僊材。", "文辭敏妙真星魄，學問沈潜是聖胎。", "黄石授兵非有意，紅旗破賊却歸來。", "阿同且共玻瓈飲，源上桃花想未開。"]'),
('47f43132-3c7d-40af-9cf6-580704755d19','壽范潔齋  其一','吳泳','宋','宋诗','song-poetry','','[]','合下金相氣質渾，更參諸老徧宗門。',64,'全唐诗/poet.song.191000.json','["合下金相氣質渾，更參諸老徧宗門。", "箕山再得顔回婿，榮國還生孔子孫。", "學問不趨岐路徑，文章祇好古罍尊。", "至今尚得詩書力，一氣清明中夜存。"]'),
('136a774e-b5b0-403b-a471-a2065619ac7d','壽范潔齋  其二','吳泳','宋','宋诗','song-poetry','','[]','青袍朝士走紅塵，公獨紉蘭結佩紳。',64,'全唐诗/poet.song.191000.json','["青袍朝士走紅塵，公獨紉蘭結佩紳。", "不事王侯嫌炙手，豈除御史更呈身。", "寒花秋後看名節，喬木霜中見本真。", "吾道天寬連地大，羊溝那得繫麒麟。"]'),
('0e65b4c2-bc1f-421b-955f-530a28c2a6f4','壽范潔齋  其三','吳泳','宋','宋诗','song-poetry','','[]','瀘水風濤七載還，今年贏得在家山。',64,'全唐诗/poet.song.191000.json','["瀘水風濤七載還，今年贏得在家山。", "臨流領客清溪上，滴露抄書翠竹間。", "晚計作堂應未晚，閒居成賦恐難閒。", "雲昏八表邊烽息，須得伊人護玉關。"]'),
('e7fa9f78-f3f6-4437-89fb-3323a81ffa99','壽范潔齋  其四','吳泳','宋','宋诗','song-poetry','','[]','憶昨薰風會面時，猶龍老子亶沖夷。',64,'全唐诗/poet.song.191000.json','["憶昨薰風會面時，猶龍老子亶沖夷。", "忠文晚節三年過，上相生辰十日遲。", "內景兩篇時點檢，中庸一卷曉行持。", "朝來泮水鴞音好，目注西山擬壽時。"]'),
('ade3fea5-39ca-49d7-a885-59ee369e9a1b','送洪司令  其一','吳泳','宋','宋诗','song-poetry','','[]','經年分月伴西清，又佐戎軺勇北征。',64,'全唐诗/poet.song.191000.json','["經年分月伴西清，又佐戎軺勇北征。", "下馬必能書檄草，從軍元是擅詩名。", "熙豐作俑能無過，元祐操舟却要平。", "局面既新棋勢別，消詳專在幕中評。"]'),
('52c06c1e-ae11-43e8-97ba-9101699e0f99','送洪司令  其二','吳泳','宋','宋诗','song-poetry','','[]','夏日曾隨別駕歸，朔風還作送公詩。',64,'全唐诗/poet.song.191000.json','["夏日曾隨別駕歸，朔風還作送公詩。", "行軍司馬自文采，祭酒諸生亡崛奇。", "國事急忙中着手，邊籌閒暇處開眉。", "嘉陵想已波濤落，風雨無忘泊岸時。"]'),
('056b7e52-9b15-478a-b730-1b64a378b1fd','送梁漕東歸  其一','吳泳','宋','宋诗','song-poetry','','[]','四年一節蜀山間，父子重來世所艱。',64,'全唐诗/poet.song.191000.json','["四年一節蜀山間，父子重來世所艱。", "鏡月澄心寒吏膽，條冰濯魄映儒冠。", "孤清自古知誰似，遺愛于今愈耐看。", "歸去光明贏一着，笑渠袖手直旁觀。"]'),
('369bef29-cd2a-4cc3-b9d8-b21e46b0b2a6','送梁漕東歸  其二','吳泳','宋','宋诗','song-poetry','','[]','皎皎從來世不容，平平未足與言功。',64,'全唐诗/poet.song.191000.json','["皎皎從來世不容，平平未足與言功。", "介言西事何妨謫，洵著權書竟是忠。", "祇爲邊民憂自北，卷將吾道載而東。", "分明自有天知己，趣檄行看騎火紅。"]'),
('1f1ebb8e-e669-4f03-a5aa-707a3f7789c9','和張周玉峨眉山行','吳泳','宋','宋诗','song-poetry','','[]','搘筇更上最高峰，浮出修眉翠掃空。',64,'全唐诗/poet.song.191000.json','["搘筇更上最高峰，浮出修眉翠掃空。", "雪汁半消巖路口，苔衣倒掛樹林中。", "異禽語已非人世，香草名應繫國風。", "晚色漸侵衣袂冷，恍疑身在蘂珠宮。"]'),
('ec82becf-c0d3-4026-b85b-225787b5c3c6','出郊懷汪尚中代簡','吳泳','宋','宋诗','song-poetry','','[]','一春烟雨盡愁端，晴日郊行尚怕寒。',64,'全唐诗/poet.song.191000.json','["一春烟雨盡愁端，晴日郊行尚怕寒。", "芳草被堤風信過，雜英滿甸雪泥乾。", "劉郎去後花無恙，杜牧來遲春漸闌。", "明日爲君開社甕，莫教人倚玉欄看。"]'),
('353db3c1-a9ed-4aab-b696-917d44694d48','和虞滄江餞臘觀梅  其一','吳泳','宋','宋诗','song-poetry','','[]','買斷江天不用賒，絃琴觴詠樂無涯。',64,'全唐诗/poet.song.191000.json','["買斷江天不用賒，絃琴觴詠樂無涯。", "年深屢見巢添鶴，春到還知未放花。", "時有詩情窺洛社，斷無書尺到京華。", "面前楊柳風來處，豪岸依然屬富家。"]'),
('f6abf919-6046-40ac-94ec-2e34992f0a45','和虞滄江餞臘觀梅  其二','吳泳','宋','宋诗','song-poetry','','[]','餞歲江梅老樹邊，每逢佳處輒犁然。',64,'全唐诗/poet.song.191000.json','["餞歲江梅老樹邊，每逢佳處輒犁然。", "吟風弄月成勞績，種藥移花當貿遷。", "心事細評無此日，春風長健有明年。", "更期人日連頭去，酬此青蘋木末天。"]'),
('d36355da-5936-42fa-9082-e35830e673fb','和韻謝惠提幹約觀梅不赴','吳泳','宋','宋诗','song-poetry','','[]','纔看花回晚日明，停杯不飲槊空橫。',64,'全唐诗/poet.song.191000.json','["纔看花回晚日明，停杯不飲槊空橫。", "羨君灑落方成趣，笑我虺隤不及盟。", "但向舍南窗北看，渾如林下水邊清。", "自來太素先羣物，枉被山礬喚作兄。"]'),
('aa77ee31-64e5-4c17-b724-6026a9e555c6','宣城勸農','吳泳','宋','宋诗','song-poetry','','[]','一分東作五分春，相汝耕夫更在勤。',64,'全唐诗/poet.song.191000.json','["一分東作五分春，相汝耕夫更在勤。", "七月詩成種田法，庶人章作勸農文。", "祈蠶必使蠶如甕，卜稼須觀稼似雲。", "老守別無新治行，只將豐歲答吾君。"]'),
('634af9e3-8935-452a-b9d7-df06c2ffdad0','永嘉勸農歸舟中','吳泳','宋','宋诗','song-poetry','','[]','使君每愛讀豳詩，稼事艱難亦粗知。',64,'全唐诗/poet.song.191000.json','["使君每愛讀豳詩，稼事艱難亦粗知。", "水凍未聞秧布野，年饑且喜麥生岐。", "坐間白叟真堪貴，眼底朱衣總是癡。", "趁刺畫船呼客語，春風已滿勸農旗。"]'),
('3e6763a0-f811-4573-bd6f-6ba024dbb2ef','贈鄉僧祖元','吳泳','宋','宋诗','song-poetry','','[]','挑包不住雁邊峰，萬里來參琰浙翁。',64,'全唐诗/poet.song.191000.json','["挑包不住雁邊峰，萬里來參琰浙翁。", "刀割萬緣隨指斷，鏡磨諸漏著身空。", "不從貝葉鑽陳跡，只向蒲團下鈍工。", "結習依然銷未盡，有時詩語學琴聰。"]'),
('8aabfcc0-4627-46a9-ae63-0aadb0f8274f','壽鄒都大  其一','吳泳','宋','宋诗','song-poetry','','[]','石虹繚繞氣如雲，中有胎僊字卯神。',64,'全唐诗/poet.song.191000.json','["石虹繚繞氣如雲，中有胎僊字卯神。", "大宅寬平春滿面，一條瑩徹玉爲人。", "細看火後交梨熟，不及霜中碩果新。", "六十二年無一事，堯夫端的是前身。"]'),
('62234ece-27a2-4a3f-a178-bdc09ecc3ac7','壽鄒都大  其二','吳泳','宋','宋诗','song-poetry','','[]','易言來復甚昭昭，須識陰陽動靜交。',64,'全唐诗/poet.song.191000.json','["易言來復甚昭昭，須識陰陽動靜交。", "乾德衆賢當首畫，建炎諸老得中爻。", "水波已動龍難蟄，時運方清鳳合巢。", "會得生生無盡意，不須詹尹揲瓊茅。"]'),
('4d8f79f0-6d99-42b3-8296-0615fc5ee45f','壽鄒都大  其三','吳泳','宋','宋诗','song-poetry','','[]','梅花又是隔年看，節節光明雪照山。',64,'全唐诗/poet.song.191000.json','["梅花又是隔年看，節節光明雪照山。", "赤螘玄蜂邊徼外，黄雞白黍野田間。", "鵠頭久已書丹版，燕額仍須護玉關。", "獨有檀沈烟一穟，明年還遶屬車斑。"]'),
('81c18259-ec4e-470c-8cd8-01c52e50cc0b','壽鄒都大  其四','吳泳','宋','宋诗','song-poetry','','[]','嶰竹吹香子氣分，蒼蒼有意瑞斯文。',64,'全唐诗/poet.song.191000.json','["嶰竹吹香子氣分，蒼蒼有意瑞斯文。", "已從嵩嶽生申伯，復嚮西山壽卯君。", "鮐背自宜當職任，虎頭曾已策功勳。", "壺中日月春長在，且試犀沈一瓣薰。"]'),
('d09bb9d1-d2fc-4a56-ae7c-e0f242f5aabb','端平改元陽月同弟某自南山過龍井山僧饒舌話辯才近事且以某兄弟爲坡潁當有所識因賦','吳泳','宋','宋诗','song-poetry','','[]','一百年前老辯才，復褰絛带下山來。',64,'全唐诗/poet.song.191000.json','["一百年前老辯才，復褰絛带下山來。", "松杉溜雨驚龍起，篁竹生風喚鶴回。", "戒行浄通林水觀，語言香落寶花臺。", "更看坡潁留詩處，月墮山空眼豁開。"]'),
('fd24f114-39df-48e3-9a60-71a0b35ffee8','宣城宴六縣宰','吳泳','宋','宋诗','song-poetry','','[]','本是詞林翰墨臣，詔書特遣牧宣城。',64,'全唐诗/poet.song.191000.json','["本是詞林翰墨臣，詔書特遣牧宣城。", "使君只辦平平政，令尹無要赫赫名。", "獄苟得情須近恕，財如足用莫求贏。", "荻花風起江防急，秋閲應令弩手精。"]'),
('a287ebe2-cf37-49c3-9c64-b61db2b3827a','寄題蔣灣效堯夫體','吳泳','宋','宋诗','song-poetry','','["\u897f\u6e56"]','剛把西湖賣與鄰，卜園新得蔣灣春。',64,'全唐诗/poet.song.191000.json','["剛把西湖賣與鄰，卜園新得蔣灣春。", "半荒亭樹景偏老，欲壓溪橋花更真。", "漫賦莫教詩過好，淺斟時要酒輕醇。", "若能會得閒中趣，便是羲皇向上人。"]'),
('347f8d3e-b1e5-4e12-8998-740e7c9b1864','送范仁叟解褐西歸并簡定叟','吳泳','宋','宋诗','song-poetry','','[]','子館於予恰九春，臨分更欲問雲津。',64,'全唐诗/poet.song.191000.json','["子館於予恰九春，臨分更欲問雲津。", "良心易放當持敬，精義無窮要汲新。", "芻狗科名應是夢，貂蟬宦業竟成塵。", "世間公議難磨滅，第一還須作好人。"]'),
('5e474946-0bb9-4b0d-a1d2-ef50fdb04c06','壽安宣相  其一','吳泳','宋','宋诗','song-poetry','','[]','皛然老子本沖夷，起爲蒼生護北陲。',64,'全唐诗/poet.song.191000.json','["皛然老子本沖夷，起爲蒼生護北陲。", "邊吏皆能問司馬，市人曾不識安期。", "拊摩鮐背應耆艾，舒卷龍韜自崛奇。", "九老圖中張白後，合添同甲一篇詩。"]'),
('60ab39d7-405d-49a0-b875-a9b88e8b7512','壽安宣相  其二','吳泳','宋','宋诗','song-poetry','','[]','梅花又是隔年看，節節光明雪照山。',64,'全唐诗/poet.song.191000.json','["梅花又是隔年看，節節光明雪照山。", "百萬虎貔雙劍外，三千騋牝寸田間。", "鶴頭捧詔從天陛，雞舌含香趁曉班。", "富有春秋洪願力，宅家那得放公閒。"]'),
('66e07087-7133-4e89-9324-05abbd58f5e8','壽安宣相  其三','吳泳','宋','宋诗','song-poetry','','[]','上謂無官可報卿，延登左棘倍恩榮。',64,'全唐诗/poet.song.191000.json','["上謂無官可報卿，延登左棘倍恩榮。", "勳存社稷身俱泰，志在生靈物轉輕。", "平蜀以前誰磊落，渡江而後獨光明。", "蚤令不作湘潭夢，料得中原已掃清。"]'),
('1839af23-e00a-4f0f-9d6c-78e6597d835c','壽安宣相  其四','吳泳','宋','宋诗','song-poetry','','[]','文俗諸儒戀局中，何曾度外看英雄。',64,'全唐诗/poet.song.191000.json','["文俗諸儒戀局中，何曾度外看英雄。", "連雞縱不能資夏，捕鹿何妨暫掎戎。", "靜撫時機漁者得，遥觀敵運獸之窮。", "書生準擬浯溪石，明寫中興第一功。"]'),
('13b0fb94-fb75-4e5c-b246-42b4f0318c42','用韻謝帥機惠春盤','吳泳','宋','宋诗','song-poetry','','[]','梅柳陰中漫寄家，閒如翠鴇立晴沙。',64,'全唐诗/poet.song.191000.json','["梅柳陰中漫寄家，閒如翠鴇立晴沙。", "癭藤罇內抄松子，行玉槃中揀蕨芽。", "猶有鄉風餐白啖，更無春夢草黄麻。", "郊行莫待芳菲月，花未開時好看花。"]'),
('3dba0067-dc83-458f-aac7-90404c9b6e89','再用韻呈帥機就寄仁溥','吳泳','宋','宋诗','song-poetry','','[]','少學東坡頗愛奇，夜抄燈疏爇松脂。',64,'全唐诗/poet.song.191000.json','["少學東坡頗愛奇，夜抄燈疏爇松脂。", "老隨年度幾絃瑟，愁怕月窺雙鬢絲。", "蠶市已非吾故國，菜園猶得子新詩。", "閒人不管東風閙，麥飯枯魚著頓炊。"]'),
('7b8308bd-9746-4ff7-98b2-6840654568c7','病中有懷','吳泳','宋','宋诗','song-poetry','','[]','二年多病少佳懷，酒落杯中見影猜。',64,'全唐诗/poet.song.191000.json','["二年多病少佳懷，酒落杯中見影猜。", "青女降霜溪屋冷，白姑記日命宮災。", "柳州解祟祟頻作，孫子逐痁痁轉來。", "就使新春年運吉，鈍庚難撥馬頭開。"]'),
('65542cb0-6ecd-4dc4-84e6-c67efc013ec2','洪都病中口占','吳泳','宋','宋诗','song-poetry','','[]','去年輿疾上洪州，百感嬰懷又怕秋。',64,'全唐诗/poet.song.191000.json','["去年輿疾上洪州，百感嬰懷又怕秋。", "病體不因衰後覺，宦情誰向死前休。", "乞身已晚荒三徑，葬子無期負一丘。", "造物儻從心所欲，樂天知命更何求。"]'),
('e5ce71ff-1c3d-43d2-8c88-2adc637aa063','送洪司令赴闕','吳泳','宋','宋诗','song-poetry','','[]','曾記嘉陵共艤舟，江風又是荻花秋。',64,'全唐诗/poet.song.191000.json','["曾記嘉陵共艤舟，江風又是荻花秋。", "三年長別不一見，十事欲言還九休。", "頫聘交馳淮水濁，行程不定隴雲愁。", "鳳鳴已向朝陽去，飛雨殘霞濕柁樓。"]'),
('a89eb571-78c8-471e-9569-9d2d15a06d1b','寒食','吳泳','宋','宋诗','song-poetry','','[]','芳樹啼鶑絮亂飛，疾風吹雨送愁歸。',64,'全唐诗/poet.song.191000.json','["芳樹啼鶑絮亂飛，疾風吹雨送愁歸。", "梨花落莫還鄉夢，麥粥凄凉展墓儀。", "倦客忍聽谿上曲，游人猶習水邊嬉。", "西瞻太白家何在，擬托征鴻寄我衣。"]'),
('302fa575-fe42-447e-ac78-690a553b06a0','黄漕祠堂','吳泳','宋','宋诗','song-poetry','','[]','古誼寥寥千載間，却從賓主得窺斑。',64,'全唐诗/poet.song.191000.json','["古誼寥寥千載間，却從賓主得窺斑。", "道同元不分窮達，禮重何妨尚往還。", "拄杖過橋聲易識，壁紗籠墨句難攀。", "篝燈試取豐碑讀，名壓三犀石更頑。"]'),
('1ce3d86b-799e-43f2-a136-8063ccd2b5b7','徑山留贈無準','吳泳','宋','宋诗','song-poetry','','[]','十載京華少得閒，茲游渾似夢中山。',64,'全唐诗/poet.song.191000.json','["十載京華少得閒，茲游渾似夢中山。", "僧行古道元無徑，雲掩重扉更不關。", "夜語濃時花簇簇，禪機漏處月灣灣。", "東坡妙喜無人識，往往神遊在世間。"]'),
('0854f3ed-a121-431c-ae5e-0ccd77f42303','試院和李湛谿韻','吳泳','宋','宋诗','song-poetry','','[]','呵叱星辰賦遠遊，更提水鏡著中流。',64,'全唐诗/poet.song.191000.json','["呵叱星辰賦遠遊，更提水鏡著中流。", "讀書有眼月千里，愛士無方春九州。", "論及養生渾是道，時因主試却關愁。", "武夷不作逢溪老，亦欲臨風助擊鷗。"]'),
('06a0c369-1edd-44b7-9983-b02cd68d13e3','沔州和李長孺','吳泳','宋','宋诗','song-poetry','','[]','朔風吹雨濕征衣，卿月西昇伴紫微。',64,'全唐诗/poet.song.191000.json','["朔風吹雨濕征衣，卿月西昇伴紫微。", "出塞未經榆眼白，宿師先喜麥頭肥。", "寶刀尚可屠龍去，錦字何緣寄鴈歸。", "猶學騷人工索句，品題香草詠菲菲。"]'),
('24ea0e5e-65c7-4a59-95cd-b86c395a689e','和洪舜俞太一宮韻','吳泳','宋','宋诗','song-poetry','','[]','祠事歸來夜向晨，仰瞻天宇肅無塵。',64,'全唐诗/poet.song.191000.json','["祠事歸來夜向晨，仰瞻天宇肅無塵。", "缾搊金井轆轤曉，鐘撼茅山幡影春。", "傍水且栽梅半樹，掃簷莫使雪橫陳。", "柏臺近日清無酒，贏得吟詩分外新。"]'),
('47aa8391-fb03-42a0-a309-3252498f2caf','謝尊固送茶','吳泳','宋','宋诗','song-poetry','','[]','閒居早是賓儔寡，有弟山行訪鳥窠。',64,'全唐诗/poet.song.191000.json','["閒居早是賓儔寡，有弟山行訪鳥窠。", "黄卷漸成迂叟僻，朱顔不似美人酡。", "詩因怕事吟偏少，酒爲看花飲輒多。", "珍重山園芳茗餉，猶勝鄉國趙家坡。"]'),
('6253bb04-da93-494d-933d-2f5a8acd2538','春寒病痞痛用古砭法以磚熨之忽一夕帳煙塞滿火自下炎上焚衣被之半有感賦之','吳泳','宋','宋诗','song-poetry','','[]','怕寒不暇解衣眠，偪塞蒸成帳頂煙。',64,'全唐诗/poet.song.191000.json','["怕寒不暇解衣眠，偪塞蒸成帳頂煙。", "學士磚頭因火灼，尚書履下透衾然。", "洞存玉性真剛漢，焚却禪身笑浪僊。", "收歛道心中夜坐，室虛窗白月如弦。"]'),
('f558b38e-4f71-4053-9296-3e407d64fd76','挽李寺丞','吳泳','宋','宋诗','song-poetry','','[]','世人談利析錙銖，汲義如君此道孤。',64,'全唐诗/poet.song.191000.json','["世人談利析錙銖，汲義如君此道孤。", "無地起樓憐寇老，有園和契遺堯夫。", "西山別後常懷子，東國歸來已棄予。", "自昔祖風高挂劍，愧無佳語潤黄壚。"]'),
('b0fbe399-c58b-4c2e-b75f-175c4257632c','和洪司令九日觀閲  其一','吳泳','宋','宋诗','song-poetry','','[]','獵獵西風九月寒，元戎緩带撫齋壇。',64,'全唐诗/poet.song.191000.json','["獵獵西風九月寒，元戎緩带撫齋壇。", "士腰弓箭翻雲去，人擁旌旄夾道看。", "振旅陣酣金柝靜，從軍詩落玉蜍乾。", "南山不謂無嘉節，深惜諸賢玩燕安。"]'),
('9754699e-6c4c-4879-9dea-14bd69397a5e','和洪司令九日觀閲  其二','吳泳','宋','宋诗','song-poetry','','[]','劍花弓月幾秋寒，宿將凋零更不壇。',64,'全唐诗/poet.song.191000.json','["劍花弓月幾秋寒，宿將凋零更不壇。", "師衆弗於先事戒，蒐田祇作具文看。", "戍還黎雅魂方定，箭洗褒斜血未乾。", "爲報道傍泥飲者，尹來遺汝百年安。"]'),
('59c48100-67cf-4d02-bf4c-6acbd7c0bafe','用晦翁十梅詩韻酬張伯脩孫子直  其一','吳泳','宋','宋诗','song-poetry','','[]','幽人履貞吉，采藻南澗濱。',24,'全唐诗/poet.song.191000.json','["幽人履貞吉，采藻南澗濱。", "所采一物微，所思萬物春。"]'),
('be8e009e-5629-441d-bb27-6c503679a0ba','用晦翁十梅詩韻酬張伯脩孫子直  其二','吳泳','宋','宋诗','song-poetry','','[]','柳絲不禁梳，桃毳不耐雪。',24,'全唐诗/poet.song.191000.json','["柳絲不禁梳，桃毳不耐雪。", "梅殘剪春綃，永日霏不絕。"]'),
('2daa1712-2f0f-4b1f-84cd-05d0ec3c5123','用晦翁十梅詩韻酬張伯脩孫子直  其三','吳泳','宋','宋诗','song-poetry','','[]','椒榝充佩幃，孤芳處幽絕。',24,'全唐诗/poet.song.191000.json','["椒榝充佩幃，孤芳處幽絕。", "當年老虬枝，豈爲風雨折。"]'),
('d38f67ff-f25c-4125-ab44-3c1452b83a14','用晦翁十梅詩韻酬張伯脩孫子直  其四','吳泳','宋','宋诗','song-poetry','','[]','最後黄香根，纖裳粲黄裏。',24,'全唐诗/poet.song.191000.json','["最後黄香根，纖裳粲黄裏。", "能以色事人，空博一時喜。"]'),
('3fc58515-4ec1-4838-8de9-476076fb2d21','用晦翁十梅詩韻酬張伯脩孫子直  其五','吳泳','宋','宋诗','song-poetry','','[]','看花須看神，折花莫折殘。',24,'全唐诗/poet.song.191000.json','["看花須看神，折花莫折殘。", "但使花骨清，豈畏花地寒。"]'),
('505497b5-5d5d-4290-95d8-bae672e5909c','用晦翁十梅詩韻酬張伯脩孫子直  其六','吳泳','宋','宋诗','song-poetry','','[]','老瓦莫厭粗，奚童莫嫌小。',24,'全唐诗/poet.song.191000.json','["老瓦莫厭粗，奚童莫嫌小。", "及時不爲樂，頃刻芳事了。"]'),
('bc8d1221-0f56-4436-b6ff-49d20a6e7e18','用晦翁十梅詩韻酬張伯脩孫子直  其七','吳泳','宋','宋诗','song-poetry','','[]','聖涯浩無邊，人乃揭其淺。',24,'全唐诗/poet.song.191000.json','["聖涯浩無邊，人乃揭其淺。", "安知舍瑟中，道味益深遠。"]'),
('5461cdff-d74b-4b3b-9d86-270dd3182cc5','用晦翁十梅詩韻酬張伯脩孫子直  其八','吳泳','宋','宋诗','song-poetry','','[]','浮名鏡邊塵，驕氣爐上雪。',24,'全唐诗/poet.song.191000.json','["浮名鏡邊塵，驕氣爐上雪。", "年來如木鷄，我肱已三折。"]'),
('44800b11-cbdb-4986-8b04-f32b928c4826','用晦翁十梅詩韻酬張伯脩孫子直  其九','吳泳','宋','宋诗','song-poetry','','[]','書消燕日長，棋遣花院寂。',24,'全唐诗/poet.song.191000.json','["書消燕日長，棋遣花院寂。", "何羨山中人，餐霞拾橡實。"]'),
('445bfa55-638d-43d7-ad4a-498af619cad2','用晦翁十梅詩韻酬張伯脩孫子直  其一○','吳泳','宋','宋诗','song-poetry','','[]','爲花能工詩，不如賦拙賦。',24,'全唐诗/poet.song.191000.json','["爲花能工詩，不如賦拙賦。", "珍重舂陵翁，能尋所樂處。"]'),
('0e3cf4f3-3f64-4806-bb90-843fa5e91d69','果山春郊即事七首  其一','吳泳','宋','宋诗','song-poetry','','[]','晴嵐撲撲染人衣，龢意溶溶接岸陲。',32,'全唐诗/poet.song.191000.json','["晴嵐撲撲染人衣，龢意溶溶接岸陲。", "春事平鋪都放着，不應祇認小桃枝。"]'),
('00942aee-38cc-46c4-beb4-f2044e2d4bbf','果山春郊即事七首  其二','吳泳','宋','宋诗','song-poetry','','[]','梅事怱怱半雨殘，李粧羞澀尚春寒。',32,'全唐诗/poet.song.191000.json','["梅事怱怱半雨殘，李粧羞澀尚春寒。", "人情只道花時好，花未開時正耐看。"]'),
('1560c0db-6938-4689-b6be-35083c027baa','果山春郊即事七首  其三','吳泳','宋','宋诗','song-poetry','','[]','野寺藏春不一奇，靜機還有動機隨。',32,'全唐诗/poet.song.191000.json','["野寺藏春不一奇，靜機還有動機隨。", "幽尋往往行終日，未信東風屬酒旗。"]'),
('3979b956-ce9a-4a16-bc7a-47960ff37cdb','果山春郊即事七首  其四','吳泳','宋','宋诗','song-poetry','','[]','花含別墅無邊思，水放長渠自在流。',32,'全唐诗/poet.song.191000.json','["花含別墅無邊思，水放長渠自在流。", "別是一般閒富貴，田家那肯讓公侯。"]'),
('5a654149-b835-47ee-83dc-fdbf995919a0','果山春郊即事七首  其五','吳泳','宋','宋诗','song-poetry','','[]','簷花夜落曉還晴，應爲農祥一展顰。',32,'全唐诗/poet.song.191000.json','["簷花夜落曉還晴，應爲農祥一展顰。", "慙愧青裙南畝婦，犁頭能得幾多春。"]');
